-- Poems batch 263
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('54303a42-e05c-4742-83ae-d86841ca5c25','和柯提舉寄詩  其四','何夢桂','宋','宋诗','song-poetry','','[]','天上文昌望六星，隴頭農稷趁三春。',32,'全唐诗/poet.song.235000.json','["天上文昌望六星，隴頭農稷趁三春。", "玉京玄圃塵塵隔，璧月瓊枝歲歲新。"]'),
('ce55f2ac-7b0f-40ec-8207-6cf9d5f989ae','秋思有感','何夢桂','宋','宋诗','song-poetry','','[]','落日西風捲白沙，關山萬里客思家。',32,'全唐诗/poet.song.235000.json','["落日西風捲白沙，關山萬里客思家。", "蘆花雁斷無來信，柿子霜紅滿樹鴉。"]'),
('af0ec753-19fd-4787-9dcb-c2a28f827e7a','題竹境','何夢桂','宋','宋诗','song-poetry','','[]','種竹元非辟世人，竹環人境似山村。',32,'全唐诗/poet.song.235000.json','["種竹元非辟世人，竹環人境似山村。", "蒼苔滿徑客稀到，雲鎖閒堂鶴護門。"]'),
('b21af037-6f74-42c7-b351-c4183715d208','贈章月岩乃子德父','何夢桂','宋','宋诗','song-poetry','','[]','學得屠龍莫履狶，屠龍有技未全疏。',32,'全唐诗/poet.song.235000.json','["學得屠龍莫履狶，屠龍有技未全疏。", "斲輪老去誰傳業，珍重青囊肘後書。"]'),
('a41ee40e-6965-4c33-8ab5-74994f40b6a5','觀燕哺雛','何夢桂','宋','宋诗','song-poetry','','[]','閒堂看盡燕雙飛，終日勞勞爲哺雛。',32,'全唐诗/poet.song.235000.json','["閒堂看盡燕雙飛，終日勞勞爲哺雛。", "父母此心誰不有，生兒幾個似慈烏。"]'),
('490d575a-a713-458f-83ff-13d90749e9e2','竹雞冢','何夢桂','宋','宋诗','song-poetry','','[]','活活聲乾落羽翎，分甘碪几委危形。',32,'全唐诗/poet.song.235000.json','["活活聲乾落羽翎，分甘碪几委危形。", "主人肯與封抔土，猶勝當年翳冢青。"]'),
('97cbbb86-e316-421f-ab6f-3f1c943b73e1','自題畫像','何夢桂','宋','宋诗','song-poetry','','[]','七分形貌十分心，縱有丹青畫不真。',32,'全唐诗/poet.song.235000.json','["七分形貌十分心，縱有丹青畫不真。", "蕭散風神清瘦骨，分明小有洞天人。"]'),
('24956142-d9f6-4d6c-96ff-263d48b7159d','與張郎中省菴二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','一統山河遍八埏，江南等作彈丸看。',32,'全唐诗/poet.song.235000.json','["一統山河遍八埏，江南等作彈丸看。", "公來踏遍官田土，只有池蛙不爲官。"]'),
('2d6c5fa1-627f-417b-a696-9473d2aad064','與張郎中省菴二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','青山雲影日悠悠，却怪隨龍上下遊。',32,'全唐诗/poet.song.235000.json','["青山雲影日悠悠，却怪隨龍上下遊。", "能捲滄溟爲雨去，白雲依舊宿林丘。"]'),
('ef334776-1d83-40a6-b162-49e7caa95de8','題二美人圖','何夢桂','宋','宋诗','song-poetry','','[]','美人娟娟江水隔，翠竹蕭蕭江月白。',32,'全唐诗/poet.song.235000.json','["美人娟娟江水隔，翠竹蕭蕭江月白。", "箋心欲寄不成章，竚立思君情脈脈。"]'),
('397d3766-e027-4b8f-b200-31a8f67d1f63','贈吳對山先生','何夢桂','宋','宋诗','song-poetry','','[]','紺裘久墮還天闕，結佩乘雲遺玉玦。',32,'全唐诗/poet.song.235000.json','["紺裘久墮還天闕，結佩乘雲遺玉玦。", "耿光滅沒不可望，一歃寒泉酹秋月。"]'),
('447a8b47-c491-4b2c-bc42-3e5bc4982819','贈錢季實','何夢桂','宋','宋诗','song-poetry','','[]','一醉狂歌天地老，醒來不記邯鄲道。',32,'全唐诗/poet.song.235000.json','["一醉狂歌天地老，醒來不記邯鄲道。", "祁連千丈土一抔，至今下馬陵前草。"]'),
('e153b22c-343f-4ac2-a243-8ea97dc2e8db','贈月山相士','何夢桂','宋','宋诗','song-poetry','','[]','萬古乾坤萬古山，山前萬古月光寒。',32,'全唐诗/poet.song.235000.json','["萬古乾坤萬古山，山前萬古月光寒。", "人生幾度能看月，常被青山與月看。"]'),
('3c9f7dce-7149-4f93-8c62-0232fae77cf8','讀書有感','何夢桂','宋','宋诗','song-poetry','','[]','短髮凌霜强自搔，可能書劍更徒勞。',64,'全唐诗/poet.song.235000.json','["短髮凌霜强自搔，可能書劍更徒勞。", "春秋已降功名薄，秦漢而來智術高。", "天外寸心孤雁影，人間萬事九牛毛。", "却憐刺股徒辛苦，狐貉何曾恥縕袍。"]'),
('73b13f03-a8c6-45f5-9ca6-7c8804214c23','晚雨','何夢桂','宋','宋诗','song-poetry','','[]','已當天色暮，況復雨霏微。',48,'全唐诗/poet.song.235000.json','["已當天色暮，況復雨霏微。", "落葉元無定，因風更自飛。", "壯心欹客枕，寒事到征衣。", "明日臨晴霽，黄花看晚暉。"]'),
('aefb96e3-9bd9-4d1f-9a49-807013f7f75a','梅魂','何夢桂','宋','宋诗','song-poetry','','[]','香滿羅幃凝不消，笛聲吹斷夜迢迢。',32,'全唐诗/poet.song.235000.json','["香滿羅幃凝不消，笛聲吹斷夜迢迢。", "霜蜚月落無尋處，欲倩青衣使者招。"]'),
('7b3e1490-bba8-49d8-9b10-f87f40ffd84f','梅影','何夢桂','宋','宋诗','song-poetry','','[]','玉頰寒肌强對人，今年清瘦不勝春。',32,'全唐诗/poet.song.235000.json','["玉頰寒肌强對人，今年清瘦不勝春。", "相知只有窗前月，摹寫春風水上身。"]'),
('a6859fbb-d21c-4e74-ba83-8f15c0b99699','輓山房先生  其一','何夢桂','宋','宋诗','song-poetry','','[]','東壁無光夜隕星，爲公痛哭淚沾襟。',64,'全唐诗/poet.song.235000.json','["東壁無光夜隕星，爲公痛哭淚沾襟。", "才高不竟平生志，身死空留萬古心。", "聽曲誰能歌白雪，知音徒擬鑄黄金。", "傷嗟遲暮邅吾道，恨不相從九地深。"]'),
('90731bee-4d6d-48a7-abf1-77b9f57fdd1c','輓山房先生  其二','何夢桂','宋','宋诗','song-poetry','','[]','病入膏肓藥砭難，綿綿相憶勸加餐。',64,'全唐诗/poet.song.235000.json','["病入膏肓藥砭難，綿綿相憶勸加餐。", "擊姦曾藉青萍劍，報德慚無白玉盤。", "樹檟未成年歲暮，枯桑猶在海風寒。", "平生書至將盈篋，淚灑長箋不忍看。"]'),
('cf12e0bc-a6b1-422d-ba65-9f03df677ede','古意四首  其一','方一夔','宋','宋诗','song-poetry','','[]','龍文雙寶劍，誰鑄吳山英。',132,'全唐诗/poet.song.235000.json','["龍文雙寶劍，誰鑄吳山英。", "秋水光的皪，俯視千金輕。", "猶餘報仇血，白帝金天精。", "百用不缺折，潛鋒埋故城。", "芒角不可掩，氣衝牛斗星。", "卓哉兩達士，一旦出幽冥。", "顯晦各有數，飛沈兩無情。", "孤雄顧其雌，玉匣時悲鳴。", "吳楚隔千里，滄波會神靈。", "一體互分合，變化不暫停。", "悠悠劍津水，早暮風雲生。"]'),
('e9e2b7ef-3324-4f17-8b49-01f221c90453','古意四首  其二','方一夔','宋','宋诗','song-poetry','','[]','陽聲鼓羣動，更變無停機。',132,'全唐诗/poet.song.235000.json','["陽聲鼓羣動，更變無停機。", "至人奪造化，假合出範圍。", "渭川起老龍，一龍不得隨。", "化爲百尺竹，玉立青差差。", "仙人去市門，三年願相依。", "金丹遲不就，失路將安歸。", "臨分投之杖，平地去如飛。", "還家尚肉眼，棄擲不復持。", "回首失蹤跡，飛騰息天池。", "惟餘萬叢玉，年年長新枝。", "猶疑風雨夜，回龍嘯空陂。"]'),
('7f3fdaa7-5910-4c4e-97e9-550b45eeb293','古意四首  其三','方一夔','宋','宋诗','song-poetry','','[]','秦皇滅諸儒，若人媚幽獨。',156,'全唐诗/poet.song.235000.json','["秦皇滅諸儒，若人媚幽獨。", "偶來得名山，依山結茅屋。", "希聲陶淳風，無意蘄絕俗。", "兒孫日以遠，幾見碧桃熟。", "漁郎從何來，延緣寒溪綠。", "茲遊窺天祕，平生未經目。", "頗見有此容，父老邀我宿。", "清談略晉魏，世路嗟翻覆。", "淹留信可樂，離念苦羈束。", "幡然理回棹，瑟瑟風吹足。", "往來記行迹，溪路三四曲。", "機心不自閟，何事驚麋鹿。", "回首不逢人，白雲渺空谷。"]'),
('1902d96a-2166-4be0-aa6a-a46e0a13b575','古意四首  其四','方一夔','宋','宋诗','song-poetry','','[]','遼海有黄鶴，翛然出塵姿。',120,'全唐诗/poet.song.235000.json','["遼海有黄鶴，翛然出塵姿。", "結巢青松頂，百丈無柯枝。", "磐石護其卵，清露哺其兒。", "一朝羽翼成，丹霄恣遨嬉。", "夕倦宿月窟，朝饑飲瑶池。", "升高忽反顧，昔是今已非。", "歸來三歎息，塵俗無由知。", "焉能與衆鳥，碎啄隨雄雌。", "欲語不可了，復作摩天飛。", "仰望邈不及，千載留餘悲。"]'),
('bfdc711f-a1fc-4529-a3ff-dfae2348ec04','予讀書之室先從兄時南嘗扁以綠猗今二十餘年矣感歎存歿遂成長篇','方一夔','宋','宋诗','song-poetry','','[]','峨峨高山東，迢迢青溪曲。',192,'全唐诗/poet.song.235000.json','["峨峨高山東，迢迢青溪曲。", "采蘅擷薜荔，結搆蝸牛屋。", "中有讀書堂，堂外萬脩竹。", "錯出泉石間，翛然隔塵俗。", "勁剛逢干節，空洞夷齊腹。", "長釣橫江鯨，翠立摩天鵠。", "借問主人誰，彼美清如玉。", "瓶罌空四壁，簡冊富萬軸。", "小篆揭新扁，高步踵前躅。", "籜龍忽變化，遺歌焉忍續。", "歲晚坐相向，此君幸予辱。", "榮悴紛變態，風雨寒暘燠。", "春來枝葉蕃，蒼璆森在目。", "勢且干青雲，肯顧凡草木。", "憐渠痛灑掃，日哦三四幅。", "吾詩試評品，千古配淇澳。"]'),
('4b0730d6-5248-49e9-bd54-e5a205b45ac2','富山泉','方一夔','宋','宋诗','song-poetry','','[]','先故居此山，兩翁各嬋嫣。',144,'全唐诗/poet.song.235000.json','["先故居此山，兩翁各嬋嫣。", "少翁復北徙，宅廢餘此泉。", "翁死且求飲，他水輒棄捐。", "試以真水往，一杯同蛻蟬。", "兩翁不可見，久矣爲飛仙。", "澤餘有盡世，泉流無竭年。", "耜巖少翁後，往歲勘丹鉛。", "倚徙感陳迹，瘦蛟落長牋。", "邇來絕妙語，此意誰能傳。", "豈知援溺手，鐵石新磨鎸。", "嗟予世味薄，飲水拋葷羶。", "時時汲脩綆，洗眼看殘編。"]'),
('1f13fc80-9214-4813-932f-660ffaf833ac','上按察胡大使','方一夔','宋','宋诗','song-poetry','','[]','我生苦不早，已後朱紫陽。',156,'全唐诗/poet.song.235000.json','["我生苦不早，已後朱紫陽。", "居近世未遠，頗亦承餘光。", "恭惟紫陽翁，派接周程張。", "實學有實用，爲世作舟航。", "古人不可見，來者猶有望。", "紫山豪傑士，理學望北方。", "帝憂浙右民，煩公持臺綱。", "吾道無南北，得志同濟量。", "我亦忝諸生，得升繡衣堂。", "厥今民凋瘵，如疾居膏肓。", "棄捐不自保，况復有蓄藏。", "吏貪不加恤，乘時肆奪攘。", "願公活斯民，風俗還虞唐。"]'),
('e02489f2-c71d-4a42-bf20-aecfa4fa4e40','賀寺簿先生入新居','方一夔','宋','宋诗','song-poetry','','[]','紫陽從西來，孤峯望吳越。',120,'全唐诗/poet.song.235000.json','["紫陽從西來，孤峯望吳越。", "自昔有佳人，高蹈造理窟。", "雉山走其下，清淑鬰未發。", "吾宗紫陽居，秀挺鸞鳳骨。", "家學印大程，南北斗柄揭。", "邇來卜新居，佳氣渺葱鬰。", "天香生桂蘭，野性老薇蕨。", "嬉遊獨樂園，翛然立清絕。", "我來坐庭隅，幽草澹風月。", "圖書有真趣，爲指掌中訣。"]'),
('6472af13-c029-40ba-a924-cd2d5571a8e5','牧牛','方一夔','宋','宋诗','song-poetry','','[]','我有折角牛，放在前山麓。',48,'全唐诗/poet.song.235000.json','["我有折角牛，放在前山麓。", "山瘦石稜稜，歲月老觳觫。", "摻摻過百指，仰此種田穀。", "短笛卧斜陽，我飯何時足。"]'),
('d2bac403-473b-4346-8c37-617d79f54907','知幾','方一夔','宋','宋诗','song-poetry','','[]','利欲沈着人，猶如膠漆盤。',48,'全唐诗/poet.song.235000.json','["利欲沈着人，猶如膠漆盤。", "誰能逝不濯，背走急水灘。", "仕宦豈不好，惟有知幾難。", "西風動歸興，至今數張翰。"]'),
('0b0eb3b5-069c-49a7-9a52-200a88f21046','讀李翰林詩','方一夔','宋','宋诗','song-poetry','','[]','喜詩如喜酒，舉世流饞涎。',216,'全唐诗/poet.song.235000.json','["喜詩如喜酒，舉世流饞涎。", "問酒有何好，妙處竟不傳。", "古人日已遠，絕響三百篇。", "後來誰措手，諷詠皆陳編。", "自從騷選起，衆作同蟲蟬。", "憲章日淪喪，變滅成飛烟。", "翰林非世人，金晶應星躔。", "手弄玉帝旂，墮作詩酒仙。", "行跡老屐齒，俠氣餘龍泉。", "淋漓灑醉墨，妙語窮真筌。", "信手拈斧斤，一揮中方圓。", "彼哉夸奪子，駭汗莫敢肩。", "玉堂不能留，飄落南海邊。", "從此誇汗漫，一往五百年。", "生平尚邱壑，夢想岷峨巔。", "慙君贈醉侯，我飲不滴涓。", "我詩如我飲，撫頂期相憐。", "莫乞飛霞佩，學舉白玉盤。"]'),
('8e115abf-b40a-43e6-9d8d-3e538c92aedf','九日讀陶淵明詩','方一夔','宋','宋诗','song-poetry','','[]','晉有靖節翁，古昔稱高士。',144,'全唐诗/poet.song.235000.json','["晉有靖節翁，古昔稱高士。", "自陳簪組後，爲義不兩仕。", "雖乏報韓功，深懷帝秦恥。", "拂衣歸故園，寒菊被栗里。", "醉餘灑新詩，題自庚子始。", "托此明大閑，言外有餘旨。", "我生後千歲，歷十五庚子。", "區區一垤中，起滅紛未已。", "壯夫感頹光，大運悲逝水。", "登高極遐想，舒卷寓至理。", "風期渺相接，衰暮竟誰似。", "酌泉薦芳馨，茫茫九泉起。"]'),
('55e7ded4-ef1a-48a6-a375-0a152c0ea029','夜坐閲書','方一夔','宋','宋诗','song-poetry','','[]','賈不至千萬，仕不至萬石。',96,'全唐诗/poet.song.235000.json','["賈不至千萬，仕不至萬石。", "時窮兩不遂，衰鬢秋蕭瑟。", "平生用力處，文字派六籍。", "胸中萬斛泉，老不出涓滴。", "丈夫處世間，志願何時畢。", "抱此無用物，價重連城璧。", "蛟龍死泥沙，蟠屈留遺跡。", "政使傳後人，虛名復何益。"]'),
('f336ede3-1790-49ed-b57e-f2b2a6092a60','寄題吳愛菊','方一夔','宋','宋诗','song-poetry','','[]','淵明歸故園，心與境俱會。',48,'全唐诗/poet.song.235000.json','["淵明歸故園，心與境俱會。", "種菊滿東籬，高致在菊外。", "故人絕世好，尚友渺千載。", "幽賞屬同流，更有心期在。"]'),
('416f4d2a-48d7-4343-82dd-cb695c802415','古意','方一夔','宋','宋诗','song-poetry','','[]','子房英特人，易老窮根柢。',168,'全唐诗/poet.song.235000.json','["子房英特人，易老窮根柢。", "縱橫出妙用，萬變不離體。", "當其報秦時，家難不顧弟。", "揮槌擣祖龍，結客自燕薊。", "天地爲震動，此身一稊米。", "秦亡志雖酬，韓破顔仍泚。", "來謁龍準公，投機類天啟。", "中原紛戰爭，兩强力難觝。", "雍容談笑間，國恥竟刷洗。", "舊君有反服，臣子獲盡禮。", "雄心就斂退，勳業猶唾涕。", "仙人在何許，高步凌北濟。", "壑松作糗糧，煮石當酒醴。", "千載邈高風，仰望首重稽。"]'),
('85b2dbf4-ca56-4faa-b873-bda70cef15da','郡人有朱買臣嚴子陵按史傳買臣吳人嘗出爲會稽太守名曰鄉郡會稽蓋今兩浙之地吾郡特以去州二十里曰朱池爲買臣昔居之地難以考見其實子陵晚耕於富春山中則今釣臺是也二公出處不同心事亦異姑以其同爲郡人各賦一首使九原有作不悵來者之不我知也  其一','方一夔','宋','宋诗','song-poetry','','[]','魯不識仲尼，妄謂東家氏。',168,'全唐诗/poet.song.235000.json','["魯不識仲尼，妄謂東家氏。", "知音古爲難，而况諧俗耳。", "寒松翳遺貌，弔古獨倚徙。", "歌聲餘老樵，昔居竟誰是。", "當年翁子貧，賣薪沽酒市。", "一朝入漢庭，歘作青雲士。", "出領虎符貴，牛酒賀閭里。", "邸間綬若若，差排庭中吏。", "旁人自送迎，我亦附長史。", "片言負茂陵，奇禍竟博死。", "窮通有定分，何足計戚喜。", "豆羹輒動色，未可欺妻子。", "阿婦非棄翁，頗亦窺見此。", "後車且恥載，誰肯並廟祀。"]'),
('68882efe-bfbc-4407-bcd9-4de060f7bbf6','郡人有朱買臣嚴子陵按史傳買臣吳人嘗出爲會稽太守名曰鄉郡會稽蓋今兩浙之地吾郡特以去州二十里曰朱池爲買臣昔居之地難以考見其實子陵晚耕於富春山中則今釣臺是也二公出處不同心事亦異姑以其同爲郡人各賦一首使九原有作不悵來者之不我知也  其二','方一夔','宋','宋诗','song-poetry','','[]','舟行徵君里，步登徵君山。',120,'全唐诗/poet.song.235000.json','["舟行徵君里，步登徵君山。", "雪瀨潄我齒，玉泉洗我肝。", "遐想臺上人，披裘曳漁竿。", "去齊復適吳，來往浮雲閒。", "一釣得文叔，客星照林巒。", "再釣得小苑，高風凜祠壇。", "古人邈不及，絕俗爲甚難。", "一時尚奇怪，千載起懦頑。", "我歌小招詞，公來顔不歡。", "長嘯震冥杳，載月下前灘。"]'),
('3e367bb7-9c9f-44eb-a08a-471869608a04','昌陽','方一夔','宋','宋诗','song-poetry','','[]','昌陽十二節，茸茸碧且鮮。',96,'全唐诗/poet.song.235000.json','["昌陽十二節，茸茸碧且鮮。", "不堪置几案，拳石留餘妍。", "托根寄幽絕，夐在荒山巔。", "不矚婦女盼，不聞雞犬喧。", "水石相依附，花開已千年。", "一朝服食成，肌骨翔飛鳶。", "我欲啜此草，隠訣無由傳。", "逝將涉浩蕩，相期十洲仙。"]'),
('f7855f0f-0ddf-4dc6-bc45-817c3416b1e9','詠史','方一夔','宋','宋诗','song-poetry','','[]','代馬必死戰，韓盧必死獵。',120,'全唐诗/poet.song.235000.json','["代馬必死戰，韓盧必死獵。", "萬族雖有殊，受性固莫奪。", "君看伏波翁，心火老不滅。", "萬里戰壺頭，赤手擁馬鬣。", "前言一朝酬，英氣半途折。", "海南紀銅柱，城西埋石蕝。", "所以高世人，甘守田園拙。", "梧楸老歸夢，桑梓借餘熱。", "人生貴適意，似用生分別。", "爲問澤車乘，何如水鳶跕。"]'),
('d34583dc-6d4f-46a5-a584-47992f71652c','早行','方一夔','宋','宋诗','song-poetry','','[]','出門挂襆被，客路寒溪早。',72,'全唐诗/poet.song.235000.json','["出門挂襆被，客路寒溪早。", "團團霧中日，淡月隠林梢。", "村巷驅饑牛，楓林度飛鳥。", "山行未十里，佳處輒藉草。", "道逢青衿生，肝膽總傾倒。", "分手各東西，蘋花風嫋嫋。"]'),
('21cadbcf-e6b8-4411-974c-47d2a44d0a3c','晚坐有感','方一夔','宋','宋诗','song-poetry','','[]','青山圍四旁，南斷如金玦。',120,'全唐诗/poet.song.235000.json','["青山圍四旁，南斷如金玦。", "殘霞映寒碧，杳杳鳥孤沒。", "我本忘機人，忽忽老歲月。", "身係三家村，心到極窮髮。", "蕭然病脚僧，丈室坐說法。", "事業誰做盡，堯舜行不徹。", "義理誰說盡，孔孟引不發。", "有心阻世用，自來同一轍。", "人生直如寄，世路會有役。", "何時拂衣去，結筏造溟渤。"]'),
('916c3108-c6bb-4d71-a225-f2a3cace394a','黄楊','方一夔','宋','宋诗','song-poetry','','[]','萬物具生理，日與化工運。',84,'全唐诗/poet.song.235000.json','["萬物具生理，日與化工運。", "黄楊性獨殊，一歲長一寸。", "氣機有時歇，厄會屢遭閏。", "豈無土壤培，亦有雨露潤。", "爾壽傳雲仍，爾木僅尋仞。", "老氏損成益，顔子退爲進。", "至人妙觀物，此理如符印。"]'),
('46ffc4e2-1c9d-4506-a6b8-fb8a93dcb7b5','竹夫人','方一夔','宋','宋诗','song-poetry','','[]','殘陽未斂戍，中夜苦無奈。',96,'全唐诗/poet.song.235000.json','["殘陽未斂戍，中夜苦無奈。", "噆膚跳蚤行，掠面飛蚊過。", "玲瓏織翠縷，有來饋一箇。", "不惟供夜直，亦可專房卧。", "此君丈夫心，節操抱寒餓。", "未免斤斧傷，復受巾幗涴。", "我老乏風情，偃息便慵惰。", "不令魁梧人，化作兒女愞。"]'),
('d2e96627-5681-45f0-af58-d4330c137821','雁奴','方一夔','宋','宋诗','song-poetry','','[]','雁落常水宿，奴輒警暗晦。',132,'全唐诗/poet.song.235000.json','["雁落常水宿，奴輒警暗晦。", "己逸渠處勞，禍患出恩愛。", "老漁窮意巧，半夜弄光怪。", "奴亟告其羣，舉羣驚相戒。", "漁火不時明，奴告不息喙。", "衆方恬夢寐，不悟伏機械。", "一夕雖屢驚，四顧無己害。", "利嘴叢之身，尤恐奴相賣。", "漁者乘其囂，尺箠盡同隊。", "辱令孟堅死，依勢博陸敗。", "小忠悞平昔，今日復何悔。"]'),
('c71fe06d-ff81-4a18-8e78-1b0051697d7e','前梁父吟','方一夔','宋','宋诗','song-poetry','','[]','朝趨梁父岑，暮投梁父麓。',96,'全唐诗/poet.song.235000.json','["朝趨梁父岑，暮投梁父麓。", "左肩抱長欃，右手牽黄犢。", "禾生亙原隰，生計自爲足。", "罷耕還讀書，何必事精熟。", "茫茫萬古墳，苞括納心曲。", "琅山藹空青，淄水漲寒綠。", "嗟我七尺軀，披雲卧幽獨。", "抱膝一長吟，清響振空谷。"]'),
('1b47931d-666d-40e3-a38a-4515c393dcf6','後梁父吟','方一夔','宋','宋诗','song-poetry','','[]','我生在畎畝，志願向此畢。',108,'全唐诗/poet.song.235000.json','["我生在畎畝，志願向此畢。", "糲飯爲我糧，醜女爲我室。", "英英帝家胄，屢駕款蓬蓽。", "片言誤相酬，攙我手不釋。", "立談豢吳兒，再戰走漢賊。", "托孤赴永安，仗鉞駐渭北。", "人生盛意氣，事會靡終極。", "桑株渺何許，歲月去如擲。", "朗然舒卷心，始末本無隔。"]'),
('88aa4fca-2fbb-455b-9398-3686381f9d5d','偶閲淵明開歲古詩因和其韻','方一夔','宋','宋诗','song-poetry','','[]','開歲倏五十，陶翁感浮休。',120,'全唐诗/poet.song.235000.json','["開歲倏五十，陶翁感浮休。", "我生苦後陶，夜夢從之游。", "大塊無停機，歲月去如流。", "棄家客東安，泛泛雙浮鷗。", "羲軒古主人，中古稱旦丘。", "大倫具五常，大法列九疇。", "寥寥向千載，孤唱絕衆酬。", "藐然愧前哲，中路肯止不。", "逝言晚聞道，惻惻懷長憂。", "廓落八紘內，俛仰吾何求。"]'),
('919ccc4c-5ea9-4974-944e-943d569223b1','別洪復翁','方一夔','宋','宋诗','song-poetry','','[]','十載與君友，何曾異悲歡。',144,'全唐诗/poet.song.235000.json','["十載與君友，何曾異悲歡。", "憂寒夜同袍，念饑日同餐。", "晚節各大繆，濁世多波瀾。", "我爭東山墩，君赴金沙灘。", "雲萍不相接，我窮君長歎。", "出門重入門，轉覺營生難。", "故人贈尺書，招我來東安。", "水雲三百里，飛鴻集江磐。", "君如跨海鵬，發軔鶱鶱翰。", "咫尺視萬里，歸泝天池湍。", "梅花點飛雪，相將理征鞍。", "新詩月幾首，願寄青琅玕。"]'),
('9fb9f1e4-b456-4f5a-9b83-286c12182c14','葛溪浴丹泉','方一夔','宋','宋诗','song-poetry','','[]','杉松翳蒼翠，古寺依寒溪。',120,'全唐诗/poet.song.235000.json','["杉松翳蒼翠，古寺依寒溪。", "小橋度空闊，勝事窮朝隮。", "仙人渺何許，昔年此孤棲。", "丹成餘此泉，高步凌雲梯。", "至今浴丹處，精光貫虹霓。", "老仙不厭世，寄跡隨東西。", "當時不相顧，野鶴羣鳬雞。", "一朝上寥廓，指爪留沙泥。", "我生曠劫內，臨老歸途迷。", "猶疑丹在水，清嚥分刀圭。"]'),
('c92d12ff-54e6-4701-8fa3-530b52a07b47','和淵明雜詩奈何五十年韻','方一夔','宋','宋诗','song-poetry','','[]','我生未爲後，議論頗自喜。',72,'全唐诗/poet.song.235000.json','["我生未爲後，議論頗自喜。", "讀書見古人，慷慨欲立事。", "既壯涉憂患，輾轉不如意。", "五十今到門，翻與窮鬼值。", "老馬但垂頭，不似新駒駛。", "前途勿復道，有酒且勤置。"]'),
('904afacb-a152-47a0-a6f4-819e9db388c3','比來東安以歡字十二韻別復翁繼有和章送別今再和答之','方一夔','宋','宋诗','song-poetry','','[]','我携無言子，東去顔不歡。',144,'全唐诗/poet.song.235000.json','["我携無言子，東去顔不歡。", "故人日已遠，嘿嘿寢與餐。", "寄洪樂山水，岡巒湧濤瀾。", "有時戲吟詩，音韻摇風灘。", "朋儕相徵逐，歌笑雜悲歎。", "朝吳暮過楚，千里不憚難。", "功成早斂退，騎鶴伴子安。", "下視地上友，俛首依江磐。", "低飛不能起，俯借摩天翰。", "我老涉世患，衰懦心不湍。", "從君上寥廓，永謝輿與鞍。", "歸來不空手，玄圃收明玕。"]'),
('35c135ac-f91d-4a89-9b38-968060906e8a','詩人詠鴟夷西子之事多矣按越敗於魯哀公元年想鴟夷五餌之策必其時也至哀公二十二年越滅吳西子復歸計其年亦老矣豈鴟夷如洛陽賈人不能忘情於舊約耶','方一夔','宋','宋诗','song-poetry','','[]','去時苧蘿山，送我摶黍叫。',96,'全唐诗/poet.song.235000.json','["去時苧蘿山，送我摶黍叫。", "歸時苧蘿山，迎我桃花笑。", "一別二十年，過眼如風燎。", "人生重後會，世事中前料。", "未驚馬齒長，猶喜雞皮少。", "功名志已酬，富貴頭終掉。", "傍君鴟夷槳，舞我烏棲調。", "撫景惜餘年，烟波老漁釣。"]'),
('9014e52c-8976-4df6-a2d4-4030710de0ce','古意六首  其一','方一夔','宋','宋诗','song-poetry','','[]','老樵腰短斧，朅來此山中。',132,'全唐诗/poet.song.235000.json','["老樵腰短斧，朅來此山中。", "林深絕人跡，邂逅兩老翁。", "石上安棋局，零落歸飛鴻。", "置斧偶坐睨，終竟誰雌雄。", "低頭欲借問，冉冉巢雲松。", "索寞下山去，樹杪餘殘紅。", "不知歲月遠，但見邑屋空。", "神仙在何處，只與人世同。", "眼浄偶自見，心到遥相通。", "片時處仙境，百年坐春風。", "區區笑劉呂，妄覓蓬萊宮。"]'),
('656ccdb7-50d1-46db-a7c0-1e92d922af37','古意六首  其二','方一夔','宋','宋诗','song-poetry','','[]','誰斧若木枝，銅榦蒼玉葉。',144,'全唐诗/poet.song.235000.json','["誰斧若木枝，銅榦蒼玉葉。", "年年來滄波，疑與溟渤接。", "戲携赤玉舄，跨此寒岌嶪。", "飄然造殊庭，不用維與楫。", "浩浩吹天風，凉氣入衣衱。", "拍浮天漢濱，匏瓜芒熚熚。", "黄牛不服箱，放繩掉長鬣。", "素娥不織裳，拋梭理香頰。", "千年蒼蘚痕，機杼空妥帖。", "疑是媧皇土，藏去壓歸篋。", "歸來不知處，滿目迷空堞。", "惟有賣卜人，知向天根躡。"]'),
('e77fd641-693d-43c4-82d1-8578a5803de9','古意六首  其三','方一夔','宋','宋诗','song-poetry','','[]','翩翩南昌尉，來自九江西。',120,'全唐诗/poet.song.235000.json','["翩翩南昌尉，來自九江西。", "天關列虎豹，欲進無階梯。", "臣有治安策，不忍死窮棲。", "浮浮山林氣，披褐朝金閨。", "上言訐貴戚，下言憫羣黎。", "肉食久喑默，狂叫發草藜。", "臣言可采擇，寸刀刳鯨鯢。", "一再不合意，反旆風凄凄。", "君綱墜不振，况復子與妻。", "自諧塵外約，東遊隠會稽。"]'),
('f867bf0a-059a-4162-a892-159e39534dd0','古意六首  其四','方一夔','宋','宋诗','song-poetry','','[]','武夷千餘仞，山上巢羣仙。',96,'全唐诗/poet.song.235000.json','["武夷千餘仞，山上巢羣仙。", "曾遊析木津，醉墮白玉船。", "其下誰換骨，潤州小嬋娟。", "烱烱玉蓮鎖，棲之此山顛。", "丹砂一點染，靈化誰控摶。", "塵根洗不盡，展轉來凡間。", "從言一念失，巫山渺雲烟。", "徒然八十返，空度三千年。"]'),
('f54eff18-5d34-458a-96c0-2ac85197fa02','古意六首  其五','方一夔','宋','宋诗','song-poetry','','[]','牧牛長得嬉，牧馬長得騎。',108,'全唐诗/poet.song.235000.json','["牧牛長得嬉，牧馬長得騎。", "惟有牧羊苦，奔走脚脫皮。", "道人不我惜，令作牧羊兒。", "我羊數萬頭，豈不爲渴饑。", "食草百步間，寒碧青萋萋。", "少許自爲足，不慕飽與肥。", "羊眠即化石，羊行不跳籬。", "竟日卧松下，誰知藉金閨。", "紫烟橫石室，兄來莫相疑。"]'),
('5db67f1e-48d2-4055-9c01-cdde85cdd0c8','古意六首  其六','方一夔','宋','宋诗','song-poetry','','[]','博浪不成功，偶此脫民籍。',108,'全唐诗/poet.song.235000.json','["博浪不成功，偶此脫民籍。", "客從何方來，年紀約五百。", "相逢昧平生，視我猶廝役。", "知是羲皇人，來去了無跡。", "神機不忍閟，袖有青囊冊。", "讀之盡綠字，歷歷幕中畫。", "十年風塵中，談笑等兒劇。", "清濁同一源，凡聖本無隔。", "願言邈清風，歸來抱山石。"]'),
('945b0d2e-edc3-4d97-9171-97365d24a901','田家四事 耕','方一夔','宋','宋诗','song-poetry','','[]','古人以農仕，仕即爲公卿。',96,'全唐诗/poet.song.235000.json','["古人以農仕，仕即爲公卿。", "未仕有常業，安得不躬耕。", "我耕常及時，破塊當初晴。", "墳壚土性異，勤怠人力并。", "泥塗淤手足，霧露沾裳纓。", "婦子挈午餉，勞苦寬我情。", "罷耕亟放牧，吾牛亦饑鳴。", "投耒重回首，深山空月明。"]'),
('240a5c48-0474-4daf-b8e1-d98f34cc6534','田家四事 種','方一夔','宋','宋诗','song-poetry','','[]','我生古揚州，田下異梁雍。',84,'全唐诗/poet.song.235000.json','["我生古揚州，田下異梁雍。", "山田種荒菜，水田種浮葑。", "地力肥瘦兼，農器有無共。", "及時撒新穀，摶黍遞幽哢。", "生意日夜長，移秧趁芒種。", "未嫌豚酒祝，自樂雞黍供。", "落日竹枝歌，猶是豳原頌。"]'),
('d2236954-7196-4bde-b324-2f732813fcc9','田家四事 耘','方一夔','宋','宋诗','song-poetry','','[]','良苗已入土，田間水沄沄。',96,'全唐诗/poet.song.235000.json','["良苗已入土，田間水沄沄。", "昨夜苗根發，翳葉如烟雲。", "草生害我苗，匝月一再耘。", "是時人苦熱，出門天未昕。", "鬰蒸體流膏，爬捽手生皸。", "手荼擁根節，腰草驅蠅蚊。", "青青衿佩子，從事哀我勤。", "哀我勤自樂，爾非沮溺羣。"]'),
('bc5413b5-23eb-4881-b119-eb88887da510','田家四事 穫','方一夔','宋','宋诗','song-poetry','','[]','凉風入衣襟，斜日照墟落。',96,'全唐诗/poet.song.235000.json','["凉風入衣襟，斜日照墟落。", "我稼將登場，築杵聲橐橐。", "宵征備寇盜，日行呀鼠雀。", "腰鎌赴田間，是處竟秋穫。", "刈疾笑翁健，負重慚兒弱。", "山炊雜戎菽，野草配場藿。", "人生累衣食，計較一餉樂。", "已矣復何言，吾生老耕鑿。"]'),
('86c873bb-8be5-4626-9412-5656298e633b','喜雨','方一夔','宋','宋诗','song-poetry','','[]','去年稻田荒，七月青蟲起。',72,'全唐诗/poet.song.235000.json','["去年稻田荒，七月青蟲起。", "今年七月雨，稻田盈尺水。", "人生會有涯，饑飽互煎煮。", "造物如狙公，顛倒生嗔喜。", "我岑枯槁人，未脫烟火味。", "試問河豚羹，何如江鱠美。"]'),
('40edecc7-3778-4186-aa33-e3aa8038e944','予家窗外種竹逾千箇每開窗輒相對終日今歲館前亦多竹遂賦一首','方一夔','宋','宋诗','song-poetry','','[]','五年慣在家，貧賤自稱好。',120,'全唐诗/poet.song.235000.json','["五年慣在家，貧賤自稱好。", "饑鷹空護巢，疲馬長戀藁。", "森萷萬脩竹，自喜結交早。", "旦暮從渠遊，不恨兩枯槁。", "今年出山去，敗鼓費擊考。", "此君不我嫌，到處愜懷抱。", "翛然書齋下，粉黛間新老。", "相看便歌詠，物外恣探討。", "此生一過客，去住何足道。", "竹下有石交，歸來薙幽草。"]'),
('0575307f-97c2-4270-b3aa-855ddc1e3371','詠史 李陵','方一夔','宋','宋诗','song-poetry','','[]','都尉出塞北，全軍戰浚稽。',120,'全唐诗/poet.song.235000.json','["都尉出塞北，全軍戰浚稽。", "喊聲春霆震，殺氣陰雲低。", "單于不相識，借問將軍誰。", "將軍本將種，氏族派隴西。", "天明鼓音死，劍斬軍士妻。", "塵沙昏白日，道路東西迷。", "馬蹄去不返，邊草空萋萋。", "高堂視白髮，到死長悲啼。", "歸期日復日，老病天一涯。", "可憐龍門翁，空作無陰兒。"]'),
('f10c018c-d4eb-4cc5-9e45-af42f2833627','詠史 蘇武','方一夔','宋','宋诗','song-poetry','','[]','中郎出玉門，簜節照絕域。',120,'全唐诗/poet.song.235000.json','["中郎出玉門，簜節照絕域。", "使指未分明，奇禍誰能測。", "劍鈍割不深，一朝來海北。", "霜風入氍毹，冰雪凍服匿。", "老羝石女兒，歲久無出息。", "遣來小居次，無何乳通國。", "古人凜垂戒，男女及飲食。", "多少英雄人，此心滅不得。", "萬里十九年，費盡一生力。", "歸來麒麟中，愁絕遠山色。"]'),
('baa28fab-8743-4a3c-af32-750791a20ae7','詠史 邵平','方一夔','宋','宋诗','song-poetry','','[]','故侯學種瓜，衰榮互相代。',108,'全唐诗/poet.song.235000.json','["故侯學種瓜，衰榮互相代。", "隨時改門戶，不改獨心在。", "中原方起事，未有山西對。", "不藉芒碭雲，遠激浙江匯。", "非關揀點人，自爲非主吠。", "蹉跎志不就，去住無留礙。", "晚入丞相閤，不墮籠絡內。", "片言中臣主，顛倒窮百態。", "除却下邳侯，漢庭無此輩。"]'),
('4f96be74-998c-44b2-b890-fbc0d8612d9f','詠史 謝安','方一夔','宋','宋诗','song-poetry','','[]','安石在東山，豈是無心者。',48,'全唐诗/poet.song.235000.json','["安石在東山，豈是無心者。", "投跡高隠中，妓樂妙陶寫。", "功成間管蔡，灑泣悲用舍。", "乃知富貴人，此心未脫灑。"]'),
('c81d6c18-be49-4bfb-a85d-2efe40ba2930','詠史 楊惲','方一夔','宋','宋诗','song-poetry','','[]','請君邯鄲舞，聽我弘農曲。',84,'全唐诗/poet.song.235000.json','["請君邯鄲舞，聽我弘農曲。", "本是田家人，誤竊封侯祿。", "貴盛難久居，終然手反覆。", "南山有舊業，披榛撒戎菽。", "苗稀草荒穢，欲鋤力不足。", "歸來日已夕，一醉酒新熟。", "歌罷即長眠，悲苦過於哭。"]'),
('c2f64268-4496-4646-b7a5-8a308c880532','感興二十七首  其一','方一夔','宋','宋诗','song-poetry','','[]','斑斑林中雉，雌雄伺朝暉。',72,'全唐诗/poet.song.235000.json','["斑斑林中雉，雌雄伺朝暉。", "鼓翅飛不遠，山田麥苗肥。", "飲啄百步間，未暮相隨歸。", "當春哺羣雛，長大各自飛。", "宇宙豈不大，嗟爾爲生微。", "窮途守一轍，畢命芝與薇。"]'),
('72160a39-15c5-4c74-a26b-6329de23a310','感興二十七首  其二','方一夔','宋','宋诗','song-poetry','','[]','婉婉馬上女，兩頰瑩寒玉。',96,'全唐诗/poet.song.235000.json','["婉婉馬上女，兩頰瑩寒玉。", "弓彎敲鐙踏，側立紛相逐。", "借問誰家兒，近出常山族。", "兒家昔鼎貴，煌煌什朱轂。", "父親守常山，忽值胡馬蹙。", "起義功不成，巢傾卵亦覆。", "妾身轉流落，歲久無錢贖。", "欲去無緣由，安得南飛鵠。"]'),
('1108209c-1d0c-457a-bad9-9cbd714a8052','感興二十七首  其三','方一夔','宋','宋诗','song-poetry','','[]','死時鮑魚臭，生時椒蘭芬。',84,'全唐诗/poet.song.235000.json','["死時鮑魚臭，生時椒蘭芬。", "好惡相補報，不及寸與分。", "當其得勢時，六合旁無人。", "侯邦盡夷滅，胡馬亦逡巡。", "豈知驪山下，金棺化灰塵。", "所以楊王孫，自與木石親。", "纍纍三尺土，悠悠百年身。"]'),
('177ad67c-0289-4797-be7f-4afdb34a9e62','感興二十七首  其四','方一夔','宋','宋诗','song-poetry','','[]','去年春花少，開晚不及時。',72,'全唐诗/poet.song.235000.json','["去年春花少，開晚不及時。", "今年花開早，滿樹紅離披。", "多花豈不好，中有枯死枝。", "夏潦則秋旱，物理有盈虧。", "鬰鬰松與柏，收斂含華滋。", "嚴霜歲欲暮，蒼翠無時衰。"]'),
('6b65e032-f0f1-4bfd-9691-47a94733a5cd','感興二十七首  其五','方一夔','宋','宋诗','song-poetry','','[]','朱樓遠迢遞，繚以十里牆。',120,'全唐诗/poet.song.235000.json','["朱樓遠迢遞，繚以十里牆。", "浮雲隠華桷，夾路翳杉篁。", "山河未曾改，世事不可量。", "往者胡馬來，主人意蒼黄。", "半死半脫走，兒女不及將。", "朝爲綺羅叢，暮作瓦礫場。", "近傳有其妾，託身于襄陽。", "一男作酒保，相望居河梁。", "骨肉各分別，中原渺茫茫。", "浮雲何足羨，俛仰悲荒凉。"]'),
('88e8e6dc-6507-4ef4-b347-5c7a448ac26e','感興二十七首  其六','方一夔','宋','宋诗','song-poetry','','[]','陰陽轉兩輪，五氣扇雙磨。',72,'全唐诗/poet.song.235000.json','["陰陽轉兩輪，五氣扇雙磨。", "有生寓寰中，濛濛如噴唾。", "魚鳥各飛沈，梧棘稱小大。", "多婦彭祖壽，立善夷齊餓。", "衆星欲西行，勁風牽以左。", "蒼蒼望北極，天命知何奈。"]'),
('a28cbcf7-9ab7-4d76-9406-e4330d56cdb5','感興二十七首  其七','方一夔','宋','宋诗','song-poetry','','[]','松柏生高岡，藤蘿托臭味。',96,'全唐诗/poet.song.235000.json','["松柏生高岡，藤蘿托臭味。", "結交青雲上，緩急不相棄。", "生平尚然諾，彷彿杜穉季。", "出入王侯門，平地生翼翅。", "兩都尚勳階，五管盛聲利。", "朝挾尺書去，滿紙一署字。", "贈我千黄金，揮斥猶涕淚。", "兒女憐賤貧，誰知丈夫志。"]'),
('646bbaa2-3211-4e9e-b4dd-2cf8ea5af33e','感興二十七首  其八','方一夔','宋','宋诗','song-poetry','','[]','種竹依遠林，風急杪不折。',96,'全唐诗/poet.song.235000.json','["種竹依遠林，風急杪不折。", "同根有榮枯，枯枝先斷截。", "茫茫天壤間，小大各糾結。", "惟人具知識，兄弟况同血。", "一居卿相位，僕妾借餘熱。", "升沈各爲謀，滴水不通洩。", "人生骨肉親，富貴猶一吷。", "丈夫屬有思，莫笑袁劉拙。"]'),
('112cdd82-4794-442d-a66f-a0290ae16702','感興二十七首  其九','方一夔','宋','宋诗','song-poetry','','[]','浙江萬里浪，杳杳來夾碣。',84,'全唐诗/poet.song.235000.json','["浙江萬里浪，杳杳來夾碣。", "倒流趨海門，震薄魚龍窟。", "舶舟何處來，隨潮出復沒。", "眩眼方摇摇，歘至如飛鶻。", "水天漭無際，雷風互飛發。", "寄身波濤中，性命危一髮。", "寄語弄潮兒，昨夜缺完月。"]'),
('8e8f7d89-ae90-4dd6-b6c2-549f3281c065','感興二十七首  其一○','方一夔','宋','宋诗','song-poetry','','[]','轉丸有餘巧，物莫如蛣蜣。',96,'全唐诗/poet.song.235000.json','["轉丸有餘巧，物莫如蛣蜣。", "置身糞壤中，不復知臭香。", "兒女苦貧賤，自愛錢滿牀。", "丈夫意見別，胡爲死排牆。", "人心最靈智，自合知短長。", "清濁雖異趣，均墮聲利場。", "爲善與爲利，相去爭毫芒。", "不見舜與跖，雞鳴辨存亡。"]'),
('62e1a7a9-7e61-4caf-8a61-cc87c8b1cd8a','感興二十七首  其一一','方一夔','宋','宋诗','song-poetry','','[]','舊籍占東南，相去天一握。',108,'全唐诗/poet.song.235000.json','["舊籍占東南，相去天一握。", "曩聞大瀛海，出縮幾蝸角。", "欲說耳目隘，欲涉關河邈。", "離合自有時，甫見一南北。", "逝將擺世事，羽化騎鸞鷟。", "朝行過夷門，暮去宿易涿。", "三晉多權謀，鄒魯守經學。", "人生出與處，相逢飽商榷。", "棄捐何足惜，無爲悞奇璞。"]'),
('026308d7-51bc-43a1-a9ac-88208100d574','感興二十七首  其一二','方一夔','宋','宋诗','song-poetry','','[]','朝登北邙坂，暮抵樂遊原。',108,'全唐诗/poet.song.235000.json','["朝登北邙坂，暮抵樂遊原。", "燐火翳復吐，髑髏夜呼冤。", "不見昔時主，但見陵與園。", "銀鳬已羽化，石馬猶草根。", "向來爭天子，一口吞乾坤。", "誰知百年後，不免遭樊溫。", "寶玉頻發掘，朽骨無精魂。", "景昭去何處，芳草悲頹垣。", "縣官供衣食，當時多子孫。"]'),
('9322c709-ab96-4f2e-b6f3-263a1cad1484','感興二十七首  其一三','方一夔','宋','宋诗','song-poetry','','[]','月府有奇木，根榦飽清露。',108,'全唐诗/poet.song.235000.json','["月府有奇木，根榦飽清露。", "生香異凡間，衝風落天路。", "高枝舞青鸞，低枝弄霜兔。", "姮娥方妙年，衣采純純素。", "娉婷不肯嫁，含情待誰訴。", "昨與汗漫期，徑向銀河渡。", "授我不死藥，倚徙怨遲暮。", "即席欲服食，終夕愁相誤。", "悠悠下高寒，回首空烟霧。"]'),
('513785d9-9f1e-41b0-9e66-69edb0472575','感興二十七首  其一四','方一夔','宋','宋诗','song-poetry','','[]','南國有美人，紈素閟清艷。',84,'全唐诗/poet.song.235000.json','["南國有美人，紈素閟清艷。", "房櫳凄冷風，孤缸颭寒燄。", "抱琴鼓黄鍾，盎盎牛鳴塹。", "一彈春岫妍，再鼓秋波灧。", "却立步蒼茫，嘿嘿有何念。", "秋夜不肯明，霜露畏點染。", "獨宿守空帷，寸抱耿霜劍。"]'),
('bdb11b80-10c9-4dae-8f23-10efb9c0f3b1','感興二十七首  其一五','方一夔','宋','宋诗','song-poetry','','[]','石蘭媚幽姿，叢生在空谷。',84,'全唐诗/poet.song.235000.json','["石蘭媚幽姿，叢生在空谷。", "霜雪凍不死，寒碧秋更綠。", "結交薇蕨中，疇昔傍人屋。", "山行偶見之，采采不盈掬。", "歲久未消歇，懷袖自清馥。", "我欲寫君心，寄以孤生木。", "必有非耳人，聽此無譜曲。"]'),
('68f1fc9b-c9c2-43b8-9e4e-3ce069a92a26','感興二十七首  其一六','方一夔','宋','宋诗','song-poetry','','[]','天陽居盛夏，生長無時休。',120,'全唐诗/poet.song.235000.json','["天陽居盛夏，生長無時休。", "熒惑欲何詣，渴奔極炎洲。", "老龍恐枯死，深潛閟陰幽。", "攢峯擁凝碧，玉鑑開寒眸。", "神靈護甿俗，盤盂置鰼鰍。", "雷公持玉斧，天女挾行輈。", "行雨豈不苦，軃懶化癡牛。", "煌煌飛電光，上下窮其搜。", "嗟龍獨何避，自愧乏世求。", "變化付雛衆，畢命歸寒湫。"]'),
('4f9afc11-f59f-4b5c-b4bf-a1bcef02fe4f','感興二十七首  其一七','方一夔','宋','宋诗','song-poetry','','[]','百年特生木，堅骨餘蒼榦。',84,'全唐诗/poet.song.235000.json','["百年特生木，堅骨餘蒼榦。", "棄材偶見收，奇製出野爨。", "絙以朱絲絃，猗蘭度將半。", "相思越關河，安得見此粲。", "悲來不成調，清響忽中斷。", "沈吟卷羅衣，終夕愁零亂。", "明月照空庭，盈盈滿霄漢。"]'),
('c91be4d3-df21-4398-9563-a4a75630325d','感興二十七首  其一八','方一夔','宋','宋诗','song-poetry','','[]','雅道久絕響，遺詩邈誰繼。',84,'全唐诗/poet.song.235000.json','["雅道久絕響，遺詩邈誰繼。", "烈士死無意，古風未淪替。", "後來何足道，翕翕逐聲勢。", "一朝有蹉跌，鳥散魚深逝。", "萬物有殊性，小大各爲計。", "松柏生高岡，不肯附蘿薜。", "世路不可回，吾自尋吾契。"]'),
('233d5b7b-5b02-4002-b7c3-05f3f107a19b','感興二十七首  其一九','方一夔','宋','宋诗','song-poetry','','[]','昔聞楚山人，服毳而冠鶡。',96,'全唐诗/poet.song.235000.json','["昔聞楚山人，服毳而冠鶡。", "危坐古松根，不饑亦不渴。", "顔色白如玉，千歲如電抹。", "我行不憚遠，晨去披裋褐。", "平生戀着心，恩愛資妙割。", "開口諒來意，丹鼎分圭撮。", "相看語未了，冉冉翔木末。", "歸來問故人，雲山渺空闊。"]'),
('097ab303-9028-4c4f-b47d-a06d98df5c7a','感興二十七首  其二○','方一夔','宋','宋诗','song-poetry','','[]','著籍占杜曲，別業在臨淄。',120,'全唐诗/poet.song.235000.json','["著籍占杜曲，別業在臨淄。", "雞號夜鐸靜，汗血逐膏脂。", "縱橫一握算，顛倒逢笑嬉。", "舉俗以爲妙，紛紛盡愚癡。", "不見朱公子，千里來相師。", "偶然得我策，沼吳航妖姬。", "祕此枕中術，若有千歲期。", "大化常不偶，日與人事移。", "人事多乖忤，汝計不得施。", "君看貨殖傳，刀間有衰時。"]'),
('ed76d049-775b-4551-adbd-07e45a60627c','感興二十七首  其二一','方一夔','宋','宋诗','song-poetry','','[]','冀北渥洼種，墮地已汗血。',120,'全唐诗/poet.song.235000.json','["冀北渥洼種，墮地已汗血。", "深目老奚奴，日夜供剪刷。", "一朝混南朔，馳道三丈闊。", "道邊館候騎，歷歷抵燕越。", "吳兒富金錢，補買計家活。", "牽來中程度，火印死不滅。", "置之皂櫪中，時彼芻與秣。", "往來給官行，飛去如電抹。", "奔走皮骨空，不見淹歲月。", "區區鹽車中，莫笑駑馬劣。"]'),
('b0907900-41ee-4b66-8dfe-98ccfd968caa','感興二十七首  其二二','方一夔','宋','宋诗','song-poetry','','[]','萬山斗入處，百獸家其間。',120,'全唐诗/poet.song.235000.json','["萬山斗入處，百獸家其間。", "天寒橡栗富，朝食暮未還。", "不知鵲與盧，與之有何冤。", "霜晨飽以飯，獵夫亦加餐。", "昨日料蹄跡，銀灣水猶渾。", "解紲任所之，理氣升岡巒。", "忽然得遺臭，逐逐窮千山。", "歸塗巖谷震，倒掛九節斑。", "渾含喜欲舞，明朝急輸官。", "犬乎爾誠能，終然死霜菅。"]'),
('f074d686-e39e-48d5-a0dd-345cfb77631c','感興二十七首  其二三','方一夔','宋','宋诗','song-poetry','','[]','桓公讀古書，慙其堂下斲。',96,'全唐诗/poet.song.235000.json','["桓公讀古書，慙其堂下斲。", "呼來與之談，妙手不可學。", "人生苦未悟，發軔要切琢。", "譬如搜海珍，澄汰江河濁。", "不辭用力久，奇寶收把握。", "君爲談空人，皮毛俱解剝。", "超遥不二門，機鋒森劍槊。", "從渠透玄妙，風影不可捉。"]'),
('ce420a29-d87d-472d-beae-1212fe6de4aa','感興二十七首  其二四','方一夔','宋','宋诗','song-poetry','','[]','吾聞羲軒時，真淳初未散。',120,'全唐诗/poet.song.235000.json','["吾聞羲軒時，真淳初未散。", "人人悟此理，不用一言贊。", "漂流三季後，前聖多憂患。", "木鐸方大鳴，音響惜中斷。", "百家自其後，非是紛相難。", "父子起爭端，恨死呻吟緩。", "秦人規我隙，行素俱灰炭。", "讀律不讀書，條貫毛髮亂。", "嗟彼商顔人，坐不學城旦。", "一曲紫芝歌，應有三人歎。"]'),
('1b492aec-bad2-41b5-b9da-cf8f1730b111','感興二十七首  其二五','方一夔','宋','宋诗','song-poetry','','[]','雄蜂採花粉，雌蜂銜花汁。',96,'全唐诗/poet.song.235000.json','["雄蜂採花粉，雌蜂銜花汁。", "粉以作黄蠟，汁以蒸白蜜。", "不辭盜我廩，但規安我室。", "吾窮還可忍，歲歲看分出。", "不見岐周人，先世但積德。", "土地付獯狄，自愛豳沮漆。", "兒孫徧天下，魯衛酆郇畢。", "勿言天未定，此理終可必。"]'),
('004061f5-adb2-416c-a861-e07327e93393','感興二十七首  其二六','方一夔','宋','宋诗','song-poetry','','[]','屏前戲羣優，黄冠與榛杖。',120,'全唐诗/poet.song.235000.json','["屏前戲羣優，黄冠與榛杖。", "喜怒視朝暮，弔慶隨俯仰。", "不知有線索，但道多伎倆。", "須臾屏後人，掣去無影響。", "人生大化中，天地一罝網。", "紛紛聲利場，舉世爭掉鞅。", "此身歸空虛，身外計得喪。", "我笑癡絕人，長作去來想。", "區區曹孟德，詭譎窮萬狀。", "聞道西陵墳，妓樂閙黄壤。"]'),
('44050ad4-9cee-4ec7-88ad-7c03be7d41e2','感興二十七首  其二七','方一夔','宋','宋诗','song-poetry','','[]','我觀古人書，得見千載上。',108,'全唐诗/poet.song.235000.json','["我觀古人書，得見千載上。", "正閏互立論，南北紛相謗。", "自從獲麟後，法度久淪喪。", "非是千萬端，史筆不可仗。", "我欲作野史，筆法師素王。", "文章行誅賞，約束歸至當。", "其人負吾誅，勿謂已屬纊。", "書成不流傳，則本留千嶂。", "還有知我人，百世永相望。"]'),
('faffd2c8-4847-4554-b8d8-8d6b9aae5cbf','夜坐苦蚊','方一夔','宋','宋诗','song-poetry','','[]','萬物有常理，動息隨昏昕。',288,'全唐诗/poet.song.235000.json','["萬物有常理，動息隨昏昕。", "區區蟲豸中，惡毒無如蚊。", "云是鬼母化，佛語非傳聞。", "喙尺利芒刺，腰圍隠花紋。", "饑尋飛翅輕，飽飲酡顔醺。", "搏噬以自肥，乘時鼓妖氛。", "潛伏草莽間，窺伺日向曛。", "須臾却四出，攢集窮崖垠。", "橫空聚復散，如布鵝鸛軍。", "騰身飛猱捷，發喊迅雷磤。", "瞥然闖門戶，來者何繽紛。", "不但入翠幕，偏工惱紅裙。", "端坐缺隄障，各各磨牙齦。", "血肉生咀嚼，斑駁瘃與皸。", "如塗守宮血，丹砂服兼斤。", "紈扇不住手，摇動酸骨筋。", "或時中指麾，殷輪血朱纁。", "雖能殺一二，未足空其羣。", "有來效方略，薙草收蕕薰。", "延燒煽烟焰，殺氣凝陰雲。", "羅空燖鴞隼，搜野醢䴥麕。", "醜類盡驅逐，暫息苗與獯。", "自從生盤古，元氣日磔分。", "有生潰亂出，甘苦更臭芬。"]'),
('c6ad7411-bb04-4bb7-9deb-5732582a9834','重九前一日與何會卿諸友分韻得日字禁體用字','方一夔','宋','宋诗','song-poetry','','[]','人生多別愁，日月去如擲。',120,'全唐诗/poet.song.235000.json','["人生多別愁，日月去如擲。", "飛鴻背朔雲，老去猶旅食。", "良會不可常，一歲四五日。", "悠然千載上，此願何時畢。", "是時屬秋季，月魄如弦直。", "倦翰縱橫飛，暮景凝紺碧。", "園英澹寒芳，貧女改顔色。", "咄哉值茲辰，僅隔風雨夕。", "心賞了無餘，萬物空相逼。", "勿歎客囊空，冷面令渠赤。"]'),
('7b131c1e-008a-4f96-8eff-98b3d676c8d6','送月溪范景淳謁告寧母','方一夔','宋','宋诗','song-poetry','','[]','小范湖海豪，霜翮迥獨立。',192,'全唐诗/poet.song.235000.json','["小范湖海豪，霜翮迥獨立。", "詩名三十年，卷軸森戢戢。", "合陪砥砮貢，昱簉鵷鷺入。", "蹉跎墮網羅，取勢斜飛集。", "栖栖縣博士，進退階伍什。", "此來歎何晚，風詩清可挹。", "東安號多士，騷墨居諫給。", "餘芳襲學子，簪筆負箱笈。", "先生隠講幃，淵源探軻伋。", "詵詵榱桷材，大匠總收拾。", "我亦箇中人，奔走緣縷粒。", "識字多不多，炙竹槁無汁。", "衰窮兩相值，噓呵借君濕。", "親幃惻盤羞，我志已不及。", "是時秋向殘，客路西風急。", "寒溪月正明，歸曬舊簑笠。"]'),
('7434a24a-11dc-4063-a82b-3da0de524e5f','壽雲岫徐友謙','方一夔','宋','宋诗','song-poetry','','[]','武林有雲岫，上有方外士。',168,'全唐诗/poet.song.235000.json','["武林有雲岫，上有方外士。", "昔年謁秦皇，渡海萬羅綺。", "蛾眉雖可憐，颯若風過耳。", "歸來但却掃，隠見白雲裏。", "舉案偕逸妻，應門付稚子。", "野興老薇蕨，天香茁蘭芷。", "自云初生時，彷彿記癸巳。", "今年值甲午，六甲再輪起。", "我來欲問道，浮榮如脫屣。", "終年坐臯比，如折當門齒。", "仙人據槁梧，今昔一隠几。", "憐我壯非少，星霜後一紀。", "石爐煉神丹，願留候薪水。", "丹成逐仙去，千歲一洗髓。"]'),
('662b1363-e8cf-47ea-be8b-2a39ba9405df','徐友謙小築冒雨訪何通叟途中作','方一夔','宋','宋诗','song-poetry','','[]','昔有王子猷，連夜泝剡溪。',108,'全唐诗/poet.song.235000.json','["昔有王子猷，連夜泝剡溪。", "自要看雪月，借人作標題。", "與君客異鄉，咫尺隔東西。", "良會不可數，花時飲桃蹊。", "俛仰便陳迹，霜葉颯已萋。", "近來費要約，尺書寄赫蹏。", "天慳竟未破，霧雨猶溟迷。", "此來有緣事，小築喧拱枅。", "請君堆壁酒，洗我流骹泥。"]'),
('6eca75dd-a307-4a30-bba9-737285c20b37','寄蒙泉王南叟','方一夔','宋','宋诗','song-poetry','','[]','憶昔未識易，來訪易祖師。',108,'全唐诗/poet.song.235000.json','["憶昔未識易，來訪易祖師。", "丹墨事點勘，君時坐臯比。", "轉眼十五載，君壯我已衰。", "爾來各異縣，漂泊寄一枝。", "重趼有問道，未省官與私。", "君處瀟灑地，一掃千首詩。", "風濤隔浩渺，相望如九嶷。", "寄音無家客，爲我問所思。", "桑榆借餘暖，歸來定何時。"]'),
('4d90d727-1892-4d5d-ae27-950406d44b8d','夜夢入一市井中見有總角道人能相人者往來熟視予久之其語不能記也因授予以一握算籌謾記其事','方一夔','宋','宋诗','song-poetry','','[]','雞鳴起羣蟄，往來黑蚍蜉。',156,'全唐诗/poet.song.235000.json','["雞鳴起羣蟄，往來黑蚍蜉。", "似聞塵埃中，亦有玉雪流。", "夜夢忽見之，恍如雲夢州。", "其人髻雙髽，衣上百結裘。", "知有袁李術，精神寄雙眸。", "語我我不解，羅縷維與陬。", "臨分忽有贈，付我一把籌。", "振衣逐輕矯，去去逝莫留。", "飛空度杳渺，劃然墮巖幽。", "我豈富貴人，胡椒窮豆區。", "長貧博長健，此理更王囚。", "仙人去何許，往往巢嵩邱。", "俗緣幾時了，約我三千秋。"]'),
('ead191ab-2d3b-4711-98c1-b370117559ae','續詠史二首 嚴君平','方一夔','宋','宋诗','song-poetry','','[]','西蜀嚴夫子，易老養高致。',72,'全唐诗/poet.song.235000.json','["西蜀嚴夫子，易老養高致。", "日閲裁數人，少取多論議。", "初不要贏餘，未暮輒關肆。", "人知取人廉，要之亦餘事。", "假我龜策業，行我誨人意。", "夫子不棄世，誰言兩相棄。"]'),
('12f49d23-e412-4241-8246-e74b044e424f','續詠史二首 韓伯休','方一夔','宋','宋诗','song-poetry','','[]','賣藥長安市，古有韓伯休。',72,'全唐诗/poet.song.235000.json','["賣藥長安市，古有韓伯休。", "紛紛要諧價，百喚不轉頭。", "坐令兒女覺，暮去不稍留。", "人生異鳥獸，飲啄擇所求。", "豈無爪距才，而要安籠囚。", "貧賤亦有道，不獨爲身謀。"]'),
('bc237904-e3bd-4e6c-b8ef-bfc58f89d21d','次韻通甫贈別','方一夔','宋','宋诗','song-poetry','','[]','借我折絃琴，彈君不調曲。',144,'全唐诗/poet.song.235000.json','["借我折絃琴，彈君不調曲。", "此材從何來，妙斲嶧陽木。", "一奏唱離鸞，再和彈別鵠。", "音響無人知，清絕過如玉。", "若人太古民，不肯墮塵俗。", "寫興希夷前，袖手澹無欲。", "彼哉紈袴兒，下視等毛粟。", "憐我來鄉村，妙詩時往復。", "相思隔碧雲，清嘯振幽谷。", "老我空自憐，頼君時擊觸。", "知音古來稀，不數晉荀勗。", "紛紛箏笛耳，勿與相徵逐。"]'),
('9d148798-f623-4f82-9279-f8155b832925','寄呈何潛齋小有洞天','方一夔','宋','宋诗','song-poetry','','[]','小有古洞天，仙峯戴靈鰲。',108,'全唐诗/poet.song.235000.json','["小有古洞天，仙峯戴靈鰲。", "何人失守衛，飛去隨波濤。", "朅來文昌宮，還作貴人牢。", "貴人舊散仙，稍厭官府勞。", "悵然念人世，謫居領巖嶅。", "饑食柏樹子，渴飲松枝醪。", "涕唾視勳業，習氣餘詩騷。", "我亦慕仙者，何時脫羈絛。", "終携綠玉杖，東去訪盧敖。"]'),
('16169b89-6927-4478-8734-1c301220b64b','續感興二十五首  其一','方一夔','宋','宋诗','song-poetry','','[]','猛虎等百獸，天賦與長雄。',108,'全唐诗/poet.song.235000.json','["猛虎等百獸，天賦與長雄。", "曼胡利秋戟，隅目磨青銅。", "從知世路暗，羣行各西東。", "吼地一長嘯，颯颯來悲風。", "饑來待人肉，不數豹與熊。", "肥領而黑喙，不知是何蟲。", "坐卧不自防，穴爾皮毛中。", "爾虎雖云猛，一旦皮骨空。", "慎勿欺微細，即且制神龍。"]'),
('b91f4d77-39c5-412e-97f2-664fbbd42a86','續感興二十五首  其二','方一夔','宋','宋诗','song-poetry','','[]','惡木生高岡，枝疎上指天。',96,'全唐诗/poet.song.235000.json','["惡木生高岡，枝疎上指天。", "雨露非有私，蟠踞幾何年。", "蕘子寢其下，山鳥棲其巔。", "匠石過不睨，生理得自全。", "皮爲野火燒，根爲螻蟻穿。", "空中不足恃，一朝踣而顛。", "上有千歲藤，相依久纏綿。", "樹猶不自保，爾藤何足憐。"]'),
('a0d454c2-1678-4421-96b3-60e82ee69b3d','續感興二十五首  其三','方一夔','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大塊無私運，萬象同一陶。',108,'全唐诗/poet.song.235000.json','["大塊無私運，萬象同一陶。", "及其成器時，罅漏雜堅牢。", "所以一世人，長短紛馬毛。", "窮或仁與善，達或虐與饕。", "共疑造物繆，名利相煎熬。", "人生有常理，賦命安可逃。", "爲善不必疑，禍福任所遭。", "孰云漆園達，夷跖均天弢。", "見夷不見疇，泰山等秋毫。"]'),
('0f6fe772-8c68-4030-9a2e-013453c2858c','續感興二十五首  其四','方一夔','宋','宋诗','song-poetry','','[]','移根托西園，桃李賞奇遇。',96,'全唐诗/poet.song.235000.json','["移根托西園，桃李賞奇遇。", "春妍雖可憐，顔色悲中路。", "奈何窮巷士，多被才華誤。", "諸公謬愛客，輪囷獲殊顧。", "投分未云深，容易輸情愫。", "恩光借春陽，滋液荷凝露。", "悠悠當路塵，素地輕點污。", "歲暮抱棄捐，君看囚山賦。"]'),
('9c78c157-6c79-41b4-8150-d956ffaff7be','續感興二十五首  其五','方一夔','宋','宋诗','song-poetry','','[]','濁水豈無月，水濁不受光。',96,'全唐诗/poet.song.235000.json','["濁水豈無月，水濁不受光。", "君看此孤蟾，出入天中央。", "遍滿千家門，徘徊度回廊。", "由來誰分璧，招我昏暗場。", "空庭澹相對，湛湛肺肝凉。", "浮雲絕點翳，寶此光明王。", "天高萬籟寂，參斗低復昂。", "人生何時畢，收拾還穹蒼。"]'),
('521c19ff-92fe-4666-8114-84f93ad587f2','續感興二十五首  其六','方一夔','宋','宋诗','song-poetry','','[]','銅駞向京洛，千里牽雙輪。',120,'全唐诗/poet.song.235000.json','["銅駞向京洛，千里牽雙輪。", "分不埋荆棘，去鄴復還秦。", "自辭秋風客，不浪五百春。", "悲歡與窮泰，過眼如飛塵。", "眷言返桑梓，茂陵翳荒榛。", "憶昔禹鑄鼎，羅縷九土珍。", "猶嫌問輕重，推落泗水濱。", "况爾不任重，頑鈍磨不磷。", "未知從此去，何時免漂淪。", "勿歎流落苦，渠更多閲人。"]'),
('d0d9ce29-f981-41f7-a35a-cfc6146b1b78','續感興二十五首  其七','方一夔','宋','宋诗','song-poetry','','[]','鴻鈞大氣力，日夜轉範模。',96,'全唐诗/poet.song.235000.json','["鴻鈞大氣力，日夜轉範模。", "賦予有定形，不與萬變俱。", "君看三春時，動植紛萬殊。", "一氣自結束，誰與施粉朱。", "人生況知識，均此造化罏。", "豈是風火煽，假合成形軀。", "戀戀千歲藥，莽莽三生塗。", "從渠夢幻論，袖中得玄珠。"]'),
('2dca528f-5159-4a54-bae7-b2d0bed1722b','續感興二十五首  其八','方一夔','宋','宋诗','song-poetry','','[]','雲日半解駁，東上雨中晴。',96,'全唐诗/poet.song.235000.json','["雲日半解駁，東上雨中晴。", "不知誰幻化，倏然成氣形。", "精光錯異采，勢且迫太清。", "良苗不潤澤，咫尺夷大明。", "兒童爭指目，萬象俱晦冥。", "須臾換光景，變滅不暫停。", "天運亙終古，百怪終無成。", "吾欲乘清風，再拜叩玄精。"]'),
('ce3e5f7a-ff51-4e35-baed-a23c0ce5266a','續感興二十五首  其九','方一夔','宋','宋诗','song-poetry','','[]','二女灑竹淚，盡是心中血。',96,'全唐诗/poet.song.235000.json','["二女灑竹淚，盡是心中血。", "精誠著於物，千載猶不滅。", "當時從南巡，豈少稷與契。", "奈何比孤纍，匍匐陽城謁。", "皇英獨何人，風泉共幽咽。", "可憐女子心，慷慨男兒烈。", "湘水流不斷，誰道恩情絕。", "何時見歸來，續君遠離別。"]'),
('9df993db-f849-41a2-b1ff-c465cf18b564','續感興二十五首  其一○','方一夔','宋','宋诗','song-poetry','','[]','老火久斂戍，蓐收令西方。',96,'全唐诗/poet.song.235000.json','["老火久斂戍，蓐收令西方。", "塵沙隨白日，慘澹無晶光。", "故葉改顔色，過雁新著行。", "孤坐墜秋月，寒燈颭空房。", "悵然盛時節，開緘理衣裳。", "芙蓉久當采，浩蕩不可量。", "芬芳易消歇，歲暮安得長。", "毋爲守空死，萬代同山岡。"]'),
('742ade7f-c271-463c-a565-258f2067854b','續感興二十五首  其一一','方一夔','宋','宋诗','song-poetry','','[]','西遊歷劍閣，寡僕敝輪鞅。',108,'全唐诗/poet.song.235000.json','["西遊歷劍閣，寡僕敝輪鞅。", "水餐掬哀湍，林宿拾墜橡。", "悲風振古木，猩鼬挾魍魎。", "十步九詰盤，奇險躋攀上。", "擔囊偶不意，一跌墮萬丈。", "岷峨渺何許，注目極遐想。", "窮年食外方，浮蹤任漂蕩。", "何時御長風，振足謝籠網。", "不須計三餐，迎我歸蒼莽。"]'),
('fe748f21-184b-4f76-a606-629e0247c4f3','續感興二十五首  其一二','方一夔','宋','宋诗','song-poetry','','[]','黄鵠浴海水，一舉凌紫埃。',96,'全唐诗/poet.song.235000.json','["黄鵠浴海水，一舉凌紫埃。", "長風九萬里，正值天門開。", "不知食何食，雲路方徘徊。", "嗟我鴻雁侶，避寒聲悲哀。", "失身墮泥滓，腹背日摧頹。", "城東極惡少，挾彈巧相猜。", "稻粱未足溉，雲雨何時來。", "不希附脩翮，有分終蒿萊。"]'),
('b81588bd-dc0e-4e46-9149-e1613e8e9564','續感興二十五首  其一三','方一夔','宋','宋诗','song-poetry','','[]','大化差不齊，人事固多繆。',72,'全唐诗/poet.song.235000.json','["大化差不齊，人事固多繆。", "紛紛騁牙角，日夜齧且鬭。", "所以椅桐中，徘徊束孤咮。", "人情隨盛衰，世途迭起仆。", "天命有定分，氣數安能囿。", "去去息吾駕，西山老危岫。"]'),
('ac9167bc-e56c-40a4-b917-8089541ef225','續感興二十五首  其一四','方一夔','宋','宋诗','song-poetry','','[]','揚州舊服卉，木綿白茸茸。',96,'全唐诗/poet.song.235000.json','["揚州舊服卉，木綿白茸茸。", "縷縷自余年，紡績燈火中。", "織成一束素，上有浴海鴻。", "歲寒若可恃，凄凄凜霜風。", "昨夜縣牒下，頭綱出城東。", "殷勤赴官急，瘢瘡免殷紅。", "我寒那可忍，負此卒歲功。", "不知落誰手，輸入秦娥宮。"]'),
('b64dce25-745c-499c-8701-5636ae6dd366','續感興二十五首  其一五','方一夔','宋','宋诗','song-poetry','','[]','瞿曇未生世，摩詰果誰宗。',108,'全唐诗/poet.song.235000.json','["瞿曇未生世，摩詰果誰宗。", "問答了不語，不立文字工。", "開流蕩千古，一雌和羣雄。", "揮斤紛萬變，動寂不離空。", "鏡壞光不滅，迴轉如輪風。", "有能詰其迹，推入滉瀁中。", "以此連環入，合散常無窮。", "愚者誘罪福，高者超神通。", "孔孟久不作，誰能掃其蹤。"]'),
('d811881d-c93f-467f-a21b-c11bff9999d8','續感興二十五首  其一六','方一夔','宋','宋诗','song-poetry','','[]','我賈賈日本，挂席窮南海。',84,'全唐诗/poet.song.235000.json','["我賈賈日本，挂席窮南海。", "冰夷鬭蛟龍，牙角吐光采。", "血人以宴娭，窟宅一朝改。", "赤手拾明月，天幸獨我在。", "歸赴王侯需，價直十百倍。", "匹夫惜性命，貪冒以賈罪。", "歌笑履波濤，竟死復何悔。"]'),
('90356269-55c5-4ff0-856a-3f5c671bf98f','續感興二十五首  其一七','方一夔','宋','宋诗','song-poetry','','[]','飄颻瑶臺雪，沆瀣竹林露。',72,'全唐诗/poet.song.235000.json','["飄颻瑶臺雪，沆瀣竹林露。", "蕭然立高寒，不受世滓汙。", "采芳拾三秀，徘徊崑山路。", "譬如漆園像，華屋非其處。", "誰能使蹇修，再拜扣情愫。", "湘波日摇蕩，去去悲遲暮。"]'),
('65853d9e-e494-43b8-a3bb-11b9492f85df','續感興二十五首  其一八','方一夔','宋','宋诗','song-poetry','','[]','文章不用世，毫端弄春妍。',96,'全唐诗/poet.song.235000.json','["文章不用世，毫端弄春妍。", "滿聽疑可采，躡空若浮烟。", "君尹西都日，琅琅賈董篇。", "如種田得穀，如鑿井得泉。", "子虛與大人，縹緲淩雲仙。", "簜節病桑梓，不置巢邊鳶。", "問君取士意，取士當誰先。", "勿取春華艷，祇取秋柏堅。"]'),
('4d0fce05-179b-4810-a6ae-cb654e1ada02','續感興二十五首  其一九','方一夔','宋','宋诗','song-poetry','','[]','化生如雀雉，隨氣更變易。',96,'全唐诗/poet.song.235000.json','["化生如雀雉，隨氣更變易。", "卵生如鵝鴨，不交無羽翼。", "人死心不滅，化作秋柏實。", "俄頃復爲人，萬化無終極。", "莊周固嘗云，知命故不惑。", "我生異草木，未可從橫直。", "縱然反常理，一二於萬億。", "種禾不生豆，此喻要嘿識。"]'),
('d56dd3c4-c4fd-4feb-841f-a60ef0d99982','續感興二十五首  其二○','方一夔','宋','宋诗','song-poetry','','[]','老氏嗇而生，併力攻一境。',96,'全唐诗/poet.song.235000.json','["老氏嗇而生，併力攻一境。", "深入黑暗中，杳杳無光景。", "佛氏定而死，百動不離靜。", "了了誰在眼，莫掇水中影。", "終然歸空無，用處各馳騁。", "紛紛墮此中，未悟此二柄。", "漂流餘千年，誰能折鋒穎。", "邈哉我前修，忠信得要領。"]'),
('ac3dfb74-a7de-435a-b9e0-0589144224a5','續感興二十五首  其二一','方一夔','宋','宋诗','song-poetry','','[]','匣空龍得偶，厨封畫通神。',120,'全唐诗/poet.song.235000.json','["匣空龍得偶，厨封畫通神。", "可憐種瓜客，猶自標故秦。", "當時祖龍死，逐鹿灞水春。", "早飛將軍檄，晚分丞相茵。", "抵死心不閒，不顧芻狗陳。", "陶朱去越後，未肯休此身。", "猶聞載窈窕，千金散賤貧。", "何如白雲叟，自與青山鄰。", "十年一易世，眉目輒少嚬。", "悠悠華山裏，甘作騎馿人。"]'),
('8f389571-1295-4f64-85c9-e6a739a1d178','續感興二十五首  其二二','方一夔','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','金陵舊長安，譙郡今豐沛。',120,'全唐诗/poet.song.235000.json','["金陵舊長安，譙郡今豐沛。", "吳州對楚山，二水相縈带。", "團團清淮月，久落青天外。", "長江穴岷峨，奔迫走吳會。", "一朝金翅飛，萬丈鐵鎖碎。", "列郡空崚嶒，故國餘叢薈。", "升高望中原，極目了河岱。", "大運有奔淪，興廢更百代。", "客行秋風早，中路乏資貸。", "歸尋舊簑笠，獨釣吾邦瀨。"]'),
('814f23b3-28df-45f8-926b-feb9cb93ec8f','續感興二十五首  其二三','方一夔','宋','宋诗','song-poetry','','[]','自從判清濁，人文肇古羲。',84,'全唐诗/poet.song.235000.json','["自從判清濁，人文肇古羲。", "中間更百聖，扶豎顛與衰。", "孔孟死不作，千載無明師。", "嗟此仁義路，舉世爭背馳。", "無人障橫潰，一朝墜民彜。", "微言雖尚在，駸駸化侏離。", "斯文亙萬古，悠悠竟何之。"]'),
('0a190137-b5b7-4fd9-ba53-36f9a20bdf73','續感興二十五首  其二四','方一夔','宋','宋诗','song-poetry','','[]','昔時累科舉，讀書患不足。',96,'全唐诗/poet.song.235000.json','["昔時累科舉，讀書患不足。", "天今予我暇，有書真不讀。", "煌煌百聖心，清徹寒泉玉。", "遺澤存讀書，浸作生民福。", "靜觀靈臺中，萬象森在目。", "天寒境自明，欲淺機自觸。", "斯文化異端，駸駸即深谷。", "晞顔以自勵，吾欲求之復。"]'),
('bac3d8c8-4a31-4815-988a-ad20ef9c1476','續感興二十五首  其二五','方一夔','宋','宋诗','song-poetry','','[]','驚禽營顆粒，飛飛集邱隅。',96,'全唐诗/poet.song.235000.json','["驚禽營顆粒，飛飛集邱隅。", "遊子困行役，十年落江湖。", "煌煌秦與洛，運轉天下樞。", "啟明曜東漢，萬足爭奔趨。", "豈無爪距力，逐利如孫吳。", "得失昧前料，青雲間泥塗。", "天命有厚薄，定分不可踰。", "歸來北山下，俛仰收桑榆。"]'),
('fd8678e8-050a-415a-a837-dc16c46ebea9','過深浦羅給事隠舊居','方一夔','宋','宋诗','song-poetry','','[]','給事三父子，著籍古池陽。',192,'全唐诗/poet.song.235000.json','["給事三父子，著籍古池陽。", "販夫偶奇貨，末暮來錢塘。", "維時漢運衰，紫宸厭天狼。", "長鯨沸河洛，幅裂萬里疆。", "惟子曉大義，白筆摇風霜。", "願提十萬旅，巢穴傾朱梁。", "青雲不假翼，無路凌高翔。", "其事竟無成，青史垂芬芳。", "中原轉莽莽，一垤爭侯王。", "登高抉浮雲，極目慘八荒。", "遐想同心人，過君橋梓鄉。", "徘徊扣牧子，遺跡悲荒凉。", "區區夏蟲知，知我於詩長。", "豈知用心處，流落不忘唐。", "我欲傳高士，置君後柴桑。", "含情苦摇蕩，佇立蒼洲旁。"]'),
('89887b42-028b-4d43-901c-8ecc25e5a0b6','次韻徐古泉雪岡見寄','方一夔','宋','宋诗','song-poetry','','[]','掬泉陟雲亭，撼桐款石室。',192,'全唐诗/poet.song.235000.json','["掬泉陟雲亭，撼桐款石室。", "桐以藥清羸，泉以洗愴惻。", "惟昔有二君，靳與世紛出。", "我來泛滄溟，幽巖傍欹側。", "不如峴山去，行盡風沙磧。", "交君父子間，風儀宛如昔。", "引坐讀書巢，呼酒軟我膝。", "吟髭怒氣張，笑眼寒光溢。", "萊編如正色，澹然離薌澤。", "別去不空手，懷袖粲金碧。", "笑我頑魯胸，孔竅暗如漆。", "順塗詠其事，搔癢發故疾。", "閉門課學子，風雨隔十日。", "蒼蒼喬木春，杳杳碧雲夕。", "相思托空言，各倚天一壁。", "終携赤藤杖，相期訪仙釋。"]'),
('988848e5-cc40-431a-a0f0-d8835ea5cc63','續評史二首 向子平','方一夔','宋','宋诗','song-poetry','','[]','貴者不如賤，桑麻鄙簪纓。',96,'全唐诗/poet.song.235000.json','["貴者不如賤，桑麻鄙簪纓。", "富者不如貧，布荆勝珠瓊。", "子平悟損益，持論悍且精。", "併敵就一向，力與世俗爭。", "所以昏嫁畢，洗然外浮名。", "投跡崖巘中，便足了一身。", "頹波不可挽，滔滔自東傾。", "惟有吾由我，去留聽從卿。"]'),
('5853b6e0-c980-4cf2-89fd-33a4551ccc9b','續評史二首 嚴顔','方一夔','宋','宋诗','song-poetry','','[]','昔有嚴將軍，積氣壯窮峽。',96,'全唐诗/poet.song.235000.json','["昔有嚴將軍，積氣壯窮峽。", "維時漢道季，貙鯨潰河郟。", "我公弛長纓，不閉蛇虎柙。", "爾軍從何來，兩强力相壓。", "天未厭亂離，龍去留空匣。", "區區報主情，盟血不受歃。", "笑談履刀鋸，性命輕一掐。", "吾但戴吾頭，卿自用卿法。"]'),
('2c4ccbe4-8e78-4fe2-a81d-cc1c0d32a88f','諸葛武侯','方一夔','宋','宋诗','song-poetry','','[]','我從古人中，不數管晏輩。',264,'全唐诗/poet.song.235000.json','["我從古人中，不數管晏輩。", "紛紛後春秋，僅有孔明在。", "伊人層壑冰，表裏絕疵纇。", "文章派莘巖，氣節凌梁岱。", "未把渭上麾，甘抱隆中耒。", "維時太清暗，芒炎亙彗孛。", "老瞞鬼蜮雄，闊步無留碍。", "區區蜂與蟻，應手鐵山碎。", "陸城胄天潢，窮乏卓錐塊。", "垂白氣不衰，逝肯一寸退。", "孔明托末契，一起鎮橫潰。", "煌煌復讎義，掀揭人心晦。", "風雲兩飛揚，眼底無强對。", "取分孫曹間，隻手探懷內。", "自堪托六尺，不啻才十倍。", "暮年五丈師，此舉不俟再。", "中堅擁貔貅，勢若决瀦匯。", "半道失良圖，天理意茫昧。", "彼哉髠鉗兒，見雪空狂吠。", "是非付陳編，清泉奉芳酹。", "何時起九京，六合需一溉。", "朗詠出師篇，千載照肝肺。"]'),
('d5c04032-171c-43a5-8962-d8bae2d7cf65','出塞行五首  其一','方一夔','宋','宋诗','song-poetry','','[]','南方地卑濕，北客畏蒸暑。',84,'全唐诗/poet.song.235000.json','["南方地卑濕，北客畏蒸暑。", "晨行螫菵露，水宿射短矢。", "秦人發謫戍，見行如棄市。", "今古共一方，今者不獨死。", "穰穰作家業，鬼妾紛驅使。", "鴟夷卵翼蕃，小兒半高鼻。", "元精穿萬化，蕩蕩不可恃。"]'),
('1b019037-f836-4f08-a964-da8e428432e7','出塞行五首  其二','方一夔','宋','宋诗','song-poetry','','[]','出塞二千里，平沙白如霜。',96,'全唐诗/poet.song.235000.json','["出塞二千里，平沙白如霜。", "探兵失單于，傳是左賢王。", "梟鳴金錯竿，士氣慘不揚。", "中軍一再鼓，萬馬赴敵場。", "名酋不可得，殺傷略相當。", "縣鞍盡胡首，前驅橐駞羊。", "幕府閲五符，半死半裹瘡。", "天子不錄過，猶侯水中鄉。"]'),
('aa1e17a9-b36c-44f2-a717-420c4364006f','出塞行五首  其三','方一夔','宋','宋诗','song-poetry','','[]','我本輕黠兒，小少槿閭閈。',96,'全唐诗/poet.song.235000.json','["我本輕黠兒，小少槿閭閈。", "未知從軍苦，悠悠赴沙瀚。", "同行五千人，骸骨蓬麻亂。", "中有脫死者，人各鳥獸竄。", "間懷大將印，辛苦生還漢。", "包以襯甲綾，來上長楊殿。", "憐我不負恩，授印親書贊。", "一來贖前過，比再軍鋒冠。"]'),
('50aa9bb6-7dfd-452a-8257-8f4839f3660c','出塞行五首  其四','方一夔','宋','宋诗','song-poetry','','[]','主公再度遼，油幢坐中堅。',120,'全唐诗/poet.song.235000.json','["主公再度遼，油幢坐中堅。", "憐我鳴吠豎，出入後狨韉。", "一朝霍家敗，主公忝姻聯。", "富貴既相關，受禍其固然。", "我時護屬國，脫命來居延。", "蹉跎偶不死，彷彿三百年。", "此來復何幸，皓首朝中天。", "昔日霍家事，歷歷在眼前。", "偶行平陽里，細草空芊綿。", "與卿等輩耳，歲暮愁紅蔫。"]'),
('bbf4acbd-f272-4e21-85b3-3db26437ce10','出塞行五首  其五','方一夔','宋','宋诗','song-poetry','','[]','登高望西北，里數逾五千。',108,'全唐诗/poet.song.235000.json','["登高望西北，里數逾五千。", "誰言龍庭遠，轉盼跨幽燕。", "喊聲振瓦石，鬭志前旌旃。", "足蹈猛虎尾，手攬饑蛟涎。", "富貴自有命，此身若浮烟。", "古來功名士，發跡昉窮邊。", "不見小盤龍，兜鍪換貂蟬。", "豈爲章句儒，白首埋陳編。", "見嗤灰與土，黯死吹不然。"]'),
('9ce30ae9-2d8c-4e12-8ede-6b31554c8c80','雨','方一夔','宋','宋诗','song-poetry','','[]','吾聞陰陽書，夏忌甲子雨。',96,'全唐诗/poet.song.235000.json','["吾聞陰陽書，夏忌甲子雨。", "蠶死麥復苦，果諧老農語。", "人生無賢愚，擾擾同一宇。", "衣食固其端，安可過取數。", "哀哉元相國，胡椒滿倉庾。", "區區口體計，所費能幾許。", "晴曦禦朝寒，野菜供晚茹。", "君看此輩人，政自有佳處。"]'),
('bc38540f-123e-4876-b531-ead1557bcd48','憶舍弟','方一夔','宋','宋诗','song-poetry','','[]','衰世門戶單，惟有子與我。',120,'全唐诗/poet.song.235000.json','["衰世門戶單，惟有子與我。", "手足共一身，右短固不可。", "投老得寡妻，誰謂此計左。", "鴟梟覆爾巢，骨肉翻成禍。", "知幾苦不早，漸理歸舟柁。", "縣官不可入，有理子亦頗。", "自憐羽翼低，尺書忽遠墮。", "兩年食奔走，老蠶自纏裹。", "相救在急難，寧能久安坐。", "玄精有可倚，矧此乃么麽。"]'),
('895e39f1-b031-492d-b7d7-6a399e868801','贈鶴峰楊提幹森','方一夔','宋','宋诗','song-poetry','','[]','功名真定兔，赤手誰摶控。',168,'全唐诗/poet.song.235000.json','["功名真定兔，赤手誰摶控。", "十載武陵春，一餉揚州夢。", "時窮非我獨，萬事付破甕。", "猶有夙昔心，耿耿滿空洞。", "豪氣輕元龍，雄卞眇子貢。", "夢池句逾勁，賭墅機屢中。", "我來客東安，兩載補缺空。", "青山浩獨媚，飛雲倦孤送。", "翩翩老令威，霜翮頗驚衆。", "憐我一客鳥，鳴和閙晴哢。", "妙哉屠龍手，老去餘此弄。", "三年逝相從，不爲千金痛。", "浮跡寄閒適，片語折喧鬨。", "歸鞭定何時，矯首躡飛鞚。"]'),
('a1d803d1-d45e-4ddd-a0ba-89ccdfa1a20e','再疊前韻別鶴峰','方一夔','宋','宋诗','song-poetry','','[]','仙鶴來富春，造次欲手控。',168,'全唐诗/poet.song.235000.json','["仙鶴來富春，造次欲手控。", "偶然留一吷，喚醒千年夢。", "興來屢相過，小醉側春甕。", "笑談驚座人，輸瀉無底洞。", "森然栝柏材，曾伴揚州貢。", "班門無棄物，一睨果奇中。", "當今搆廊廟，况聞棟桴空。", "行看飛騰去，不待吹噓送。", "我亦懶散人，箋註鄙玄衆。", "向何寫懷抱，清苦等吟哢。", "詩來出其右，雲月困朝弄。", "風簷數四讀，愈我岑岑痛。", "復作摩天飛，不鬭雞鶩鬨。", "何時款君門，共把果下鞚。"]'),
('29e40175-c017-405a-9889-8d99ddcdb71c','猩猩','方一夔','宋','宋诗','song-poetry','','[]','醉酒水鉤吻，短屐木連瑣。',120,'全唐诗/poet.song.235000.json','["醉酒水鉤吻，短屐木連瑣。", "猩猩見且駡，爾欲寢處我。", "吾屬從此逝，相語此最叵。", "行行指忽動，念念頤亦朵。", "試來衣食之，危機忽交墮。", "糟醨自熏煮，繩索自纏裹。", "獵者躡其蹤，羣隊相隨坐。", "盛血亂殷紅，剪髮供髢鬌。", "明知好是餌，不悟貪爲禍。", "君看得意處，早轉潮頭柁。"]'),
('5fffbbe7-7ffe-43b9-8f1d-6f04977de39e','觀兼山黄公河海圖二首 河','方一夔','宋','宋诗','song-poetry','','[]','黄河從天落，北來受降城。',96,'全唐诗/poet.song.235000.json','["黄河從天落，北來受降城。", "劃至韓城縣，噴薄萬雷霆。", "何處雜泥滓，濁濁不復清。", "奔迫梁楚間，赤子如浮萍。", "近來到淮泗，烟波鼓長鯨。", "無人起隄障，何時返滄溟。", "惜哉神禹疏，高下昧地形。", "胡中倘可注，曷不施經營。"]'),
('9d40035c-4417-4aed-a343-4f7971870f6e','觀兼山黄公河海圖二首 海','方一夔','宋','宋诗','song-poetry','','[]','逝川走東海，日夜無休歇。',120,'全唐诗/poet.song.235000.json','["逝川走東海，日夜無休歇。", "咄此盤中渦，不長亦不竭。", "日月走中天，於焉雙出沒。", "駭浪掀扶胥，高於朔山雪。", "蠵蜃吐樓臺，蛟鼉護窟穴。", "海若不徒夸，馮夷甘受屈。", "吾聞三神山，恍恍銀宮闕。", "便隨長風去，發軔首溟渤。", "倘逢方平生，海底探明月。", "坐待清淺時，歸來未華髮。"]'),
('e16e177f-844a-43cd-adb6-0f1b74fb0e1a','將歸戲作此以別諸友','方一夔','宋','宋诗','song-poetry','','[]','新都玻璃江，下會東陽派。',240,'全唐诗/poet.song.235000.json','["新都玻璃江，下會東陽派。", "南圖俟扶摇，東首掉澎湃。", "千峰白雲粘，百道清泉灑。", "仳室舊樵貧，釣瀨老漁怪。", "桐君古仙居，稚川昔高邁。", "都忘語嘿殊，未覺高下隘。", "棲身傍冷門，吐口洗殘債。", "針石遠相粘，鹽卵危不壞。", "露翰倦孤飛，金波炯三桂。", "驚心歲月遒，過眼風雨快。", "感此桑扈鳴，春蠶續菅蒯。", "悠然耕田歌，早秧補葵芥。", "豈無田園念，未脫塵氛械。", "去來久無書，情愫不比畫。", "自慙榱桷材，曾螫蟲虺蠆。", "難將西山景，少補東隅敗。", "妻子累寒餓，文字欺聾聵。", "未酬醉鄉封，暫倒仙源界。", "蕭散縱孤騫，遊戲留一慨。", "他日對牀情，爲君作佳話。"]'),
('bd76bea9-829a-4078-8ba0-9299ffd8e5fb','藥圃五詠 杞菊','方一夔','宋','宋诗','song-poetry','','[]','藥中有杞菊，甘食比蔬菜。',96,'全唐诗/poet.song.235000.json','["藥中有杞菊，甘食比蔬菜。", "維昔陸與蘇，賦詠窮梗概。", "搜尋入吾圃，孤根擢荒穢。", "未能竟俗好，堇堇生意在。", "辛荑滿袖衽，枝葉不一采。", "少需摘絳實，疊疊貫珠琲。", "歲晚脫皮毛，凉葉蘇渴肺。", "靈厖守我宅，無復逐夜吠。"]'),
('8ce8bbad-bcb4-4060-8828-b4ed93d52742','藥圃五詠 甘菊','方一夔','宋','宋诗','song-poetry','','[]','楚客賦夕餐，經傳不著名。',96,'全唐诗/poet.song.235000.json','["楚客賦夕餐，經傳不著名。", "野菊或殺人，神農著翳經。", "此品甘且辛，叢生數千莖。", "分種不封囊，移根或盆盛。", "噉茶摘其葉，觴酒啜其英。", "風霜振枯槁，氣味老更成。", "平生攻苦淡，矜此歲晚情。", "不獨醒頭目，吾其寄餘齡。"]'),
('20a9062b-2a0d-4a37-90dc-f13eb0924c75','藥圃五詠 白朮','方一夔','宋','宋诗','song-poetry','','[]','白朮號山薑，以西北爲上。',96,'全唐诗/poet.song.235000.json','["白朮號山薑，以西北爲上。", "近來出古潛，何必論地望。", "老鴉銜子去，往往生絕嶂。", "歲久根株成，細大極殊狀。", "洗削事煎烹，補冷逐虛漲。", "彼哉不好事，蜜浸溢瓶盎。", "游媚富貴人，遠作千里餉。", "平生不爲口，我欲禦烟瘴。"]'),
('3fe6a5a2-d563-4863-a956-ede01dfeac84','藥圃五詠 川芎','方一夔','宋','宋诗','song-poetry','','[]','芎苗高一丈，細花如申椒。',96,'全唐诗/poet.song.235000.json','["芎苗高一丈，細花如申椒。", "不獨服芎根，衣佩或采苗。", "清芬襲肌骨，歲久亦不消。", "所以湘浦客，潔修著高標。", "我老苦多病，風寒首頻摇。", "願移一百本，溉根豁煩囂。", "雖無下女遺，乾葉插盈腰。", "逃泥貰旦暮，不學楚人謠。"]'),
('7ebe7e48-f056-4054-b6b0-d8aba90b91f1','藥圃五詠 茯苓','方一夔','宋','宋诗','song-poetry','','[]','老松踰百圍，名爲棟梁材。',96,'全唐诗/poet.song.235000.json','["老松踰百圍，名爲棟梁材。", "孤根雖故在，不復萌條枚。", "生意無處泄，浩浩還根荄。", "結爲千歲苓，膚色狀瓊瑰。", "洗曝不遺力，藥裹手自開。", "羊棗出河北，胡麻來天台。", "蒸以白砂蜜，盛以紅瓷杯。", "一朝服食盡，玉色還嬰孩。"]'),
('56e9d9d0-cd86-4668-9b7f-8e9a149492a8','宿前灣','方一夔','宋','宋诗','song-poetry','','[]','夕行前溪灣，翁嫗招我宿。',48,'全唐诗/poet.song.235000.json','["夕行前溪灣，翁嫗招我宿。", "入門燈火閙，偶此寄一足。", "客囊喜清浄，我倦睡頗熟。", "回首失浮蹤，終朝露如沐。"]'),
('7bb8e44c-fed0-4c1c-89a4-4e85fcaf0e44','上胡主簿愿','方一夔','宋','宋诗','song-poetry','','[]','尹公起宣城，謂是金閨彥。',168,'全唐诗/poet.song.235000.json','["尹公起宣城，謂是金閨彥。", "失脚簿領叢，斜飛集州縣。", "南陵枌榆地，妙年試雄剸。", "還將舊棠陰，來作清溪掾。", "近來多政學，誤製好東絹。", "我公有淵源，家學富經傳。", "四明炯清水，玉映崑山片。", "以茲撫凋瘵，精神皎如練。", "囷倉出毫末，德化速郵傳。", "到官未百日，惻惻庭闈戀。", "花外想安車，戲舞斑衣緣。", "推此壽斯民，童髦劇歡忭。", "我亦囿陶鈞，有道恥貧賤。", "洗眼看政成，携上金鑾殿。"]'),
('47e33d9f-c6a4-4c77-a065-5ab12cf980a1','問稼隠疾','方一夔','宋','宋诗','song-poetry','','[]','日子來訪我，話舊樂復樂。',168,'全唐诗/poet.song.235000.json','["日子來訪我，話舊樂復樂。", "中年情義深，一別輒作惡。", "子我皆客居，浮萍嘆流落。", "傷心縮地術，倒指賞月約。", "雞黍喜有期，書久懶不作。", "是時困著愚，處處熬膏鑊。", "而子金石軀，坐受貧鬼縛。", "傳聞數日來，卧病清風閣。", "況子賢主人，苓朮富裝橐。", "子亦屢折肱，忍不急呼藥。", "大患緣有身，此理直糟粕。", "要令文殊師，欲扣維摩諾。", "人生餘幾許，何事紛六鑿。", "殷懃今夜月，爲我照寂寞。"]'),
('dc87b32e-4a71-4748-8fd2-fb3fdefe6da2','寄友直借古書','方一夔','宋','宋诗','song-poetry','','[]','五日學作詩，十日學書紙。',96,'全唐诗/poet.song.235000.json','["五日學作詩，十日學書紙。", "書成自稱好，對客發微泚。", "爾來草書人，作態工側媚。", "譬如老孫娘，不病要兒齒。", "我空詩未工，苦瘦如我字。", "有詩使人寫，適興聊爾爾。", "宿緣喜多學，未用進於技。", "試問宜休民，何如覓青李。"]'),
('a520d5cf-8361-426c-8ec1-0ebab1e4488e','以白瓷爲酒器中作覆杯狀復有小石人出沒其中戲作以識其事','方一夔','宋','宋诗','song-poetry','','[]','彼美白瓷盞，規模來定州。',72,'全唐诗/poet.song.235000.json','["彼美白瓷盞，規模來定州。", "先生文字飲，獨酌無獻酬。", "咄哉石女兒，不作蛾眉羞。", "憐我老寂寞，赤手屢拍浮。", "子頑不乞火，我醉不驚鷗。", "無情兩相適，付與逍遥遊。"]'),
('727b923b-1d25-4a70-a32e-d217f93cba12','寄徐雪岡二首  其一','方一夔','宋','宋诗','song-poetry','','[]','我行其偶然，觸石五溪渡。',48,'全唐诗/poet.song.235000.json','["我行其偶然，觸石五溪渡。", "歸迷日已暗，有客相與晤。", "訢君相與問，酒罷首東路。", "坐恨此機失，欲去翻疑悞。"]'),
('02f44207-bcc2-4214-887b-a7bc50d22fca','寄徐雪岡二首  其二','方一夔','宋','宋诗','song-poetry','','[]','明庚共一天，出沒巧相避。',48,'全唐诗/poet.song.235000.json','["明庚共一天，出沒巧相避。", "與君別半載，轉脚不相值。", "君來過故人，我復捨此去。", "悵然起遐瞻，雲歸水東逝。"]'),
('217ba41a-9cf2-4552-9402-4a5b9552abed','秋夜有感','方一夔','宋','宋诗','song-poetry','','[]','西窗枕清溪，流水日夜響。',192,'全唐诗/poet.song.235000.json','["西窗枕清溪，流水日夜響。", "孤眠夜無寐，離夢苦摇蕩。", "自我辭家來，弦月屢下上。", "消息不曾真，百念墮滉瀁。", "憶昔心氣雄，躍躍盛年想。", "窺奇故牧儲，借重宗橐賞。", "山搜富金沙，澤淤耀琨簜。", "天池鶱孤飛，崑山紛獨往。", "下視夸奪子，蠓蠛鳴甕盎。", "區區凡楚爭，逐逐臧穀網。", "蹉跎改素摽，零落收宿莽。", "平生矜與夸，榮爲謝外奬。", "惟餘不盡心，耿耿猶疇曩。", "譬如老獵獫，聞呼齒足痒。", "清江三百里，西風颯菰蔣。", "明朝泝歸舟，鴉軋鳴兩槳。"]'),
('f24a874a-47f4-4c2b-983b-b56b6953d886','洪平齋有官舍見月三首與程楊二公又各次韻中秋日休諸友用韻爲戲奔逸絕塵之作未能擬其萬一也  其一','方一夔','宋','宋诗','song-poetry','','[]','月行十三度，晝夜風輪急。',120,'全唐诗/poet.song.235000.json','["月行十三度，晝夜風輪急。", "不知誰鞭策，行天出復沒。", "我欲訴清虛，雲路九萬級。", "梯飈空裊裊，月走那可及。", "願言住仙府，露重環佩濕。", "將從匏瓜摘，復結漢津汲。", "相期無情欲，不灑孤眠泣。", "落杵玄霜寒，出削玉斧澀。", "笑我南飛鳥，未辦一枝葺。", "歸歟定驚魄，烟霧飽清吸。"]'),
('c6164851-2081-4bd9-85cf-350c776ed680','洪平齋有官舍見月三首與程楊二公又各次韻中秋日休諸友用韻爲戲奔逸絕塵之作未能擬其萬一也  其二','方一夔','宋','宋诗','song-poetry','','[]','北極跳宜碣，南瞻盡閩甌。',120,'全唐诗/poet.song.235000.json','["北極跳宜碣，南瞻盡閩甌。", "眇觀此瀛海，浮空竟千秋。", "瑞光出冰輪，千丈開雲頭。", "月行無厚薄，不盡離人愁。", "夜半北斗高，闌干壓幽州。", "繁星見復沒，如滓浮新篘。", "庭虛步清影，梧桂聲颼飀。", "舉杯飲未釂，棹歌起漁舟。", "光景正清絕，賓去我獨留。", "飲技未必奏，頹然老伶優。"]'),
('533025e4-9481-4188-a340-29a90ccd1d8b','洪平齋有官舍見月三首與程楊二公又各次韻中秋日休諸友用韻爲戲奔逸絕塵之作未能擬其萬一也  其三','方一夔','宋','宋诗','song-poetry','','[]','憶昔戰秋闈，不復返隻輪。',120,'全唐诗/poet.song.235000.json','["憶昔戰秋闈，不復返隻輪。", "嗟此無用學，棘猴費精神。", "當時羞見月，月豈欲負人。", "我去月千里，月來轉情親。", "餘音唱窈窕，小詩鬭清新。", "團團桂樹影，金粟香不陳。", "便當結幽佩，凌空訪仙真。", "那知滿夜夜，此去空塵塵。", "翩然倚高寒，不數肇與晨。", "笑渠老章句，步驟準過秦。"]'),
('0e6ce912-016f-43e9-8b61-ec0496e93971','次韻稼隠告歸','方一夔','宋','宋诗','song-poetry','','[]','我觀大瀛海，天水二清廓。',192,'全唐诗/poet.song.235000.json','["我觀大瀛海，天水二清廓。", "誰麾海若來，樂鬭萬蛟鰐。", "風濤拍屯門，潰作無底壑。", "鬐鬛豎旂旛，牙角利椎鑿。", "血人不肯吐，安得留殘啄。", "茫茫泝雲槎，日夜失棲泊。", "歸塗三月糧，囊底餘圭勺。", "平生崒嵂氣，磨淬去隅角。", "案空螢已乾，匣閉龍不躍。", "故衣粘蜃氣，未洗瘴霧惡。", "爾來出白雲，奔走亂車鐸。", "有來證奇字，時扣草玄閣。", "高碁固饒人，欲學苦無脚。", "惟君桑梓英，遇合長落落。", "申旦首胥溪，險韻當離酌。", "勿爲松菊挽，來占秋堂幕。"]'),
('90eebb56-94b2-4ea6-94db-eff24de84906','贈心梅黄教諭','方一夔','宋','宋诗','song-poetry','','[]','太玄八十一，經世加一倍。',288,'全唐诗/poet.song.235000.json','["太玄八十一，經世加一倍。", "方圓起參兩，奇耦常相配。", "大哉天壤間，理大獨無對。", "而數行其中，往往不相背。", "冥探洞古今，幽討極覆載。", "吾求之瓦礫，數亦無不在。", "陰陽如推車，五氣如轉磑。", "雜然霧與珠，人物等唾欬。", "惡或盜跖壽，善或伯夷餒。", "人事非不明，所值互吉悔。", "長平四十萬，高下付一概。", "誰尸造化筆，一一難歸罪。", "君言吾有數，萬竅均大塊。", "試將握算推，不出範圍內。", "譬如埏埴人，萬器同一焙。", "前陶或堅牢，後陶或破碎。", "中間又不同，純駁千萬態。", "當時君與相，此年有真宰。", "黄蛇吞輿地，或者非茫昧。", "八宮卦縱橫，四柱數進退。", "以此尺棰義，合散無罣礙。", "昔君雄少年，盧雉喝好采。", "失脚落鶡冠，漕闈雙奏凱。", "爾來相乘除，得失賭一塞。"]'),
('90336215-9934-4f96-8c53-1028745d8401','次韻王蒙泉見寄併和鄙作','方一夔','宋','宋诗','song-poetry','','[]','君譜猗蘭操，曲度得碩師。',108,'全唐诗/poet.song.235000.json','["君譜猗蘭操，曲度得碩師。", "孤唱絕衆和，不與淫聲比。", "難逢拊石盛，終作蹈海衰。", "近傳貧作祟，疽疣等駢枝。", "西風幾揮淚，徙倚哀吾私。", "好音忽西墮，竹下哦君詩。", "翛然落月色，融融伴君疑。", "慇懃告司鼎，君側要子思。", "試歸扣小有，坐待天定時。"]'),
('bdfceba8-78f7-4b56-97f2-ba339d84a72a','送講書吳友直過吳門省兄','方一夔','宋','宋诗','song-poetry','','[]','寒城十月交，萬葉風蕭槭。',120,'全唐诗/poet.song.235000.json','["寒城十月交，萬葉風蕭槭。", "林幄變浮紅，水鏡湛虛碧。", "維時子吳子，驅車欲何適。", "千里想蓴羹，去作水鄉客。", "我非蓴羹客，海嶠有兄伯。", "譬如鵾與鵬，形影困乖隔。", "去鄉三十載，如浮家泛宅。", "相思不即見，歲歲累行役。", "感此歲寒情，高歌慰離析。", "看君乘長風，健翮搏水擊。"]'),
('208c2e22-35f0-4d8a-93ef-b4d654f0620b','徐靜樂以賤生有詩次韻爲謝','方一夔','宋','宋诗','song-poetry','','[]','偉哉盤古靈，萬仙集殊庭。',144,'全唐诗/poet.song.235000.json','["偉哉盤古靈，萬仙集殊庭。", "分布歲鎮熒，生化與尅刑。", "氣機浩不停，幾人得寧馨。", "開落隨日蓂，嗟哉此三星。", "光彩浮四溟，芽甲逢春霆。", "鋩刃發霜硎，蹉跎歎流萍。", "白雲歸杳冥，十年哀伶俜。", "賦芧由狙㹶，貧鬼急索絣。", "碧梧墮倦翎，館我修遺經。", "緬彼雙峽青，易學驅沸溟。", "出關東傅丁，渡海北返寧。", "共君萬頹齡，藥籠俱參苓。"]'),
('8e1f0db5-5f02-4457-a5ee-ad4fa6f494dc','壽雲岫以所畫壽星爲喻','方一夔','宋','宋诗','song-poetry','','[]','吳山多金堂，我來訪仙真。',168,'全唐诗/poet.song.235000.json','["吳山多金堂，我來訪仙真。", "神交若有契，邂逅見主人。", "浮雲白步障，老松青承塵。", "從以香嚴髫，環以瓊樹春。", "仙人坐盤石，杯勸三五巡。", "果苞武陵秀，木爇占城珍。", "幾見蓬海沙，不數上古椿。", "問從何處來，騎鹿來秋旻。", "謂是老人瑞，游戲葛水濱。", "容我野服見，間簉西閣賓。", "再拜上祝辭，慇懃寄千諄。", "一祝等龜鶴，再祝生麒麟。", "語罷却復進，罄折問養神。", "隨之上南極，放牧雲漢津。"]'),
('d3ae1da7-f88f-482b-9340-42ea0ce5c9c7','偕教諭傅草堂黄心梅及諸兄遊賢明寺','方一夔','宋','宋诗','song-poetry','','[]','朋儕久拘檢，偶此陟翠微。',144,'全唐诗/poet.song.235000.json','["朋儕久拘檢，偶此陟翠微。", "凌波渡野航，踏雲扣小扉。", "林霜變紋纈，抝月湛珠璣。", "古寺半莓苔，空堂盡蛜蝛。", "持鉢乞朝暮，殘僧猶未歸。", "清歌振冥杳，善響聲轉希。", "倦餘枕木榻，慮靜鷗不飛。", "我亦嘿不語，趺坐觀天機。", "幽芳艷巖菊，暝色漏晴暉。", "趁行戲拍肩，扶醉爭牽衣。", "鄧林蔭千里，飛栖偶相依。", "無人識幽趣，再鼓黄金徽。"]'),
('9ada8103-d36c-4ecd-abfb-2de706abfb2e','次韻沃梅泉見寄併見和鄙韻','方一夔','宋','宋诗','song-poetry','','[]','我來沸鳴蟟，坐閲寒蛩響。',192,'全唐诗/poet.song.235000.json','["我來沸鳴蟟，坐閲寒蛩響。", "有興寄滄洲，逝欲窮浩蕩。", "百年如彎弧，落處分寸上。", "前塗知幾許，乾坤一漭瀁。", "念子住沃洲，屢作扁舟想。", "杖屢縱勝游，文字醉清賞。", "奇音遇朗鑒，請我黄岡簜。", "世氛久昏暗，有縶不能往。", "交情浮雲淡，樂意陽春盎。", "老鶴鶱孤飛，況子開三網。", "離合固其常，豈是比土莽。", "我亦屬同流，始末藉虛奬。", "永懷芳蘭苕，不肯間誰曩。", "詩來森如束，快讀劇爬癢。", "吾詩非世好，一派分凡將。", "君如領此言，急浪盪飛槳。"]'),
('e758cb3a-fc60-4cb0-aa06-33ccc492fd8d','催雪','方一夔','宋','宋诗','song-poetry','','[]','滕六避熱屬，飛雪不到城。',96,'全唐诗/poet.song.235000.json','["滕六避熱屬，飛雪不到城。", "人意逐高下，造化亦世情。", "桂窗坐清曉，青山灑寒霙。", "巨松古鬚鬣，老梅玉璜珩。", "僅餘小培塿，岡隴縱復橫。", "其下數茅屋，榾柮烟火明。", "我興牛背上，披裘欲晨征。", "作詩逼僵龍，一夕紛瑶瓊。"]'),
('3318bcee-37e9-4e00-8658-cc20f98e3234','讀白樂天詩','方一夔','宋','宋诗','song-poetry','','[]','淵明避俗士，出語未必俗。',120,'全唐诗/poet.song.235000.json','["淵明避俗士，出語未必俗。", "衝口吐奇偉，往往寫心腹。", "外韜中勁剛，芒刃不堪觸。", "如渠不絃琴，非絲亦非木。", "樂天後此翁，逸駕追奔躅。", "未知溝中斷，孰與朱與綠。", "吾觀外國風，雅麗豈不足。", "自從受繩削，稗語棄不錄。", "嗟彼千載人，何但詩可續。", "誰能學柳下，不受嫠也宿。"]'),
('b63f287d-a1f7-478e-9b1e-277c415503e5','揚子雲','方一夔','宋','宋诗','song-poetry','','[]','兩都秦與洛，派自赤帝精。',96,'全唐诗/poet.song.235000.json','["兩都秦與洛，派自赤帝精。", "譬如同根木，南枯北猶榮。", "哀哉千里草，四百終火行。", "窮新何爲者，欺孤易天明。", "中間十五載，無汝元城名。", "誰尸春秋筆，恕彼投閣生。", "當時有凡例，黨中獨垂情。", "區區考亭叟，再主斯文盟。"]'),
('812be90f-f9c1-4600-bed7-045276aa9ff9','代壽新城劉尹迪','方一夔','宋','宋诗','song-poetry','','[]','峨峨嵩少精，皎皎河洛秀。',240,'全唐诗/poet.song.235000.json','["峨峨嵩少精，皎皎河洛秀。", "東都誰經始，多士傳自舊。", "驊騮冠冀北，盡在伯樂廐。", "於今雖應姓，况我隆準胄。", "金閨集羣彥，合伴鴛鷺簉。", "隨風落東南，州縣倦奔走。", "王謝舊江山，屏幛列千岫。", "公來長蓮幕，同列得領袖。", "慇懃山陰叟，多謝厖不嗾。", "三年賀政成，囊封飛剡奏。", "胡爲靳軒騰，未能脫墨綬。", "居然寄百里，芒炎應列宿。", "東安杭屬邑，民俗朴且陋。", "下車日無事，餘刃游膚腠。", "朝廷重民社，政自不輕授。", "沈沙珠吐光，閉谷蘭騰臭。", "天高元北極，錫馬接清晝。", "森森琅玕姿，錯落羣玉囿。", "生賢造物意，積善神明佑。", "百壺登公堂，祝公南山壽。"]'),
('701e013c-337c-49f4-a2e3-5d907df912bb','擬上徐容齋','方一夔','宋','宋诗','song-poetry','','[]','我憶昔孺子，獨以高士稱。',120,'全唐诗/poet.song.235000.json','["我憶昔孺子，獨以高士稱。", "當時漢道季，諸賢盡奔騰。", "高士卧不起，玉壺湛清冰。", "至今拜畫像，遺芳暨玄曾。", "先生奮東魯，鳬山立霜鷹。", "行臺累分府，螫𧍗驅蚊蠅。", "青溪古巖邑，膏油沸如蒸。", "猾吏溺死灰，饑窮坐相仍。", "此來獨何晚，三載欽風稜。", "爲回浙江水，六合俱清澄。"]'),
('0b10e1f6-2df5-4a63-81c7-5b2959a0d051','大水寄洪復翁','方一夔','宋','宋诗','song-poetry','','[]','昨夜龍宮留惡客，使者借車收二麥。',176,'全唐诗/poet.song.235000.json','["昨夜龍宮留惡客，使者借車收二麥。", "溪澗洪流十丈高，不辨東阡與西陌。", "高田忽變黄鵠陂，下者匯作魚龍宅。", "新陳接食已觖望，夏不早耕後何獲。", "似聞山縣未休戍，旁郡豪酋遺俘馘。", "携孥扶老避人禍，漂麥漲田遭鬼責。", "不知造化誰主張，罪欲誰歸問河伯。", "生平舌耕真左計，邇來硯破筆毛磔。", "中宵耿耿坐長歎，滿眼兵荒遭此厄。", "先生少抱調燮才，蒼生不忍饑寒迫。", "潛深請磨楯鼻墨，試草千言救荒策。"]'),
('e0810537-138f-457d-8205-1414531ced23','宋月山以陶金戶遁山中值雪有詩次韻訪之','方一夔','宋','宋诗','song-poetry','','[]','金沙潭頭石贔屭，凍蟻紛紛半僵死。',144,'全唐诗/poet.song.235000.json','["金沙潭頭石贔屭，凍蟻紛紛半僵死。", "淘江漉海攖龍鱗，領使省金蹲虎兕。", "欲將江浙飽虛牝，遮蓋誰施千丈被。", "先生誤墮世網中，死灰更溺無遺燬。", "携家北走入深山，雪中高卧那能起。", "世間得喪何足道，坎止流行一彈指。", "忍凍孤吟寒士歌，力將冰蘗戰紈綺。", "君窮無比我更窮，濕沫難擊三千里。", "明朝裹飯約共話，炯炯方瞳巖壑裏。"]'),
('490136c1-360b-4435-9a0c-76ef216b2dae','六月食寒梅','方一夔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六月火雲聳奇觀，讀書舌爛喉吻乾。',131,'全唐诗/poet.song.235000.json','["六月火雲聳奇觀，讀書舌爛喉吻乾。", "西湖水仙珠徑寸，使來遺我數百丸。", "清冷冰齒嚼不碎，玉池灧灧生微瀾。", "問仙何處得此物，孤根漏暖來孤山。", "霜嚴雪虐石犖确，美人忽破冰玉顔。", "紛紛青黄暗烟雨，我獨炎暑餘酸寒。", "異材晚成要有待，居然升置鼎鼐間。", "君不見周家老將太公望，八十封侯起釣磻。"]'),
('451df6e1-3481-407c-ba1b-695bf9cd4b8d','立冬前後大雷電震者數日','方一夔','宋','宋诗','song-poetry','','[]','雲如車駮低壓城，紅光閃電枉矢行。',96,'全唐诗/poet.song.235000.json','["雲如車駮低壓城，紅光閃電枉矢行。", "老龍偷出牛蹄泓，霹靂數聲驚頑冥。", "雨下如注翻四溟，黑風吹落魚鮪腥。", "蚯蚓奮角蛇怒鱗，穴居林處無潛形。", "小目飛箋奏天庭，速收阿香加誅刑。", "夜闌景霽百怪停，炯炯北極環衆星。"]'),
('110bd44f-f11d-4490-9194-2384a4ee6234','巖峰寄洪復翁','方一夔','宋','宋诗','song-poetry','','[]','巖峯孤尖來何雄，此地金紫山爲宗。',272,'全唐诗/poet.song.235000.json','["巖峯孤尖來何雄，此地金紫山爲宗。", "西行百里無去處，突起峭壁高衡嵩。", "一支側走截水口，鱗甲閃閃卧玉龍。", "龍來苦渴噀澗水，光芒錯出千丈虹。", "試緣石嶝步巉絕，圭笏琬琰來會同。", "天風回聲過絕頂，波濤洶洶生寒松。", "銀壪玉澗斲冰雪，飛雪六月聲琤琮。", "孤撐碧落望北極，世間無此奇絕峯。", "其下仙人昔蛻骨，玉棺往往留遺蹤。", "昂頭欲語忽飛去，時有歸鶴來遼東。", "住持山人子洪子，枝葉遠出崖仙翁。", "妙年歷落出塵想，幽幽桂樹生芳叢。", "溪山佳勝屬彈壓，綺語異境爭天工。", "心期不與俗子偶，移文招我來山中。", "劇談抵掌振林谷，妙趣吻合比鐘鏞。", "丈夫舒卷自常事，要令邱壑藏心胸。", "他年蓄久極必泄，膚寸油雲雨太空。"]'),
('60644964-4172-41c2-a5d8-5831d56cd971','桐關大石','方一夔','宋','宋诗','song-poetry','','[]','蓋天蒼蒼非虛空，高懸萬象驚愚蒙。',128,'全唐诗/poet.song.235000.json','["蓋天蒼蒼非虛空，高懸萬象驚愚蒙。", "仙人朝罷玉帝側，戲拋黄土留遺蹤。", "何年墮此作砥柱，千古屹立洪濤中。", "巨魚出沒深不測，罅縫草長蒲花茸。", "淙淙細浪夜舂擊，水石鞺鞳鏗金鐘。", "我來載酒坐其上，扁舟南下編青篷。", "飲酣恍恍欲飛去，如踞猛虎騎遊龍。", "夜深酒醒山月落，一曲短笛橫秋風。"]'),
('b60c2b41-a7bf-4d50-a263-5b6c48782963','赤山嶺','方一夔','宋','宋诗','song-poetry','','[]','赤山嶺罅闊百尺，人言老龍破山出。',96,'全唐诗/poet.song.235000.json','["赤山嶺罅闊百尺，人言老龍破山出。", "天生異物出有時，不知何年留此跡。", "想龍久蟄當飛騰，怒迸脩鱗血淋瀝。", "至今頑石尚嵌巖，朝暾光映半山赤。", "龍去川原秋雨足，龍歸洞穴寒雲濕。", "我家山下龍爲友，欲挽銀河清八極。"]'),
('27b22c78-21f2-4336-afc5-97a679d3ecc1','粵王墓','方一夔','宋','宋诗','song-poetry','','[]','何年遺此粵王墓，陳迹留傳自先故。',128,'全唐诗/poet.song.235000.json','["何年遺此粵王墓，陳迹留傳自先故。", "纍纍三冢壓荒山，古木寒烟暗行路。", "憶昔祖父伯姑蘇，北連齊楚陵强都。", "自從鴟夷載西子，子孫運盡償前逋。", "三軍散後東西走，窮無寄跡埋丘首。", "安全發掘不可知，故號至今喧衆口。", "丘山華屋何足言，死名死利分汙尊。", "英雄自古無葬處，誰與遺臭留乾坤。"]'),
('50e07929-3085-492c-b528-487ff06b9639','李伯時明皇按樂圖','方一夔','宋','宋诗','song-poetry','','[]','開元天子方承平，年年十月遊華清。',192,'全唐诗/poet.song.235000.json','["開元天子方承平，年年十月遊華清。", "游龍爛簇五家錦，玉奴姊妹俱傾城。", "太常舊譜看不足，鬭雞舞馬渾粗俗。", "霓裳一闋天上來，三郎自按新翻曲。", "賀老琵琶先定場，都曇擊鼓齊高張。", "繡帽金童小垂手，堂上合奏甘伊凉。", "胡兒大眼何曾見，來簉膝前雙舞旋。", "天顔有喜分塞酥，宮花銜出昭陽殿。", "龍眠老手落貴家，忽入老眼憑歎嗟。", "尚嫌却後欠二筆，不寫漁陽鳴鼓撾。", "人生歡樂如風影，自古極衰根極盛。", "後來倘有曲江公，此圖合作千秋鏡。"]'),
('7c061257-8de1-4db7-b6e8-845b76d2c0cc','明妃曲','方一夔','宋','宋诗','song-poetry','','[]','明妃去時載橐駞，金環珠絡紅錦靴。',192,'全唐诗/poet.song.235000.json','["明妃去時載橐駞，金環珠絡紅錦靴。", "燕支山北萬蹄馬，半夜劍槊鏘橫磨。", "老胡鬚鼻極殊狀，黄羊乳酪氈裘帳。", "此生賦分逐飛走，一回坐起一惆悵。", "當初自恃顔如花，不嫁比鄰來天家。", "掖庭咫尺隔萬里，十年不復逢宮車。", "畫工不信能相誤，一朝流落天涯去。", "漢使年年去復來，長安不見低烟霧。", "寒沙擊面雁飛秋，手抱琵琶淚暗流。", "上絃冷冷寫妾苦，下絃切切寫漢羞。", "妾身生死何須道，漢人嫁我結和好。", "曲終誰是知音人，斷魂去作墳頭草。"]'),
('a3d529ed-0ebf-4ef5-984f-bdca3af90243','太湖石獅子筆架','方一夔','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','憶昔金仙去後遺雙狻，化作雙玉南海邊。',130,'全唐诗/poet.song.235000.json','["憶昔金仙去後遺雙狻，化作雙玉南海邊。", "洞庭山鬼逐不得，夜吼雲根今幾年。", "先生曾作橘洲客，屢撼梧桐怖龍伯。", "携歸深山動光彩，黑貙縮爪羆藏迹。", "爛爛眼有百步威，安眠不動鎮書帷。", "自慙四座無長物，煩護老穎書中□。", "醉墨淋漓日千幅，毫端猶带湖光綠。", "憐渠駿猛助奇怪，他日相從校天祿。"]'),
('5f210b9e-5b0c-4054-a73e-6c321f882362','九里路','方一夔','宋','宋诗','song-poetry','','[]','去年九里路，烏攫人腸挂枯樹。',92,'全唐诗/poet.song.235000.json','["去年九里路，烏攫人腸挂枯樹。", "今年九里溪，沙頭白骨高復低。", "人生變滅如泥土，死後猶傳姜萬戶。", "翠眉粉頰誰家兒，夜赴軍前效首虜。", "將軍多愛恩意疎，分將吳口充包苴。", "慇懃道與送行使，前日朝官多有書。"]'),
('691c75c5-87d4-4339-943d-88bcd5fe8f9a','七夕織女歌','方一夔','宋','宋诗','song-poetry','','[]','牛郎咫尺隔天河，鵲橋散後離恨多。',128,'全唐诗/poet.song.235000.json','["牛郎咫尺隔天河，鵲橋散後離恨多。", "今夕不知復何夕，遥看新月橫金波。", "拋梭擲紝愁零亂，彩鳳飄飄度霄漢。", "重來指點昔游處，香奩寶篋蟲絲滿。", "一年一度承君顔，相別相逢比夢間。", "舊愁未了新愁起，已見紅日銜青山。", "當初謾道仙家別，日遠月長不見接。", "不似人間夫與妻，百歲光陰長會合。"]'),
('67438268-1277-4bfe-9025-b388f871367a','文書再報六月朔日食','方一夔','宋','宋诗','song-poetry','','[]','憶昔雨洗冬甲子，春來飛雪徧千里。',160,'全唐诗/poet.song.235000.json','["憶昔雨洗冬甲子，春來飛雪徧千里。", "老農雪讖古相傳，一番春雪一番水。", "今年麥熟雲成堆，并刀收斂疑寇來。", "自從入梅不見雨，田間熱氣飛黄埃。", "清臺奏下郵傳急，月蝕九分日蝕七。", "昨宵搥鼓閙如雷，素娥憑怒面漆黑。", "太陽室家怒相囓，東西不肯還宮闕。", "天公不肯目偏盲，又傳日蝕林鍾月。", "一箋夜拜東皇公，休作怪變驚兒童。", "願分陰陽作平等，五日一雨十日風。"]'),
('d6e4fedf-2cf0-4417-8eb8-f12830e993d3','續憎蒼蠅','方一夔','宋','宋诗','song-poetry','','[]','炎官煽毒日色頳，四海鼎沸遭焚蒸。',160,'全唐诗/poet.song.235000.json','["炎官煽毒日色頳，四海鼎沸遭焚蒸。", "吳牛耕罷汗且喘，暫休樹影眠溝堘。", "不知蒼蠅名品夥，乘時附勢相欺陵。", "其間一種號赤目，巧窺猛攫如饑鷹。", "鑽眸噆鼻不可奈，以首溷水澆清澄。", "自期擺脫有此計，須臾撲緣如牽繩。", "牧兒旁坐少肋力，摑以指掌麾以肱。", "更憑草帚時一掃，墜地死者堆斗升。", "乾坤蕩蕩産萬類，涵淹惡物吁可憎。", "閒從林下看水牯，作詩爲續憎蒼蠅。"]'),
('285e8ada-010c-4d8a-b3f5-67395d32a75b','寄題沃祥卿梅泉二大字蓋何潛齋筆也','方一夔','宋','宋诗','song-poetry','','[]','錢塘數首梅花聯，羅浮三疊梅花篇。',196,'全唐诗/poet.song.235000.json','["錢塘數首梅花聯，羅浮三疊梅花篇。", "世間妙語久絕響，誰能高步凌飛仙。", "窮冬天氣寒刻栗，草木槁死冰頑堅。", "孤根漏暖得春早，水流石竇聲濺濺。", "美人拭面照古鏡，沈吟不去愁嬋娟。", "下有山人學冷淡，入夜忍凍僵護肩。", "臨流赤脚踏白石，手挼紅藟餐雲烟。", "長哦新句詩清苦，口吻噤噤棲饑鳶。", "近聞梅花詩祖出水部，久遣詩孫參洞天。", "許分一派伴岑寂，毫端紫氣衝魁躔。", "我來嗽香嚥清冷，欲說妙偈夢未圓。", "澹然人我了無語，但見花梢明月墮寒泉。"]'),
('6c3ec385-9fca-4ac6-b7bf-36c7c68614dd','人有叢菊見遺而花半分黄白者','方一夔','宋','宋诗','song-poetry','','[]','有來遺我異色菊，一叢深淺分白黄。',136,'全唐诗/poet.song.235000.json','["有來遺我異色菊，一叢深淺分白黄。", "變窯燒成古罍洗，怪石錯出真琳琅。", "我疑造物有間氣，紛紛醜好都難量。", "不然司花出新巧，分枝接葉爲作半面粧。", "書生生活澹無味，笑指枯硯收禾桑。", "偶逢好事慰寂寞，日與相對揮清觴。", "自憐今世少有趙昌徐熙水墨筆，誰寫諸相爭毫芒。", "惟有詩人具真畫，翛然心地超羲皇。"]'),
('5199da20-8024-47a7-b9d5-08ade3fa380d','次韻吳友直和潘樂閒見寄韻','方一夔','宋','宋诗','song-poetry','','[]','文章蟠窟蛟蛇黑，精神緊峭冰玉白。',192,'全唐诗/poet.song.235000.json','["文章蟠窟蛟蛇黑，精神緊峭冰玉白。", "置君承明天祿中，富貴不待相促迫。", "學參諸老居二四，氣凜羣兒壓千百。", "生平不主疽與環，況復侯封羨賁赫。", "蹉跎無便凌風雲，歸伴凡魚東海窄。", "袖餘閩越奇傑氣，掩藏光怪恣窺摘。", "如今老境謝紛華，斥去浮花收粟麥。", "我來兩見鳴春禽，低向藋間飛拍拍。", "有時乘興騁詩俊，稗說讕言都不擇。", "魚還非子子非我，肝膽相忘總無隔。", "苦無分遇食太倉，近犬驚人屢遭責。", "一身何必要贏餘，我爲鼠謀從下策。"]'),
('c2d15f27-04fd-4bf5-8045-b30234569035','用子聲韻謝吳友直惠蠟箋','方一夔','宋','宋诗','song-poetry','','[]','千年老穀無人知，萬杵椎冰身汗熱。',192,'全唐诗/poet.song.235000.json','["千年老穀無人知，萬杵椎冰身汗熱。", "木膚解剝白於綿，凍手龜皴腕將折。", "荆州魚網蘭亭絸，彼美不曾傳祕訣。", "獨留此木在人間，禿盡青山散妖血。", "邇來奇製蠟作紋，草木蟲魚生眼纈。", "只今吳越稱第一，秋浦浣花派滕薛。", "先生好古得此物，揮手行與時流別。", "紫薇花前草尺一，書成氣凜寒松雪。", "不然名山撰古史，蛟龍鬰屈蟠奩篋。", "有時浮戲寫詩章，颯颯落錐蠶食葉。", "比來分遣二十輩，西江遠借餘波浥。", "聊憑和詩報瓊瑶，袖手愧逢强對怯。"]'),
('12c079d6-431c-4548-9718-965d17fb02b9','表甥何雲嶠舍館而語游於其行贈之以詩','方一夔','宋','宋诗','song-poetry','','[]','書生事業窘一門，窮年獨處三家村。',196,'全唐诗/poet.song.235000.json','["書生事業窘一門，窮年獨處三家村。", "蟾蜍爬沙鞭不走，無力號叫排天閽。", "曩聞將軍狂可撼，往舍窠臼窺其藩。", "讕言稗說不暇擇，談笑抵當如優髠。", "諸公義財澀且薄，頗樂軟熟憎囂煩。", "今君窮餓坐百巧，安肯挾冊媒朝昏。", "試探囊中祕花術，勇决不待中宵奔。", "吾聞武侯暗得司馬法，平沙散布風雲屯。", "多時奇傑了不悟，後來知者靖與溫。", "子今持此說性命，禍福出口如瀾翻。", "文章不作杯水直，不如薄藝隨我兩脚跟。", "滔滔世駕不可挽，行矣與汝傾離尊。"]'),
('14c481cc-b84b-448e-a3be-7153db559943','和東坡惠州梅花三疊  其一','方一夔','宋','宋诗','song-poetry','','[]','子真換骨三家村，青帝東臯來醉魂。',128,'全唐诗/poet.song.235000.json','["子真換骨三家村，青帝東臯來醉魂。", "夜深更遣明月洗，瘴氛吹散南海昏。", "仙宮么鳳挽不住，自要寂寞留故園。", "便教凍餓死亦足，冷面不作雞肉溫。", "烟痕半空照寒水，露臉猶泫迎晨暾。", "游蜂底處得消息，不計春色關重門。", "先生對花韻清苦，短偈衮衮翻千言。", "花神嗔我太漏泄，罰以太白傾殘樽。"]'),
('0439e8aa-3662-4a92-8297-393ad706a55a','和東坡惠州梅花三疊  其二','方一夔','宋','宋诗','song-poetry','','[]','萬松嶺上三家村，林下美人現香魂。',128,'全唐诗/poet.song.235000.json','["萬松嶺上三家村，林下美人現香魂。", "淡粧素服謝琱飾，擺落玉鏡塵埃昏。", "散花衣祴粘不落，昨夜偶過祇樹園。", "樹下泠泠潄澗玉，亂流赤脚飛泉溫。", "噴成澗草萬片玉，陰崖未肯希春暾。", "自憐艷質媚幽獨，拄杖敲鏗誰過門。", "相期但有月知狀，不用椽筆書要言。", "花應一笑飲我語，隨風飛墜雙銀樽。"]'),
('e0e1d191-e6b2-4a66-b0e2-f7f204b3db90','和東坡惠州梅花三疊  其三','方一夔','宋','宋诗','song-poetry','','[]','白鶴峯頭荔子村，誰喚東坡半死魂。',128,'全唐诗/poet.song.235000.json','["白鶴峯頭荔子村，誰喚東坡半死魂。", "作詩惱花太愁絕，雲月黯黯天昏昏。", "欲教綺語洗蠻瘴，不使冠服棲邱園。", "海山淮水隔萬里，十年契闊陳寒溫。", "老仙不食烟火味，曉隨鴉餐暘谷暾。", "此花亦解慰流落，如在玉堂西掖門。", "自從三疊振絕響，澹然相對俱忘言。", "我來戲譜不調曲，時有問字爭芳樽。"]'),
('b2b1c718-918a-40c0-aeaa-3d142a752161','苦瘡歎','方一夔','宋','宋诗','song-poetry','','[]','西家真王化作灰，東家穉松雪霜摧。',128,'全唐诗/poet.song.235000.json','["西家真王化作灰，東家穉松雪霜摧。", "人生有命惟脆薄，逝水一去何時回。", "試看昨日繞牀戲，或騎青竹折早梅。", "須臾變滅不可恃，惟見松下雙土堆。", "嗟哉玄冥弄權柄，掀簸炎瘴飛氛埃。", "天公不肯憐赤子，坐使瘡痏愁嬰孩。", "斷魂零落向何處，溪頭望哭思歸來。", "誰能便作忘情者，作詩往助風泉哀。"]'),
('bf8bf906-c68a-4624-bf66-64ecdc5600dd','次韻王介山別齋職','方一夔','宋','宋诗','song-poetry','','[]','葛溪練練鋪瓊氈，仙人燒丹幾何年。',191,'全唐诗/poet.song.235000.json','["葛溪練練鋪瓊氈，仙人燒丹幾何年。", "庠老三年住仙窟，歸騎踟躕鞭不前。", "當今越雪竟誰是，危坐臯比紛不恥。", "區區升斗老英雄，得失何殊釣溫水。", "惟君挾策從東來，家傳瓢履師顔回。", "後來終竟祠石室，此去應難隠釣臺。", "青山笑我逢遲暮，怪奇文字無人覷。", "誰麾清夢落東安，疎頑尚費推擠去。", "悠悠雲水交情中，荆州篠簜慙中空。", "琤餘韻逐飛鞚，詩老箭鋒那可衝。", "男兒事業人人有，氣概相期向杯酒。", "他年擁節過子陵，莫道故交翻覆手。"]'),
('08e47b36-bdb3-44ce-8803-4fb7e5e31865','代雲岫送王介山','方一夔','宋','宋诗','song-poetry','','[]','功名零落如破氈，羲娥不住隨流年。',192,'全唐诗/poet.song.235000.json','["功名零落如破氈，羲娥不住隨流年。", "問君發跡縣博士，幾時得到龍旂前。", "我今老去覺今是，回首當年空自恥。", "妄心不起百事冷，已作古井無波水。", "看君富貴亹亹來，雲路何須取勢回。", "忽然結束行萬里，首冠步摇趨天臺。", "相思望望碧雲暮，少微光芒紛下覷。", "應憶秋江老故人，瑶音定寄雲鴻去。", "我時階砌蘭玉中，襹褷六翮摶秋空。", "與君追逐赤霄上，寶劍騰空不可衝。", "兩眼昏花惟我有，早梅樹下離亭酒。", "呼童草寫送行詩，不是當今無價手。"]'),
('ac7bbea9-3e30-441b-a8dc-755850d4cd1d','代履道送王介山','方一夔','宋','宋诗','song-poetry','','[]','寒廳零落分半氈，雪霜刻栗年復年。',192,'全唐诗/poet.song.235000.json','["寒廳零落分半氈，雪霜刻栗年復年。", "書生事業澹無味，頼有夫子坐我前。", "世間好惡紛非是，蠻觸相挺人不恥。", "嗟君嗜好與世殊，推波獨障百川水。", "君今何去昔何來，江南欲掉扁舟回。", "相思此去杳如夢，日斜獨上高高臺。", "富貴來時未爲暮，道旁愚婦從渠覷。", "我亦來乘下澤車，看君萬里翺翔去。", "雲萍聚散渺莽中，講席人驚冀北空。", "少陵時作湖山主，一面誰當孔道衝。", "相看一醉無何有，笑指春江作春酒。", "丈夫何事兒女態，明日長亭一揮手。"]'),
('5c360d9a-b57d-48cf-af27-3590fb0a1d88','次韻洪復翁辭沃氏招館','方一夔','宋','宋诗','song-poetry','','[]','可憐傾城無蹇修，睥睨欲媲王與侯，年華荏苒春復秋。',232,'全唐诗/poet.song.235000.json','["可憐傾城無蹇修，睥睨欲媲王與侯，年華荏苒春復秋。", "夜彈古詞韻三州，紛紛箏笆沸啁啾，忽爾雅操聲俱收。", "我亦少小獵九丘，掩鼻利達視若蕕，秣厲欲洗平生羞。", "羲娥鞭後逝莫留，誰麾衰暮出巖幽，丁丁斤斧愁林搜。", "苞裹破硯開荒疇，詩卷千束喘兩牛，隘視宇宙前無儔。", "頼有夫子紛應酬，冷然獨繭繅長抽，讕言不作詩帳囚。", "旁人指我作書郵，雙雙紫芒炯中洲，談笑不下孫叔優。", "交情雲水空悠悠，肯爲腐鼠瞥下韝。", "湖海何處無俊游，對面不識非我謀。", "醉呼梅花居上頭，高寒不落第二流。", "我亦倒囊出饑猴，雪中雙屨追清游。"]'),
('0b86cfc4-f98d-4f92-b48d-b2251c44b2dc','借王介山韻送子聲小學教諭','方一夔','宋','宋诗','song-poetry','','[]','小兒心孔暗不開，紛紛誰是驊騮材。',64,'全唐诗/poet.song.235000.json','["小兒心孔暗不開，紛紛誰是驊騮材。", "徐生善頌有名父，文斾新向儒宮來。", "雁行趨立誰家子，捧書驚看眉間喜。", "我亦歸謀二頃田，送老西河從此始。"]'),
('c9753e56-7574-448e-9cf8-c08255452b45','無愁潭','方一夔','宋','宋诗','song-poetry','','[]','酌我無愁酒，歌我無愁詩。',259,'全唐诗/poet.song.235000.json','["酌我無愁酒，歌我無愁詩。", "朅來無愁潭上弄明月，潄滌萬慮清肝脾。", "平生蓄積總開豁，便欲遺世超希夷。", "持盃試問此潭水，昔來何處今何之。", "覆船山高寒岌嶪，玉泉飛下東天池。", "分流一瀉數百里，直抵絕壑潴清漪。", "鏡平百丈洞無底，其下深黑蟠蛟螭。", "幽蘭薜芷亂洲渚，倒影寒浸枯松枝。", "千回萬折流到海，波濤噴薄孤城危。", "潮生水滿潮退涸，蓬萊清淺倏改移。", "此愁與水兩無盡，昔人已去今人悲。", "君不見莫愁山下春水長，畫船鼉鼓相追隨。", "淡烟芳草望不斷，石城荒廢留空陂。", "不如此潭只在山水窟，縱有奇勝無人知。", "何曾紅粉照清泚，但有欵乃漁翁詞。", "一聲歌斷暮山碧，秋風兩鬢寒颸颸。"]'),
('747e58f2-2356-4b52-9e1e-e00f8fbe41b7','大雪','方一夔','宋','宋诗','song-poetry','','[]','一日雪，空裏浮花生眼纈。',179,'全唐诗/poet.song.235000.json','["一日雪，空裏浮花生眼纈。", "二日雪，竹松委地枯楠折。", "三日雪，獸駭禽奔蹄跡滅。", "四日雪，翁嫗啼饑淚成血。", "天生萬物忍棄捐，似爲多情幻奇絕。", "由來恩怨不相關，無情有情總磨折。", "君不見堯時洪流浸十日，赤子喁喁化魚鼈。", "湯時亢旱烘七年，山河大地紅爐熱。", "當時賢聖救不得，坐待時來自休歇。", "蓋天垂地憂長人，浪教寒士頭先白。", "玉皇高居耳目遠，鬼神虎豹爭羅列。", "頊冥滕屏罪當誅，劈牋試與東風說。"]'),
('2abe6bca-e859-44d1-bc4d-e18358ecc2db','次邵卓翁韻奉寄族祖竹巖令孫','方一夔','宋','宋诗','song-poetry','','[]','君不見李唐秘府堆故紙，韓老作詩{言奉}校理。',166,'全唐诗/poet.song.235000.json','["君不見李唐秘府堆故紙，韓老作詩{言奉}校理。", "若此當時九歲童，苞裹寶函漸血指。", "吾宗魁橐百世傳，近騎箕尾凌蒼烟。", "再生雛鳳墮君砌，次第聲名期拍肩。", "願渠養氣休吟誦，六翮褵褷鳳質竦。", "椅桐傾枝真有待，羽儀留作清時用。", "我今老去不作文，閉精嘿坐學養神。", "蕭然衰白不復漆，猶喜兒輩奔秦軍。", "閒扣商謳詡人瑞，筆陣縱橫人不畏。", "歸看英物定何如，山西老將空羞愧。"]'),
('56bb9b1f-0b7c-4fbb-b7aa-d280c1eb8cf4','夜坐','方一夔','宋','宋诗','song-poetry','','[]','竹翠濃如滴，絺凉薄似空。',48,'全唐诗/poet.song.235000.json','["竹翠濃如滴，絺凉薄似空。", "遐觀山缺處，露坐月明中。", "計較圍碁勝，喧呼琢句工。", "畏途誰觸熱，衣袂漲塵紅。"]'),
('627e3231-2b09-468a-8b49-fe977c2cbe56','宿赤山嶺','方一夔','宋','宋诗','song-poetry','','[]','杖屨過山東，一重高一重。',48,'全唐诗/poet.song.235000.json','["杖屨過山東，一重高一重。", "雲烟呈晚色，雨露洗秋容。", "偃蹇石伏虎，連蜷木寓龍。", "夜深橫短笛，獨宿最高峯。"]'),
('bec64c06-4f5e-499d-b00f-784613ccbe84','雨雪交作','方一夔','宋','宋诗','song-poetry','','[]','雪晴那復雨，雨雪苦纏綿。',48,'全唐诗/poet.song.235000.json','["雪晴那復雨，雨雪苦纏綿。", "連月無行地，窮冬不見天。", "穴居貍舐掌，水宿鷺聯拳。", "更道深山裏，翁饑歇午烟。"]'),
('7834d8d1-aa38-4531-8166-109de24ffa05','吾生','方一夔','宋','宋诗','song-poetry','','[]','行年四十九，忽忽笑浮生。',48,'全唐诗/poet.song.235000.json','["行年四十九，忽忽笑浮生。", "客少真成懶，兒多半學耕。", "閒身窮縛急，壯志老圖成。", "自號知非子，悠然仕止情。"]'),
('ed54d883-107f-4f9e-b688-e5790637d4d4','春晚憶弟','方一夔','宋','宋诗','song-poetry','','[]','自歎形容改，空驚歲月更。',48,'全唐诗/poet.song.235000.json','["自歎形容改，空驚歲月更。", "黠蠶附繭死，怨鳥寄巢生。", "歉歲愁親故，貧家分弟兄。", "江南芳草地，此別若爲情。"]'),
('36266bb4-eb7b-417d-b27c-474cf7c0a8d4','秋夜','方一夔','宋','宋诗','song-poetry','','[]','露白初濡木，星虛漸集房。',48,'全唐诗/poet.song.235000.json','["露白初濡木，星虛漸集房。", "蛾飛爭墮水，魚退急投梁。", "搗練隄防冷，收禾準備荒。", "只愁棗紅地，萬馬逐殘羌。"]'),
('f832f31e-f6b6-4199-ab54-4cd05de6dea0','冬日','方一夔','宋','宋诗','song-poetry','','[]','冬晴不作雪，無處聽寒號。',48,'全唐诗/poet.song.235000.json','["冬晴不作雪，無處聽寒號。", "山外一輪起，霧中三丈高。", "曝肩樵解褐，曬翼鳥遺毛。", "不特寒梅早，牆陰發露桃。"]'),
('0f017ea1-67f8-4513-abe6-ba0e53329324','早行','方一夔','宋','宋诗','song-poetry','','[]','早行理歸裝，殘燈耿曙光。',48,'全唐诗/poet.song.235000.json','["早行理歸裝，殘燈耿曙光。", "開門半山月，立馬一庭霜。", "鐘響知雲寺，波聲認石梁。", "脩途留不住，去去出山莊。"]'),
('27d37ad6-398d-432c-ba39-afa0f7c456f1','山行','方一夔','宋','宋诗','song-poetry','','[]','幽懷浩難寫，倚徙一枝藤。',48,'全唐诗/poet.song.235000.json','["幽懷浩難寫，倚徙一枝藤。", "春蔓雲根草，寒流石罅冰。", "山行千萬轉，茶話兩三僧。", "亭下尋歸渡，漁舟喚不譍。"]'),
('86074673-5958-44db-893c-3e5b21575b12','晚坐二首  其一','方一夔','宋','宋诗','song-poetry','','[]','羲娥相逐走，歲月不饒人。',48,'全唐诗/poet.song.235000.json','["羲娥相逐走，歲月不饒人。", "露重棲翰倦，月明歸夢頻。", "還家如過客，落地即成親。", "世路秋風早，悠悠多賤貧。"]'),
('1a10fb6c-3c73-45b3-8862-24bd96d31d74','晚坐二首  其二','方一夔','宋','宋诗','song-poetry','','[]','蘋風入疎竹，紅影颭窗扉。',48,'全唐诗/poet.song.235000.json','["蘋風入疎竹，紅影颭窗扉。", "遠地猶爲客，寒閨未寄衣。", "絲蟲墮復上，旅雁去還歸。", "寄語水曹裔，相期老翠微。"]'),
('47b60fd3-2230-4417-8d52-2842cef0fed6','雜興','方一夔','宋','宋诗','song-poetry','','[]','旅雁南猶北，絲蟲墮復粘。',48,'全唐诗/poet.song.235000.json','["旅雁南猶北，絲蟲墮復粘。", "流年忙裏過，衰髮暗中添。", "記事推銀管，尋題探玉籤。", "區區淡生活，與世異酸甜。"]'),
('f7c9b7cc-9cbe-4e1a-a84c-ee458f9fb5ae','游淥渚','方一夔','宋','宋诗','song-poetry','','[]','朝遊伍胥渡，暮投杜主祠。',48,'全唐诗/poet.song.235000.json','["朝遊伍胥渡，暮投杜主祠。", "綠蕪高犢背，紅雨瘦花枝。", "夾道鳴腰鼓，輕舟颭彩旗。", "蹇馿寒服客，未許看腰肢。"]'),
('b39a73f7-e492-4a2d-8d33-26faa6b23512','曉行二首  其一','方一夔','宋','宋诗','song-poetry','','[]','百年長擾擾，無地寄浮蹤。',48,'全唐诗/poet.song.235000.json','["百年長擾擾，無地寄浮蹤。", "客醉傷春酒，人行送曙鐘。", "烟霏啼謝豹，星斗壓盧龍。", "笑共孤雲往，歸投江上峯。"]'),
('50580b75-f475-48de-b707-0635850f9305','曉行二首  其二','方一夔','宋','宋诗','song-poetry','','[]','百折飄香路，千攢疊翠鄉。',48,'全唐诗/poet.song.235000.json','["百折飄香路，千攢疊翠鄉。", "斷橋人蹬蘚，低樹女剃桑。", "泊店風烟靜，問途山水長。", "新歸愁復去，佇立轉蒼茫。"]'),
('774d70a5-9f7f-42d3-a8f2-8c220baa2194','秋興四首  其一','方一夔','宋','宋诗','song-poetry','','[]','坐卧足清幽，何須定遠侯。',48,'全唐诗/poet.song.235000.json','["坐卧足清幽，何須定遠侯。", "一簷霜竹月，四壁夜蟲秋。", "酒不推辭醉，詩能斷送愁。", "可憐江令老，萬里返南州。"]'),
('2f816b74-7d74-481e-9d68-4962d133e38a','秋興四首  其二','方一夔','宋','宋诗','song-poetry','','[]','西窗幽絕處，懶與老相便。',48,'全唐诗/poet.song.235000.json','["西窗幽絕處，懶與老相便。", "燕伴遲歸客，潮推逆上船。", "照杯窺戶月，注硯養花泉。", "近藁無新語，歸來學釣鯿。"]'),
('9e87e47d-e2fb-4bc6-83cc-ab157fa5184a','秋興四首  其三','方一夔','宋','宋诗','song-poetry','','[]','孤跡寄滄洲，浮雲無去留。',48,'全唐诗/poet.song.235000.json','["孤跡寄滄洲，浮雲無去留。", "大山招楚些，小海傍吳謳。", "相值誰非我，欲歸春復秋。", "西風葛溪路，衣袖晚颼颼。"]'),
('96eb22d9-7dd3-4868-80ac-86ff3c5500b8','秋興四首  其四','方一夔','宋','宋诗','song-poetry','','[]','故里千山遠，荒城八月寒。',48,'全唐诗/poet.song.235000.json','["故里千山遠，荒城八月寒。", "霜椑餘鳥啄，社雨洗魚殘。", "紫塞跑風鬣，青冥縱露翰。", "微生獨不化，羈紲老江干。"]'),
('8888608a-d778-4298-93f7-8e42f8d37d5e','秋晚雜興十二首  其一','方一夔','宋','宋诗','song-poetry','','[]','深秋轉蕭索，木葉滿荒城。',48,'全唐诗/poet.song.235000.json','["深秋轉蕭索，木葉滿荒城。", "逝水流年景，西風逆旅情。", "圉監通馬語，籠養變禽鳴。", "吾道知衰久，人都一概聲。"]'),
('e747901c-d17a-4918-89b4-2f9cd6005939','秋晚雜興十二首  其二','方一夔','宋','宋诗','song-poetry','','[]','烏桕數家村，漁樵自作鄰。',48,'全唐诗/poet.song.235000.json','["烏桕數家村，漁樵自作鄰。", "舊墳前日發，富室近來貧。", "古道狐成怪，深山鬼作人。", "茫茫塵世事，無處問蒼旻。"]'),
('8f2cdfbb-1e7d-43e3-9499-f99f8a9c7bd9','秋晚雜興十二首  其三','方一夔','宋','宋诗','song-poetry','','[]','天涯誰道遠，嶺海接并幽。',48,'全唐诗/poet.song.235000.json','["天涯誰道遠，嶺海接并幽。", "馬带交河種，人穿真臘裘。", "梅花南國夢，苜蓿故宮秋。", "安得方仙道，飄飄訪十洲。"]'),
('22f630dc-57fd-4826-b8fd-27d0f2cb16b1','秋晚雜興十二首  其四','方一夔','宋','宋诗','song-poetry','','[]','月去極百度，天行水四旁。',48,'全唐诗/poet.song.235000.json','["月去極百度，天行水四旁。", "渥洼駒汗血，婆綠宇旁行。", "朔雨夏猶雪，南苞冬未霜。", "地中在何處，無便向嵩邙。"]'),
('823710cd-8e21-4533-aa2e-cd984f273c18','秋晚雜興十二首  其五','方一夔','宋','宋诗','song-poetry','','[]','門前吳越路，幾步隔紅塵。',48,'全唐诗/poet.song.235000.json','["門前吳越路，幾步隔紅塵。", "學課九千字，年書十二神。", "殷牀馳道馬，隔岸渡橋人。", "自愧樊籠裏，飛騰未有因。"]'),
('f95edd57-618e-458b-8a84-16d8c1e6f77d','秋晚雜興十二首  其六','方一夔','宋','宋诗','song-poetry','','[]','地占繁雄郡，人奔財賦疆。',48,'全唐诗/poet.song.235000.json','["地占繁雄郡，人奔財賦疆。", "北僧泥佛相，南客賈胡裝。", "打穀拳毛馬，彈箏跕躧娼。", "西風愁世路，無路立蒼茫。"]'),
('ab519e12-ee26-4832-8abb-bb8cd4ccd3fe','秋晚雜興十二首  其七','方一夔','宋','宋诗','song-poetry','','[]','青溪溪上路，書劍此棲遲。',48,'全唐诗/poet.song.235000.json','["青溪溪上路，書劍此棲遲。", "凉月穿衣褐，寒波照鬢絲。", "古桐傳賀若，橫玉犯龜茲。", "不爲傷秋老，孤吟自可悲。"]'),
('3a16a02f-0d1d-4c79-bc10-d71da2f2ffba','秋晚雜興十二首  其八','方一夔','宋','宋诗','song-poetry','','[]','誰作百年客，聊隨三宿僧。',48,'全唐诗/poet.song.235000.json','["誰作百年客，聊隨三宿僧。", "詩皆傳妙品，禪未悟中乘。", "曉枕空鳴角，秋窗夜剔燈。", "欣欣會心處，走墨剡溪藤。"]'),
('9c02dea3-94ff-4fe8-9ff0-60e97e3fddf7','秋晚雜興十二首  其九','方一夔','宋','宋诗','song-poetry','','[]','蟲壁話秋闌，西齋日已寒。',48,'全唐诗/poet.song.235000.json','["蟲壁話秋闌，西齋日已寒。", "階鳴辭故葉，水擊跕飛翰。", "路接千峯榭，潮通百丈灘。", "葛仙無處覓，我欲問燒丹。"]'),
('14feb0fd-7d59-4171-914f-60a448dfc731','秋晚雜興十二首  其一○','方一夔','宋','宋诗','song-poetry','','[]','夜魄湛精氣，冰魂消瘴氛。',48,'全唐诗/poet.song.235000.json','["夜魄湛精氣，冰魂消瘴氛。", "寒洲沙印篆，荒樹葉鎸文。", "詞度柳三變，書臨顧八分。", "誰憑當道勢，擡舉上青雲。"]'),
('2bc113e5-2548-43be-936d-a15f8f80803a','秋晚雜興十二首  其一一','方一夔','宋','宋诗','song-poetry','','[]','蕭索已秋色，空濛欲暮天。',48,'全唐诗/poet.song.235000.json','["蕭索已秋色，空濛欲暮天。", "平蕪荒樹外，疎柳斷橋邊。", "山暝殘雲合，波停碎月圓。", "眼前森萬境，忽忽暗彫年。"]'),
('ae20158e-d9e5-42f1-874b-681aa50e9165','秋晚雜興十二首  其一二','方一夔','宋','宋诗','song-poetry','','[]','客來銀水北，叩我老生涯。',48,'全唐诗/poet.song.235000.json','["客來銀水北，叩我老生涯。", "裘褐多捫蝨，田蕪半種瓜。", "文章動窮髮，碑板過流沙。", "終竟成何事，逢人莫浪誇。"]'),
('ab31bc5a-8549-408d-ba52-8993bf61a150','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 柑','方一夔','宋','宋诗','song-poetry','','[]','橘橙吾臭味，豈特是情親。',48,'全唐诗/poet.song.235000.json','["橘橙吾臭味，豈特是情親。", "三寸燕南異，一雙甌水珍。", "色包金錯晚，香擘玉纖春。", "無復承平事，天恩徧貴臣。"]'),
('525cbe78-45f7-4069-a3b4-ade6239e1bfd','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 橘','方一夔','宋','宋诗','song-poetry','','[]','果綠景初好，花開日正寒。',48,'全唐诗/poet.song.235000.json','["果綠景初好，花開日正寒。", "嚼香流玉瀣，分熟剪金丸。", "淮枳標殊性，甌柑並二難。", "無人徵包貢，蓬殿淚闌干。"]'),
('f3bf54e4-fc5b-4cb4-aaa7-245c7d460a0e','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 橙','方一夔','宋','宋诗','song-poetry','','[]','人皆遺外像，爾獨取皮毛。',48,'全唐诗/poet.song.235000.json','["人皆遺外像，爾獨取皮毛。", "露顆團黄玉，春枝剪綠袍。", "搗虀燒雨韭，飛縷薦霜螯。", "南橘應同派，誰云僕命騷。"]'),
('2cba2435-b594-42c0-b521-1ddc6c537e3e','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 梨','方一夔','宋','宋诗','song-poetry','','[]','自是雪香骨，風霜閲四時。',48,'全唐诗/poet.song.235000.json','["自是雪香骨，風霜閲四時。", "紙包防蠆尾，泉浸浴瓊肌。", "不作離愁斧，能爲潤肺醫。", "看渠津潤處，詩就已涎垂。"]'),
('b8e189a1-5bc7-4151-a88e-f7b17a539023','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 栗','方一夔','宋','宋诗','song-poetry','','[]','秦燕千樹地，富貴出山莊。',48,'全唐诗/poet.song.235000.json','["秦燕千樹地，富貴出山莊。", "外作蝟毛磔，中含雞子黄。", "懸枝開霽日，芽綠候春陽。", "每憶和兒炒，如今去故鄉。"]'),
('1882032b-3636-4873-972e-47ca6c716d0b','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 椑','方一夔','宋','宋诗','song-poetry','','[]','共祖青龍寺，分支金谷湄。',48,'全唐诗/poet.song.235000.json','["共祖青龍寺，分支金谷湄。", "擣生澄水漆，摘熟剝霜皮。", "半啄餘秋鳥，羣偷縛夜貍。", "長卿消病久，清冷慰詩脾。"]'),
('88a49349-72f0-44f5-8d9e-2665dc0d3324','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 柿','方一夔','宋','宋诗','song-poetry','','[]','萬株名古寺，近復說東陽。',48,'全唐诗/poet.song.235000.json','["萬株名古寺，近復說東陽。", "翠樹駢頳卵，燒空炯夜光。", "果堪凉渴朔，葉復草顛張。", "欲上潼江去，尋思石蜜霜。"]'),
('cc3f685e-c077-4df7-9bdc-0c2f5a08a210','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 榧','方一夔','宋','宋诗','song-poetry','','[]','有木出蠻鄉，生居萬仞岡。',48,'全唐诗/poet.song.235000.json','["有木出蠻鄉，生居萬仞岡。", "凌烟圖朽質，中水濯青裳。", "細剝瓊肌瑩，香浮琱俎光。", "尸蟲穴何處，食果得奇方。"]'),
('d47ccfd6-99fa-4e40-8a23-2163db957d2d','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 藕','方一夔','宋','宋诗','song-poetry','','[]','辛苦學淘河，尋根不仗柯。',48,'全唐诗/poet.song.235000.json','["辛苦學淘河，尋根不仗柯。", "千虬蟠下土，尺玉浸清波。", "自笑抽絲亂，從渠鑿竅多。", "誰分冰片片，一醉洗沉疴。"]'),
('52e02e6f-2e9b-4e1f-9c8e-631d25801e7d','世之詠物者採春花而落秋實余欲矯其失作冬果十詠 榴','方一夔','宋','宋诗','song-poetry','','[]','種自塗林得，名隨博望來。',48,'全唐诗/poet.song.235000.json','["種自塗林得，名隨博望來。", "半因霜虐重，多爲雨淫開。", "粒破冰生骨，房分珠带胎。", "玉匙飛一餉，爲我配金罍。"]'),
('a649150e-329c-443d-9a11-9f29b1662ac7','別徐雪岡','方一夔','宋','宋诗','song-poetry','','[]','春曉杏花路，逢梅憶故知。',48,'全唐诗/poet.song.235000.json','["春曉杏花路，逢梅憶故知。", "一年離別恨，幾度唱酬詩。", "風雪愁歸路，關山隔後期。", "欲言難即見，臨水寄相思。"]'),
('40dfa666-630b-4618-ba86-c2abd3c27097','別子聲諸友','方一夔','宋','宋诗','song-poetry','','[]','祇有去日數，悠悠歲月除。',48,'全唐诗/poet.song.235000.json','["祇有去日數，悠悠歲月除。", "再三來使語，千萬故人書。", "老况難爲別，親情暫以疎。", "往來愁道路，吾道竟何如。"]'),
('8b9fd9c8-63f0-46c2-b71e-4cb9baf76f47','夜坐','方一夔','宋','宋诗','song-poetry','','[]','風葉夜蕭騷，寒燈照寂寥。',48,'全唐诗/poet.song.235000.json','["風葉夜蕭騷，寒燈照寂寥。", "冷泉和月汲，殘葉带霜燒。", "半白吟髭茁，餘紅醉臉潮。", "舊來樵牧地，小隠不須招。"]'),
('d2335323-8e26-4b7e-b682-80c4b28611b7','山居二首  其一','方一夔','宋','宋诗','song-poetry','','[]','幽人在何處，東崦是吾家。',48,'全唐诗/poet.song.235000.json','["幽人在何處，東崦是吾家。", "小澗石楠樹，疎籬木槿花。", "林深啼蜀鳥，水滑搗胡麻。", "五字山居偈，長吟老歲華。"]'),
('a1f74b85-86df-4cc2-9a8d-23db33e549d0','山居二首  其二','方一夔','宋','宋诗','song-poetry','','[]','柴扉終日掩，一室靜無塵。',48,'全唐诗/poet.song.235000.json','["柴扉終日掩，一室靜無塵。", "久坐已穿榻，高眠不禿巾。", "詩腸愁境樂，酒面老年春。", "自有白雲隔，無勞麾俗人。"]'),
('5e1aa542-040c-45e4-9c5e-547b0c7d22c8','早行臨安道中','方一夔','宋','宋诗','song-poetry','','[]','早行高坎市，遺構草新青。',48,'全唐诗/poet.song.235000.json','["早行高坎市，遺構草新青。", "敗壁蝸留篆，空棺狐讀經。", "落花新舊恨，別酒短長亭。", "惟有松林下，寒梅尚獨醒。"]'),
('496768b1-b4ee-4e39-85a1-93c733678206','燈下書懷二首  其一','方一夔','宋','宋诗','song-poetry','','[]','浮生幾半百，况復值秋闌。',48,'全唐诗/poet.song.235000.json','["浮生幾半百，况復值秋闌。", "瘦地年年旱，貧家種種難。", "兒因廢學懶，妻爲典衣寒。", "吾意憐文墨，時時展卷看。"]'),
('6e4e0cde-9922-4fe9-944c-cd1b1ec7a942','燈下書懷二首  其二','方一夔','宋','宋诗','song-poetry','','[]','青雲謝足下，流水暗門闌。',48,'全唐诗/poet.song.235000.json','["青雲謝足下，流水暗門闌。", "生計作詩苦，客愁行路難。", "老慙鞍馬晚，窮笑硯蟾寒。", "歲暮餘松菊，留人仔細看。"]'),
('7c44e1f7-4c19-4b8f-8114-b868a1dbee44','過棠山徐墳欲招通甫不果晚憩景德觀以歸寄通甫','方一夔','宋','宋诗','song-poetry','','[]','送春過棠峯，假步自登眺。',240,'全唐诗/poet.song.235000.json','["送春過棠峯，假步自登眺。", "行田走詰屈，攀磴上䆗窱。", "岡巒聳四圍，崖壁儼雙峭。", "野芳躑躅紅，林宿離黄叫。", "感彼松下人，脆甚風中燎。", "精靈散埃氛，骨肉蔽窾竅。", "晝眠嘷狐狌，夜照飛熠燿。", "朗悟豁餘悲，清響發長嘯。", "思君客沃洲，對面隔蓬嶠。", "扣門乏因緣，更僕煩請召。", "流落俱異鄉，節奏本同調。", "風高鷁退飛，月落牛反噍。", "夷猶憇仙宮，酬答領道要。", "幽尋屋種梅，雜坐逕披藋。", "棋枰夜半局，丹竈晝殘燒。", "心期迥獨詣，世誘浩難掉。", "詩興逼行雲，樹色留晚照。", "拾翠記前遊，舉白倒餘釂。", "桐尾隠寶匣，龍文掩魚鞘。", "何日聯華鑣，葭菼亂漁釣。"]'),
('9cc9fa84-ea6d-4c74-988e-bc98e3d6e2ce','遠遊四十韻','方一夔','宋','宋诗','song-poetry','','[]','介士苦拘檢，策士妙籌度。',288,'全唐诗/poet.song.235000.json','["介士苦拘檢，策士妙籌度。", "俠窟養聲譽，宦海高階爵。", "紛然殊門戶，何能脫韁索。", "自憐心期遠，雅與俗物薄。", "潛光瑩璆璧，幽芬結蘺葯。", "濯濯出山泉，亭亭橫空鶚。", "挾策誤中眉，投耒悲失脚。", "文圍嚴靷鞅，詩戰淬鋩鍔。", "梯飈轉南溟，銘山蕩朔漠。", "君門虎豹嚴，天路鬼神惡。", "高唱不逢和，貴售屢遭却。", "龍移崖垠崩，鼇掉海湖涸。", "運流數遷謝，時改異今昨。", "乃翁安事書，此輩宜疎闊。", "三年屠蛟虯，無用閑猛斫。", "百金買砂青，不售虛奇藥。", "日月雙飛奔，身世兩寂寞。", "夜雨暗燈火，秋月冷籬落。", "不甘軟弱吞，坐受饑窮縛。", "萬里落半途，全局差一着。", "逝將故人心，共赴青雲約。", "東遊畧蓬壺，南望趨衡霍。", "鼎中珠還返，腰下寶踴躍。", "朝真玉皇頷，問道金仙諾。"]'),
('743f5e02-b55c-46bf-bedd-1c0fcc992302','雜興','方一夔','宋','宋诗','song-poetry','','[]','世奕奔趨若决河，誰將獨力障頹波。',64,'全唐诗/poet.song.235000.json','["世奕奔趨若决河，誰將獨力障頹波。", "指衣太守存唐苦，循髮將軍負漢多。", "薜芷不芳甘自變，白圭有玷尚堪磨。", "是非勿與時人說，爲就重華述九歌。"]'),
('67eebe59-6a2c-42a2-8819-8f858a32cab7','閔忠','方一夔','宋','宋诗','song-poetry','','[]','弱冠知名動紫宸，兩朝際遇荷恩深。',64,'全唐诗/poet.song.235000.json','["弱冠知名動紫宸，兩朝際遇荷恩深。", "身先赴義人爭死，天不成功淚滿襟。", "自鄭有謀歸華氏，舍湘無地托王琳。", "鞠躬待死無餘事，不負朝廷不負心。"]'),
('7044dc62-676a-4155-8a9f-63e69e6a9bd4','誅姦','方一夔','宋','宋诗','song-poetry','','[]','握兵結眷冕旒前，牢落英雄二十年。',64,'全唐诗/poet.song.235000.json','["握兵結眷冕旒前，牢落英雄二十年。", "虎殿壽觴人痛哭，鵑堂私語衆喧傳。", "爾身不恤無埋地，此恥奚容共戴天。", "不有四明倡清議，至今蛟虎卧山淵。"]'),
('292a597c-1236-4ff9-b09f-cfe4cb8966e2','盧明之開壚','方一夔','宋','宋诗','song-poetry','','[]','懶作西風汗漫遊，歸謀諸婦此淹留。',64,'全唐诗/poet.song.235000.json','["懶作西風汗漫遊，歸謀諸婦此淹留。", "采花墩近初成酒，種秫田多早带秋。", "燕頷已空西塞夢，犢裩莫遣遠山愁。", "滄江留得偏醒客，袖手時凭百尺樓。"]'),
('a2c56c98-6261-4198-8106-4a89bb4b0172','宋震翁以詩見推次韻爲謝','方一夔','宋','宋诗','song-poetry','','[]','脩竹猗猗月半間，此生贏得占清閒。',64,'全唐诗/poet.song.235000.json','["脩竹猗猗月半間，此生贏得占清閒。", "磨鉛勘易未三絕，吐火燒丹欲九還。", "騎鶴腰纏空入夢，跨牛髀骨慣行山。", "秋來閒把詩消遣，敢向騷壇占絕班。"]'),
('c7bd7aba-3f40-47fe-a85b-7d14a599c58b','雜興  其一','方一夔','宋','宋诗','song-poetry','','[]','種竹千竿密復疎，菉猗深處着蝸廬。',64,'全唐诗/poet.song.235000.json','["種竹千竿密復疎，菉猗深處着蝸廬。", "有牀自可安周易，無飯誰教典漢書。", "疊嶂畫屏圍棐案，飛泉白練落階除。", "絕無半點功名望，一任浮雲自卷舒。"]'),
('c5254348-d7da-48f4-8edb-6c997c8dd255','雜興  其二','方一夔','宋','宋诗','song-poetry','','[]','不露文章世不驚，由來天亦厭虛名。',64,'全唐诗/poet.song.235000.json','["不露文章世不驚，由來天亦厭虛名。", "弦歌夫子窮將聖，風雅靈均死獨清。", "其道卷懷何足恨，斯文得與豈無情。", "長歌獨坐滄浪水，休說他年起濯纓。"]'),
('ef006fbc-7f42-494a-8c39-0d7f07309921','雜興  其三','方一夔','宋','宋诗','song-poetry','','[]','青山相對總儀刑，人世浮華隔幾塵。',64,'全唐诗/poet.song.235000.json','["青山相對總儀刑，人世浮華隔幾塵。", "厚味不知菘韭薄，舊銜那似菊松新。", "銀罌豹血爭劉項，翠釜駞峯死虢秦。", "大抵危機隨富貴，不曾粘著退閒人。"]'),
('f9448c6b-883d-4e05-aeaf-123742d5f2a4','雜興  其四','方一夔','宋','宋诗','song-poetry','','[]','霜風獵獵響林坳，獨有寒梅漸作包。',64,'全唐诗/poet.song.235000.json','["霜風獵獵響林坳，獨有寒梅漸作包。", "倒影水涵窺沼樹，淺痕月印上窗梢。", "綠衣低掛酒初熟，烏帽斜欹門屢敲。", "花得初陽人得復，俱從顔子結窮交。"]'),
('4dc488ee-9914-47db-875a-5346d274099e','雜興  其五','方一夔','宋','宋诗','song-poetry','','[]','天地生生不盡仁，惟梅先得一年春。',64,'全唐诗/poet.song.235000.json','["天地生生不盡仁，惟梅先得一年春。", "花神銓次初編譜，月老莊嚴妙寫真。", "索笑暗添風度爽，嚼香清洗肺肝塵。", "莫嫌刪後多題品，自二南來有幾人。"]'),
('b5b3821b-296c-4f6a-90bb-84d8fd0a0f09','予家世居富山久矣世有隠德老坡所謂我家韋布三百年惟有陰功不知數蓋類是也因作此以記其實且以勉族氏子弟云  其一','方一夔','宋','宋诗','song-poetry','','[]','自有乾坤有此山，嘉名久矣落人間。',64,'全唐诗/poet.song.235000.json','["自有乾坤有此山，嘉名久矣落人間。", "吐吞雲霧景千變，森秀松柟翠四環。", "肯並貴溪爭顯達，應同愚谷耐堅頑。", "山人儘得清吟趣，芳杜香蓀不厚顔。"]'),
('0768c0fb-3f12-4c2d-93de-c7cf9ae04513','予家世居富山久矣世有隠德老坡所謂我家韋布三百年惟有陰功不知數蓋類是也因作此以記其實且以勉族氏子弟云  其二','方一夔','宋','宋诗','song-poetry','','[]','家住青溪東復東，林霏嵐影暗葱蘢。',64,'全唐诗/poet.song.235000.json','["家住青溪東復東，林霏嵐影暗葱蘢。", "山排闥入蹲蒼虎，水抱村流卧玉龍。", "田畫井疆前後隴，岡橫乾艮兩三重。", "客來若問誅茅地，落日雲飛第一峯。"]'),
('fa132502-2c77-4dfe-8df5-3728b76883fd','予家世居富山久矣世有隠德老坡所謂我家韋布三百年惟有陰功不知數蓋類是也因作此以記其實且以勉族氏子弟云  其三','方一夔','宋','宋诗','song-poetry','','[]','我家韋布久嬋嫣，積善工夫遠有源。',64,'全唐诗/poet.song.235000.json','["我家韋布久嬋嫣，積善工夫遠有源。", "東漢賢良來鼻祖，晚唐文獻到聞孫。", "世增忠厚成風俗，人尚耕桑務本根。", "賸喜邇來多識字，粗書甲子記新元。"]'),
('1c048814-2e8e-4285-8863-541310319141','靜樂先生祠堂','方一夔','宋','宋诗','song-poetry','','[]','五季橫流欲障天，先生雅志寄林泉。',64,'全唐诗/poet.song.235000.json','["五季橫流欲障天，先生雅志寄林泉。", "嘯吟獨抱濟時畧，高尚甘爲遯世賢。", "奕葉簪纓他有耀，微時耒耜我相傳。", "何年得見歸來鶴，暫假風翰逐老仙。"]'),
('fad685ee-4fbc-463e-86b5-0cc2f95db2c5','梅','方一夔','宋','宋诗','song-poetry','','[]','玉妃破白入春宮，萬紫千紅立下風。',64,'全唐诗/poet.song.235000.json','["玉妃破白入春宮，萬紫千紅立下風。", "老樹冰霜皴剝後，寒枝烟水有無中。", "月橫山館笛初起，人立溪橋馬欲東。", "爲寄故人無信息，更憑健筆入詩筒。"]'),
('aa8b5e04-656c-46a0-80e3-59bd2ddc66b1','雜興','方一夔','宋','宋诗','song-poetry','','[]','南枝憔悴北枝榮，轉眼浮華跡已陳。',64,'全唐诗/poet.song.235000.json','["南枝憔悴北枝榮，轉眼浮華跡已陳。", "昨夢已空巫峽雨，昔遊曾記武陵春。", "浮生一日復一日，世事後人哀後人。", "兩鬢欲霜行脚倦，悠悠無計謝風塵。"]'),
('ee370a5e-4ca9-4922-85a4-81f06e48ef95','大卿先生惠藥方','方一夔','宋','宋诗','song-poetry','','[]','淺謀不遂少年狂，咄咄催人鬢髮蒼。',64,'全唐诗/poet.song.235000.json','["淺謀不遂少年狂，咄咄催人鬢髮蒼。", "深雪寒添詩興爽，早梅清徹夢魂香。", "已諳林壑投閒趣，且試神仙却老方。", "聞說丹爐留近處，贏糧我欲問金堂。"]'),
('7bf94fbb-5679-4576-a897-91bebe9a5a34','田園雜興','方一夔','宋','宋诗','song-poetry','','[]','半生燈火誤牛衣，晚歲纔能悟昨非。',64,'全唐诗/poet.song.235000.json','["半生燈火誤牛衣，晚歲纔能悟昨非。", "雨笠半欹將犢去，絲車細捲趁蛾飛。", "粟生燒地山宜老，草爛新畬水正肥。", "莫道勞生何日息，邇來是事喜忘機。"]'),
('e3811974-f894-4249-9418-94319843a021','觀物','方一夔','宋','宋诗','song-poetry','','[]','彭殤顔跖不相齊，秋悴春榮各有時。',64,'全唐诗/poet.song.235000.json','["彭殤顔跖不相齊，秋悴春榮各有時。", "共種花分紅白色，同根木有死生枝。", "悲欣自是人情異，賦予寧非造物私。", "却笑莊生未諳此，安排齊物費言辭。"]'),
('cab68db7-1991-4147-8fc8-87aabc42c6b3','木犀花  其一','方一夔','宋','宋诗','song-poetry','','[]','此花習氣愛巉巖，不受紅塵點碧衫。',64,'全唐诗/poet.song.235000.json','["此花習氣愛巉巖，不受紅塵點碧衫。", "地把鷲峯移境界，天教蟾窟墮塵凡。", "瑶林摵摵敲殘玉，金屑霏霏貯滿函。", "月影徘徊花影亂，待携雙盞與君銜。"]'),
('0dca55c4-b6f6-4f7b-9b2a-2eb0d0668f0e','木犀花  其二','方一夔','宋','宋诗','song-poetry','','[]','招隠誰招到碧巖，自嫌黄綬映青衫。',64,'全唐诗/poet.song.235000.json','["招隠誰招到碧巖，自嫌黄綬映青衫。", "月光童子分根柢，金粟如來混聖凡。", "勝賞莫辭空百盞，麗酬不記達千函。", "竦身便脫塵埃去，徑上清虛謝轡銜。"]'),
('25ab3bbe-2586-4bb2-88de-0a680db84253','木犀花  其三','方一夔','宋','宋诗','song-poetry','','[]','秋風吹夢遶千巖，偷看天宮雲錦衫。',64,'全唐诗/poet.song.235000.json','["秋風吹夢遶千巖，偷看天宮雲錦衫。", "色尚紅黄定崔李，花從開謝識荆凡。", "試教月老排芳譜，更聽仙童誦玉函。", "賸有辟寒金粟樹，丁寧棲鳥莫教銜。"]'),
('4395b6a8-d417-47e2-86e6-e6a5d7d6d0a5','木犀花  其四','方一夔','宋','宋诗','song-poetry','','[]','曾住仙山九折巖，夜凉蘿荔掛衣衫。',64,'全唐诗/poet.song.235000.json','["曾住仙山九折巖，夜凉蘿荔掛衣衫。", "月窺樽裏如相伴，人立花邊自不凡。", "叢綠聯環瑲玉佩，殘黄鎖骨現金函。", "枝空蟾窟今誰記，猶道東陵繫舊銜。"]'),
('d82f3c23-95db-4091-bd19-4a1dc49165b4','耜巖連和六首予與汪子新亦各再和二首  其一','方一夔','宋','宋诗','song-poetry','','[]','夜隨凉氣坐秋巖，醉墨淋漓亂點衫。',64,'全唐诗/poet.song.235000.json','["夜隨凉氣坐秋巖，醉墨淋漓亂點衫。", "花裏固知仙種別，詩中肯道使君凡。", "乘風徑欲眠香窟，修月曾經發寶函。", "收拾萬金歸賈橐，不須麟閣大書銜。"]'),
('7a5999b6-7847-41cc-9679-a6ecec9428d0','耜巖連和六首予與汪子新亦各再和二首  其二','方一夔','宋','宋诗','song-poetry','','[]','風韻孤高百尺巖，敝袍爭得似荷衫。',64,'全唐诗/poet.song.235000.json','["風韻孤高百尺巖，敝袍爭得似荷衫。", "久知郤氏聲名遠，自愧賓王骨相凡。", "閒搗香涎供玉杵，戲題綵帖拂塵函。", "醉來爲問姮娥信，更倩魚傳與雁銜。"]'),
('828b0549-be1b-4d4b-ad1d-e5e57fc579c3','秋晚雜興','方一夔','宋','宋诗','song-poetry','','[]','白藕花殘暑氣收，憑高更欲上層樓。',64,'全唐诗/poet.song.235000.json','["白藕花殘暑氣收，憑高更欲上層樓。", "蒹葭淅瀝水天晚，禾黍高低風雨秋。", "雞甕豕零更佐使，狗屠狐叫或王侯。", "世間萬事祇如許，莫把閒愁枉白頭。"]'),
('5a6b2dfc-3acc-4e0c-81cf-88b7c42c4d60','以書院課治事留杭十日竟爲小吏所阻','方一夔','宋','宋诗','song-poetry','','[]','倦看世態變凉炎，老覺詩書味更嚴。',64,'全唐诗/poet.song.235000.json','["倦看世態變凉炎，老覺詩書味更嚴。", "與世不諧多枘鑿，謀生甚拙欠虀鹽。", "摶風肯羨鵾鵬化，署紙偏憎雁鶩箝。", "從使小兒輕我輩，只今歸去問陶潛。"]'),
('19882cdb-7a38-4442-b22b-8033795cb342','舟泊松江','方一夔','宋','宋诗','song-poetry','','[]','蓴江幾度酹張翰，屈指今纔二十年。',64,'全唐诗/poet.song.235000.json','["蓴江幾度酹張翰，屈指今纔二十年。", "昔日米囊羞破釜，暮年詩卷壓歸船。", "飛飛燕子依風席，漠漠楊花點客氈。", "草遠烟濃迷處所，鄉心飛去白雲邊。"]'),
('2218598c-e4f8-464d-98b9-b1898e45695b','過錢塘舊京','方一夔','宋','宋诗','song-poetry','','[]','曾逐東風過曲江，人間俯仰隔興亡。',64,'全唐诗/poet.song.235000.json','["曾逐東風過曲江，人間俯仰隔興亡。", "江頭潮涸趨漁浦，山下城空失鳳凰。", "漠漠黄埃昏草棘，悠悠陳迹閲星霜。", "由來離黍遊麋地，不分鈴鳴替戾岡。"]'),
('734e1f31-ac93-471a-bb71-2cc8a6c01636','再點陶金戶計','方一夔','宋','宋诗','song-poetry','','[]','萬里雲程阻便風，孤鴻痛定再傷弓。',64,'全唐诗/poet.song.235000.json','["萬里雲程阻便風，孤鴻痛定再傷弓。", "徵求多出儒冠外，飛走難逃世網中。", "不分事情多倚仗，厭看人面訴貧窮。", "生平豪氣難磨折，時向毫端吐白虹。"]'),
('43a67cad-e1a7-469c-9faa-624c705cae06','清明二首  其一','方一夔','宋','宋诗','song-poetry','','[]','漢世諸陵已古邱，悲風摵摵老梧楸。',64,'全唐诗/poet.song.235000.json','["漢世諸陵已古邱，悲風摵摵老梧楸。", "金人往日淚曾墮，石馬何時汗忽流。", "江北江南千里隔，身前身後百年愁。", "九原定有英靈在，消得寒儒浪白頭。"]'),
('15fc8baf-44ce-45bb-80fa-2f363e215cf4','清明二首  其二','方一夔','宋','宋诗','song-poetry','','[]','一去昭陽入朔臺，羈魂流落不歸來。',64,'全唐诗/poet.song.235000.json','["一去昭陽入朔臺，羈魂流落不歸來。", "葬從胡地留妃骨，死向南方颺后灰。", "鴉噪莫看耘墓迹，酒香誰把洒陵杯。", "茫茫草地人稀到，風急棠梨落又開。"]'),
('15e29db6-e0ca-44ce-84be-af9fe7024afa','次韻洪復翁食蕨','方一夔','宋','宋诗','song-poetry','','[]','花葉根莖種種香，誰知山草宿舂糧。',64,'全唐诗/poet.song.235000.json','["花葉根莖種種香，誰知山草宿舂糧。", "筠籃凈洗傾銀粉，瓦釜狂搜凍蔗漿。", "爽口如兼三鼎味，療饑不試五倉方。", "西山餓死真餘事，安有冥鴻爲稻粱。"]'),
('785c4bab-d190-44fe-8153-433ba55d43df','別弟','方一夔','宋','宋诗','song-poetry','','[]','欲去相看手重携，寒波芳草助淒迷。',64,'全唐诗/poet.song.235000.json','["欲去相看手重携，寒波芳草助淒迷。", "無人傳業空多子，有弟持家老得妻。", "風雨燈前頻入夢，詩文酒後共分題。", "孤飛不羨冥鴻舉，只羨南歸羽翼低。"]'),
('669ab7c6-dd2b-427b-b807-dd3fce722edf','雜興十首  其一','方一夔','宋','宋诗','song-poetry','','[]','前程在處暗危機，脫跡紅塵入翠微。',64,'全唐诗/poet.song.235000.json','["前程在處暗危機，脫跡紅塵入翠微。", "清水一竿張釣具，白雲四壁掛樵衣。", "馬惟畫骨空嗟瘦，龍不點睛那解飛。", "差有陳編相伴住，時將詩句洗前非。"]'),
('0225c0a6-2125-40bd-a974-e382af07efa1','雜興十首  其二','方一夔','宋','宋诗','song-poetry','','[]','老去蹉跎萬事休，襟期甚不入時流。',64,'全唐诗/poet.song.235000.json','["老去蹉跎萬事休，襟期甚不入時流。", "倦飛已作歸林鳥，懶起猶如落草牛。", "一點眉黄無宦况，五分頭白爲詩愁。", "玉人期我滄洲上，未擬他年賦遠遊。"]'),
('7b410b91-4ab4-41c9-8012-f06baac9d640','雜興十首  其三','方一夔','宋','宋诗','song-poetry','','[]','已更門戶自持鉏，謝絕交遊與世疎。',64,'全唐诗/poet.song.235000.json','["已更門戶自持鉏，謝絕交遊與世疎。", "處變卿還用卿法，養高吾自愛吾廬。", "屏張前世無聲畫，架插今生未見書。", "水北山人偏解意，求分半席間樵漁。"]'),
('c38f4f12-90cc-41c2-b965-00862c435ea6','雜興十首  其四','方一夔','宋','宋诗','song-poetry','','[]','冷落門牆絕似冰，夜窗風雨耿孤燈。',64,'全唐诗/poet.song.235000.json','["冷落門牆絕似冰，夜窗風雨耿孤燈。", "采盆任我翻成雉，涴墨從渠點作蠅。", "休說文章祇小技，由來富貴總無能。", "依稀楊李無人憶，但憶瀼西杜少陵。"]'),
('70804baf-c32e-4d53-9143-97fb385802e6','雜興十首  其五','方一夔','宋','宋诗','song-poetry','','[]','紫綬緋裳印佩金，我於數子總無情。',64,'全唐诗/poet.song.235000.json','["紫綬緋裳印佩金，我於數子總無情。", "傍人門戶傳書客，投老田園識字氓。", "世變委懷無逆順，事機到手即功名。", "子房收斂英雄迹，誰說神仙在穀城。"]'),
('7d705aae-4117-4e35-895a-b440ec8ff68f','雜興十首  其六','方一夔','宋','宋诗','song-poetry','','[]','人境無緣斷俗喧，丁寧牢閉兩柴門。',64,'全唐诗/poet.song.235000.json','["人境無緣斷俗喧，丁寧牢閉兩柴門。", "五更孤枕客懷惡，半世青燈書眼昏。", "有日空爲無日計，醉時還道醒時言。", "白雲久有南山夢，不待他年畢嫁婚。"]'),
('f84fd6c5-afac-4a8b-b87b-c8c1eacddca0','雜興十首  其七','方一夔','宋','宋诗','song-poetry','','[]','駸駸鏡裏鬢霜侵，偶占溪東十畝陰。',64,'全唐诗/poet.song.235000.json','["駸駸鏡裏鬢霜侵，偶占溪東十畝陰。", "風雨四時無盡藏，松篁終夜有餘馨。", "家藏爲米難餬口，日課除詩罕用心。", "誰說倉曹任窖穀，近來家富屢千金。"]'),
('53e9c073-cd76-433a-be92-a984287817da','雜興十首  其八','方一夔','宋','宋诗','song-poetry','','[]','先生高寄此林泉，懶拙方知此樂全。',64,'全唐诗/poet.song.235000.json','["先生高寄此林泉，懶拙方知此樂全。", "足屨兩忘便不借，人琴俱隠付無絃。", "雲歸書帙留殘潤，日上香盤裊細烟。", "勘破世紛無一事，又拈枯筆續前編。"]'),
('5447df49-1658-40f4-8b53-fc54f429df25','雜興十首  其九','方一夔','宋','宋诗','song-poetry','','[]','不仙不釋不居官，久狎漁樵作往還。',64,'全唐诗/poet.song.235000.json','["不仙不釋不居官，久狎漁樵作往還。", "細雨飽眠一黄犢，白雲秀拔幾青山。", "浮生往事真成夢，舉世誰人最得閒。", "惆悵伏波粗意氣，暮年猶向五溪蠻。"]'),
('6ca9dcc4-e81c-4809-a0d0-a61a30094831','雜興十首  其一○','方一夔','宋','宋诗','song-poetry','','[]','生平繆計百無成，衰白如期入鏡明。',64,'全唐诗/poet.song.235000.json','["生平繆計百無成，衰白如期入鏡明。", "鳥不驚猜無忤物，人多怒駡漸逃名。", "襟懷落落憐孤影，歲月悠悠過半生。", "老去自知無處用，只留雙眼待昇平。"]'),
('1ac7afc6-cb9e-4910-a02d-48462008ffc8','春晚即事二首  其一','方一夔','宋','宋诗','song-poetry','','[]','紛泊楊花逐晚風，杜鵑聲徹故園東。',64,'全唐诗/poet.song.235000.json','["紛泊楊花逐晚風，杜鵑聲徹故園東。", "百千種事孤愁外，四十餘年一笑中。", "血作公文緣分定，膊成山字坐詩窮。", "少時懷抱今寥落，惆悵西窗夕照紅。"]'),
('b4f67d54-2b3a-4d0b-8743-630cf43c9d3d','春晚即事二首  其二','方一夔','宋','宋诗','song-poetry','','[]','匆匆塵裏換時光，春去夤緣底事忙。',64,'全唐诗/poet.song.235000.json','["匆匆塵裏換時光，春去夤緣底事忙。", "鳩已居巢晴逐婦，蜂方出穴暖分王。", "唱耕農起催秧綠，打供僧來趁麥黄。", "今歲先生貧到骨，時時爲米糴官倉。"]'),
('76af0338-8975-4cce-8c08-14ade5081b9b','妾薄命','方一夔','宋','宋诗','song-poetry','','[]','薄命佳人玉絕瑕，不隨緣分落民家。',64,'全唐诗/poet.song.235000.json','["薄命佳人玉絕瑕，不隨緣分落民家。", "悲風古冢生青草，落日深宮唱白花。", "萬里思情餘蹋踘，一生舊恨付琵琶。", "雄蜂雌蝶難相並，莫向春風怨歲華。"]'),
('2159e2cb-2310-4a88-9592-b65716eea8b1','雜興三首  其一','方一夔','宋','宋诗','song-poetry','','[]','自合林泉着散仙，虎蛟在處卧山淵。',64,'全唐诗/poet.song.235000.json','["自合林泉着散仙，虎蛟在處卧山淵。", "未秋已擬償新穀，計月先愁欠子錢。", "冷眼慣看平地險，薄情誰念死灰然。", "人生還有相逢處，昨日淮陰召少年。"]'),
('ad9db293-bfd5-41af-9f5c-1081d965365a','雜興三首  其二','方一夔','宋','宋诗','song-poetry','','[]','漫向松邊倚瘦筇，一生襟抱與誰同。',64,'全唐诗/poet.song.235000.json','["漫向松邊倚瘦筇，一生襟抱與誰同。", "照人不老古今月，送客多情南北風。", "才盡懸知詩作祟，數奇莫與命爭窮。", "冶金百煉今無幾，休向人前說事功。"]'),
('dfdc8dd0-6114-4446-913e-d0a91ba23b66','雜興三首  其三','方一夔','宋','宋诗','song-poetry','','[]','經秋春蕙歎時過，歸卧南窗竹一坡。',64,'全唐诗/poet.song.235000.json','["經秋春蕙歎時過，歸卧南窗竹一坡。", "世味甚輕貪慾少，交情稍重怨恩多。", "羞從綠酒看霜劍，悔把青燈誤雨簑。", "技癢未能忘習氣，新詩寫罷更長歌。"]'),
('5adca3f9-cc7f-4de3-b103-04071c71a80a','神仙','方一夔','宋','宋诗','song-poetry','','[]','擾擾爭趨陌路塵，好閒平地即蓬瀛。',64,'全唐诗/poet.song.235000.json','["擾擾爭趨陌路塵，好閒平地即蓬瀛。", "青羊石化紫烟客，白鶴松成老樹精。", "夾岸碧桃春水闊，滿山落葉暮雲橫。", "神仙不用尋行迹，只向漁樵混姓名。"]'),
('cda95703-e835-4f47-a1d5-227d3a824dfc','竹','方一夔','宋','宋诗','song-poetry','','[]','當年知己晉參軍，畫手分傳老可文。',64,'全唐诗/poet.song.235000.json','["當年知己晉參軍，畫手分傳老可文。", "碎影貼金初得月，寒梢聳翠欲干雲。", "平生自是輕餘子，一日那能無此君。", "解爲南風却炎暑，擬封清渭答殊勛。"]'),
('323b21db-ceb9-426b-90ca-7d4ec5922fd1','夜坐二首  其一','方一夔','宋','宋诗','song-poetry','','[]','人間無處避紅爐，急掃風軒醉一壺。',64,'全唐诗/poet.song.235000.json','["人間無處避紅爐，急掃風軒醉一壺。", "泉冷月涵沉水璧，荷香雨跳走盤珠。", "神遊曾到清凉境，幽討如橫綠野圖。", "醉髮醒鬆吟骨聳，從人笑絕道詩癯。"]'),
('276d25b8-352c-4aa1-876c-91ed1d8a0cb9','夜坐二首  其二','方一夔','宋','宋诗','song-poetry','','[]','呼奴薙草火攻蚊，與客高談到夜深。',64,'全唐诗/poet.song.235000.json','["呼奴薙草火攻蚊，與客高談到夜深。", "風辨雌雄分別想，歲占牡牝喜嗔心。", "塵生渴肺須狂飲，寒聳詩肩更苦吟。", "秋色滿懷人不寐，坐看落月與橫參。"]'),
('99edf390-e04d-4f58-93b9-595d0b4fdfd9','術者謂予清淡鎡基不貧不富而有壽','方一夔','宋','宋诗','song-poetry','','[]','誰甘清淡厭輕肥，命薄那堪不值時。',64,'全唐诗/poet.song.235000.json','["誰甘清淡厭輕肥，命薄那堪不值時。", "插架簡編家四壁，蟠胸梗概鬢千絲。", "狂圖入夢空騎鶴，壽相生芒欲鬭龜。", "莫訝時魚更多骨，從來萬事有參差。"]'),
('43fa2a21-f79e-4c86-8874-c77c066827e2','看笋','方一夔','宋','宋诗','song-poetry','','[]','丁寧莫採籜龍兒，造物成材各有時。',64,'全唐诗/poet.song.235000.json','["丁寧莫採籜龍兒，造物成材各有時。", "寸碧縱橫牛戴角，一斑纏裹豹留皮。", "長身上水夜深看，直幹干雲歲晚知。", "名節爲君描畫盡，清吟堪繼菉猗詩。"]'),
('5a686078-9cd4-44ea-a6fe-abfb894b2f6d','初秋雜興三首  其一','方一夔','宋','宋诗','song-poetry','','[]','利欲驅人看罷休，人間歲月不停留。',64,'全唐诗/poet.song.235000.json','["利欲驅人看罷休，人間歲月不停留。", "別愁萬里滄江水，歸夢五更黄葉秋。", "貯腹謾誇李書簏，爛腸難擬董糟丘。", "老懷抑塞無人會，徙倚西風百尺樓。"]'),
('43603d14-e9f1-45ba-8ecd-3b1907becbb2','初秋雜興三首  其二','方一夔','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','守困書帷滯土牛，誰揮尺箠浴寒流。',64,'全唐诗/poet.song.235000.json','["守困書帷滯土牛，誰揮尺箠浴寒流。", "舊人不了新人事，今日那知明日愁。", "一雁驚飛湘水浦，孤蟾空掛岳陽樓。", "江南總解單于曲，吹徹殘梅故國秋。"]'),
('7ba7bf86-eba9-47d7-9d69-76f3bcca573b','初秋雜興三首  其三','方一夔','宋','宋诗','song-poetry','','[]','田怕秋陽老怕貧，誰能骯髒拔風塵。',64,'全唐诗/poet.song.235000.json','["田怕秋陽老怕貧，誰能骯髒拔風塵。", "窮年兀坐少生計，末路相逢無故人。", "自愛漂摇棲倦翼，誰分浩蕩慰窮鱗。", "區區溫飽何須較，莫負秋來風月身。"]'),
('f3bf5721-8cc8-4614-8983-5b46ceaf7142','有懷洪復翁入郡城納金課','方一夔','宋','宋诗','song-poetry','','[]','故人東下濯滄浪，見說金沙作斗量。',64,'全唐诗/poet.song.235000.json','["故人東下濯滄浪，見說金沙作斗量。", "昔想萬錢還跨鶴，晚知六博亦亡羊。", "詩傳劍閣烟霞藁，地入桐廬雲水鄉。", "瀟灑滿懷無處着，歸程何况接新凉。"]'),
('680327a8-c69a-4f30-a12e-6a0104e12afa','雜興三首  其一','方一夔','宋','宋诗','song-poetry','','[]','老去時光漸不禁，那堪風景入秋深。',64,'全唐诗/poet.song.235000.json','["老去時光漸不禁，那堪風景入秋深。", "文章何啻建安骨，議論能無元祐心。", "舊日交遊誰可托，中年憂患苦相尋。", "致身稷契非輕許，末路無成學苦吟。"]'),
('25febbb8-7013-4fe0-a310-291802d0451e','雜興三首  其二','方一夔','宋','宋诗','song-poetry','','[]','做事英雄竟不成，飛鴻何處避弓矰。',64,'全唐诗/poet.song.235000.json','["做事英雄竟不成，飛鴻何處避弓矰。", "杲卿有舌駡阿犖，叔夜無頭傳廣陵。", "禍福難知隨命值，才名太盛取天憎。", "江流渺渺無回勢，獨向西風倚瘦藤。"]'),
('0416b0ec-df8e-4d46-8500-b2400408a6c7','雜興三首  其三','方一夔','宋','宋诗','song-poetry','','[]','窮守空山兩鬢蓬，老饕有分過年豐。',64,'全唐诗/poet.song.235000.json','["窮守空山兩鬢蓬，老饕有分過年豐。", "珠璣推上稻花水，金鐵敲殘梧葉風。", "興寄小窗詩卷裏，夢回別墅笛聲中。", "俗緣相逐何時了，一笑人間萬慮空。"]'),
('e0fcd952-87ba-4dd3-a1a7-0f452276c157','社日思家','方一夔','宋','宋诗','song-poetry','','[]','曉鼓鼕鼕露未收，老翁雞彘祝甌簍。',64,'全唐诗/poet.song.235000.json','["曉鼓鼕鼕露未收，老翁雞彘祝甌簍。", "家家酒綠枌榆社，處處霜紅柿栗秋。", "笑別比鄰包祭肉，醉呼童稚認歸牛。", "一年兩度村田樂，不羨人間萬戶侯。"]'),
('2e8c8bac-3336-4b1e-9b24-bdd7598dfb3e','晚秋','方一夔','宋','宋诗','song-poetry','','[]','蕭蕭兩鬢竟蒼然，況近重陽風雨天。',64,'全唐诗/poet.song.235000.json','["蕭蕭兩鬢竟蒼然，況近重陽風雨天。", "欲暝江村烟四起，漸寒山館客孤眠。", "葉題舊恨在何處，菊折寒香仍去年。", "爲憶故人三歎息，東籬沽酒已無錢。"]'),
('e7aac783-c20a-44b6-9fac-7f55ee93942f','菊','方一夔','宋','宋诗','song-poetry','','[]','矯首春風獨後時，冰霜自厲占東籬。',64,'全唐诗/poet.song.235000.json','["矯首春風獨後時，冰霜自厲占東籬。", "悲如屈子淒涼意，清似陶翁平澹詩。", "寂寞秋香憐向晚，徘徊寒蝶笑生遲。", "蹇予氣味差相似，采采金英盡一巵。"]'),
('f68892e5-a9f4-4a24-a07c-efb92599c52a','雜興四首  其一','方一夔','宋','宋诗','song-poetry','','[]','我亦山林澹蕩人，籠禽飲啄失天真。',64,'全唐诗/poet.song.235000.json','["我亦山林澹蕩人，籠禽飲啄失天真。", "客求妙墨多辭病，兒欠寒衣屢訴貧。", "夜雨書檠翻汗竹，秋風野飯配絲蓴。", "文章固是平生志，贏得蕭蕭兩鬢塵。"]'),
('e235988e-f5ae-4be4-81b2-d4abe6b2d2d3','雜興四首  其二','方一夔','宋','宋诗','song-poetry','','[]','江上千峯缺復遮，疎林點點噪歸鴉。',64,'全唐诗/poet.song.235000.json','["江上千峯缺復遮，疎林點點噪歸鴉。", "短篷細網船回浦，快馬青衫客到家。", "酒味春風生竹葉，笛愁寒月老梅花。", "丈夫處世便疎豁，莫買虛名鬭角蝸。"]'),
('06f091a8-e126-437c-8c3e-e68094b9754f','雜興四首  其三','方一夔','宋','宋诗','song-poetry','','[]','滿目風埃落日低，拳支醉頰面山西。',64,'全唐诗/poet.song.235000.json','["滿目風埃落日低，拳支醉頰面山西。", "平堤樹密欲藏寺，古渡舟橫不礙溪。", "渺渺幾竿秋水浄，啞啞三匝夜烏啼。", "老來獨有詩情在，口占新晴付小溪。"]'),
('51aacb9d-e4c1-43c2-ad1b-f353930b6e48','雜興四首  其四','方一夔','宋','宋诗','song-poetry','','[]','又是山村秋暮天，蹉跎身世惜流年。',64,'全唐诗/poet.song.235000.json','["又是山村秋暮天，蹉跎身世惜流年。", "風鳴淺瀨高還下，山碍浮雲斷復連。", "豪氣尚餘孤劍裏，眵眸合老短檠邊。", "心期蟠屈憑誰說，盡是巾箱千萬編。"]'),
('60c7a49e-ea15-42d1-97c7-b4f07e0a4b79','續遣瘧鬼','方一夔','宋','宋诗','song-poetry','','[]','老天難料倏炎凉，水帝遊魂未伏藏。',64,'全唐诗/poet.song.235000.json','["老天難料倏炎凉，水帝遊魂未伏藏。", "子喜朋儔饜口腹，我愁冰炭置肝腸。", "力持正論明無鬼，醉讀離騷祓不祥。", "惟有五窮推不去，主人改事屏車檣。"]'),
('cb18c030-9cf9-4ec0-8ae4-c7c0421db848','江村晚望','方一夔','宋','宋诗','song-poetry','','[]','江上孤村日欲斜，秋光淡淡渺天涯。',64,'全唐诗/poet.song.235000.json','["江上孤村日欲斜，秋光淡淡渺天涯。", "幾多田舍隠林薄，三兩漁舟出荻花。", "歸路負樵勞息樹，亂流浴馬怒噴沙。", "憑誰剪出機中素，圖入人間富貴家。"]'),
('6fd3993f-c121-4ac0-8198-fb389a6b38cb','春雪','方一夔','宋','宋诗','song-poetry','','[]','薝蔔林中忍辱仙，春來戲作散花天。',64,'全唐诗/poet.song.235000.json','["薝蔔林中忍辱仙，春來戲作散花天。", "曉山寒勁雲迷色，夜帳光生月鬭妍。", "北海無書羝不乳，朝陽有路馬難前。", "從知造物憎賢達，擁絮高吟更自憐。"]'),
('1a151ebf-b4e6-4cc1-add5-7fb417e966f6','雨霽二首  其一','方一夔','宋','宋诗','song-poetry','','[]','次第尋春不恨遲，春光偏在雨晴時。',64,'全唐诗/poet.song.235000.json','["次第尋春不恨遲，春光偏在雨晴時。", "風林竅暖山飛鳥，潭洞門開驚卧螭。", "酒冽萬家供笑語，土牛千耦樂耘耔。", "物華又逐年華轉，惟有詩人老更衰。"]'),
('cc2942a0-f0e9-44e7-9c55-d5d4d5ec8d39','雨霽二首  其二','方一夔','宋','宋诗','song-poetry','','[]','誰傳春漲沒溪毛，又喜朝晴暖土膏。',64,'全唐诗/poet.song.235000.json','["誰傳春漲沒溪毛，又喜朝晴暖土膏。", "箬裹旋生新接樹，花窠重發舊栽桃。", "掃蜂上篲經營早，通燕歸簾結構牢。", "莫道山中勳業少，等閒善類入鈞陶。"]'),
('a473c5e6-e17b-4ffb-b91f-d21e8c5f6a71','次韻胡柳塘夏自然春遊','方一夔','宋','宋诗','song-poetry','','[]','邂逅相逢玷俊遊，共臨清泚看橫舟。',64,'全唐诗/poet.song.235000.json','["邂逅相逢玷俊遊，共臨清泚看橫舟。", "野情瀟洒便僧寺，塵事囂煩遠市樓。", "倚杖有詩追和韻，折花隨酒記行籌。", "歸來散步斜陽下，休笑浮雲等幻漚。"]'),
('2aba0015-a12d-4ca2-aad0-534c8b013418','春日言懷','方一夔','宋','宋诗','song-poetry','','[]','睡覺東窗味正濃，鶑聲破曉入簾櫳。',64,'全唐诗/poet.song.235000.json','["睡覺東窗味正濃，鶑聲破曉入簾櫳。", "社前處處石泉水，春半時時花信風。", "交友如雲翻手散，浮華是夢轉頭空。", "癡兒不識愁滋味，笑折花枝滿把紅。"]'),
('732be1e9-a3dd-485d-a834-18b306bc4c41','大水','方一夔','宋','宋诗','song-poetry','','[]','長時烟雨弄梅黄，身似枯株守破窗。',64,'全唐诗/poet.song.235000.json','["長時烟雨弄梅黄，身似枯株守破窗。", "雲氣冒山天失晝，水聲撼屋浪翻江。", "田通小澗頻障土，船上高原屢徙樁。", "舉世滔滔何日息，笑傾牀下古罌缸。"]'),
('c01f3ed8-4b29-420e-b370-a7d7989a44b2','雜興五首  其一','方一夔','宋','宋诗','song-poetry','','[]','由來勢退不英雄，誰怨天公苦不公。',64,'全唐诗/poet.song.235000.json','["由來勢退不英雄，誰怨天公苦不公。", "蟲臂鼠肝俱造化，草妖木怪盡神通。", "百年身世浮漚裏，大地山河曠劫中。", "巧拙賢愚俱莫問，此生元只似虛空。"]'),
('1ccf4d08-7540-47e3-a128-8bf161ef65b8','雜興五首  其二','方一夔','宋','宋诗','song-poetry','','[]','老骨槎牙不入時，可看霜雪點鬚眉。',64,'全唐诗/poet.song.235000.json','["老骨槎牙不入時，可看霜雪點鬚眉。", "短披樵褐形如鶴，長把農書手欲龜。", "饑飽生前皆有定，文章死後竟何禆。", "憑高欲說無人會，早暮南窗盼綠猗。"]'),
('287af796-90f1-4a1e-a2fa-d78825f3d346','雜興五首  其三','方一夔','宋','宋诗','song-poetry','','[]','冷看風濤起怒鵬，自慚無力逐飛騰。',64,'全唐诗/poet.song.235000.json','["冷看風濤起怒鵬，自慚無力逐飛騰。", "林泉襟韻清如水，儒素門牆淡似僧。", "凉與竹奴分半榻，夜將書嬭伴孤燈。", "人生適意祇如許，玉署金門不用登。"]'),
('19ef7265-4004-4115-b018-e4819b9fb003','雜興五首  其四','方一夔','宋','宋诗','song-poetry','','[]','六月猶披紫綺裘，酸醎世味不相投。',64,'全唐诗/poet.song.235000.json','["六月猶披紫綺裘，酸醎世味不相投。", "清泉遶屋聲聲冷，高竹依簷葉葉秋。", "揮汗讀書如有慕，撚髭安字更何求。", "向無二事消閒日，誰遣先生一段愁。"]'),
('8c688deb-94be-441f-a797-b08196cebc44','雜興五首  其五','方一夔','宋','宋诗','song-poetry','','[]','甘死蓬窗笑我癡，興來况值夜凉時。',64,'全唐诗/poet.song.235000.json','["甘死蓬窗笑我癡，興來况值夜凉時。", "閒中不覺年華促，歸去方知宦路危。", "酒甕沉沉傾玉瀣，簟筠細細蹙風漪。", "月殘夢醒詩初就，枯筆長拋網蟢絲。"]'),
('f56551b5-0d30-4de6-826f-33953a92dfa2','蓮花','方一夔','宋','宋诗','song-poetry','','[]','水仙微步碧玻璃，家在湘湖西復西。',64,'全唐诗/poet.song.235000.json','["水仙微步碧玻璃，家在湘湖西復西。", "清欲濯纓長在水，妙曾斲鼻不污泥。", "已知浄社曾參問，合是濂溪善品題。", "欲採遠香無覓處，拏舟驚起兩鳧鷖。"]'),
('946e727b-f961-482d-b2cd-afa0292eece6','府城別任惠叔表兄','方一夔','宋','宋诗','song-poetry','','[]','乘興來爲兩月留，廿年蹤跡歎萍浮。',64,'全唐诗/poet.song.235000.json','["乘興來爲兩月留，廿年蹤跡歎萍浮。", "銜杯清話燈前雨，對榻羈魂枕上秋。", "倦矣悲鳴雙客鳥，歸歟浩蕩一漁舟。", "吟邊若值孤飛雁，頻寄新詩慰別愁。"]'),
('c9c83a65-0f91-4cc4-ae10-70b7c111f927','雪','方一夔','宋','宋诗','song-poetry','','[]','北帝宮中億萬姝，天花散盡滿天衢。',64,'全唐诗/poet.song.235000.json','["北帝宮中億萬姝，天花散盡滿天衢。", "蓬山宮闕白禽獸，秦地山河銀雁鳬。", "寒聳吟肩呵滴硯，春回醉頰宴開爐。", "梅花半樹南枝早，夢遶孤山訪老逋。"]'),
('87121038-366b-42d1-b01d-a26f563e744e','王古樵觀予苦瘡鄙句遂自賦眉遭二韻各二首因次其韻爲戲  其一','方一夔','宋','宋诗','song-poetry','','[]','老去瘡殘擬炙眉，暫憑酒力引風巵。',64,'全唐诗/poet.song.235000.json','["老去瘡殘擬炙眉，暫憑酒力引風巵。", "久疎朋友慙多病，薄買田園費學醫。", "吟罷肩寒生軫粟，坐來形槁似枯梨。", "浮生自笑多磨障，畫癖書癡發舊痍。"]'),
('951ba3e0-999e-4220-93e3-bab5d5cd0ab9','王古樵觀予苦瘡鄙句遂自賦眉遭二韻各二首因次其韻爲戲  其二','方一夔','宋','宋诗','song-poetry','','[]','吾衰端不爲蛾眉，不假霜鉛補漏巵。',64,'全唐诗/poet.song.235000.json','["吾衰端不爲蛾眉，不假霜鉛補漏巵。", "無恙感君頻寄語，不龜媿我未逢醫。", "命窮漸退星臨木，書悞無憑病發梨。", "康濟自身猶未辨，敢將蘇息問民痍。"]'),
('bde68452-ac2d-45b8-a997-cbb1850cdf62','王古樵觀予苦瘡鄙句遂自賦眉遭二韻各二首因次其韻爲戲  其三','方一夔','宋','宋诗','song-poetry','','[]','無端痁疥適相遭，空苦無成似嚼螯。',64,'全唐诗/poet.song.235000.json','["無端痁疥適相遭，空苦無成似嚼螯。", "瘢疻着身猶刻畫，垢腥滿爪費爬搔。", "行吟謾想歌愁絕，坐食空慚飽老饕。", "偶見新詩還技癢，寒窗細字認牛毛。"]'),
('ead58f9e-1a50-4710-a9b9-2cc6743fd190','王古樵觀予苦瘡鄙句遂自賦眉遭二韻各二首因次其韻爲戲  其四','方一夔','宋','宋诗','song-poetry','','[]','命災况復與窮遭，真似蟛蜞縛兩螯。',64,'全唐诗/poet.song.235000.json','["命災况復與窮遭，真似蟛蜞縛兩螯。", "鱗甲稜稜便浄浴，髮鬚種種快頻搔。", "甕頭轑酒何妨醉，松下餐肪不厭饕。", "快寫田家剜肉句，夜闌禿盡管城毛。"]'),
('3132704a-4417-4cd5-b9e0-610512042e83','田家  其一','方一夔','宋','宋诗','song-poetry','','[]','近來不復應差科，生計無成奈老何。',64,'全唐诗/poet.song.235000.json','["近來不復應差科，生計無成奈老何。", "漆種十年雖恨晚，牛生百犢未嫌多。", "春耕着我扶犁手，社飲還渠擊壤歌。", "聞道溪頭新長水，偷閒試着舊漁簑。"]'),
('7c80c711-b440-4755-9ed1-b9e2e73f6342','田家  其二','方一夔','宋','宋诗','song-poetry','','[]','數間茅屋占林塘，二頃田園幸未荒。',64,'全唐诗/poet.song.235000.json','["數間茅屋占林塘，二頃田園幸未荒。", "蒿葉正長蠶卧起，鶑聲漸老麥青黄。", "壁間龍骨流泉活，筐載豚蹄白酒香。", "春事年年閒過去，欲將擁腫問庚桑。"]'),
('467b5c34-874a-4b3b-928a-f0181f40e963','秋晚雜興','方一夔','宋','宋诗','song-poetry','','[]','暫憑高處豁雙明，獨上譙樓倚晚晴。',64,'全唐诗/poet.song.235000.json','["暫憑高處豁雙明，獨上譙樓倚晚晴。", "烟岫齊紈千萬疊，落梅羌管兩三聲。", "秋風世路客凄楚，流水年光獨老成。", "吟興未如歸興切，蕭蕭落葉滿山城。"]'),
('5809c593-3775-404a-b389-c0e72eec0469','題洪復翁詩卷後二首  其一','方一夔','宋','宋诗','song-poetry','','[]','袖中光燄照崖垠，詩律雄渾遠有源。',64,'全唐诗/poet.song.235000.json','["袖中光燄照崖垠，詩律雄渾遠有源。", "近藁自成新句法，束書不叛舊遊門。", "折芳梅下人雙屨，話別沙頭酒一罇。", "健筆世間誰措手，老夫先擬舉降幡。"]'),
('7e3e393d-affe-4c15-81d8-dfb3ab186ae5','題洪復翁詩卷後二首  其二','方一夔','宋','宋诗','song-poetry','','[]','詩裏人傳大小賢，自憐同業不同年。',64,'全唐诗/poet.song.235000.json','["詩裏人傳大小賢，自憐同業不同年。", "白雲孺子詩千首，黄石老人書一編。", "冷眼危途風竹亂，知心舊事雪松堅。", "別愁去作星橋夢，長傍河西牛斗邊。"]'),
('4071beed-aec3-4294-885c-3b91c22c3e2a','春晚雜興四首  其一','方一夔','宋','宋诗','song-poetry','','[]','未妨行樂少年場，倚徙東風醉一觴。',64,'全唐诗/poet.song.235000.json','["未妨行樂少年場，倚徙東風醉一觴。", "芳樹染成啼血艷，落花流出漲痕香。", "陰陰春色和天老，脈脈愁情共水長。", "坐閲流年能幾見，菱花應笑鬢邊霜。"]'),
('f97e2a04-acbb-4d65-8ad9-7a0510993aba','春晚雜興四首  其二','方一夔','宋','宋诗','song-poetry','','[]','懶向風軒掃落花，暮年情態惜韶華。',64,'全唐诗/poet.song.235000.json','["懶向風軒掃落花，暮年情態惜韶華。", "春盤脆響供雷笋，夜焙芳蘚摘露芽。", "蠶老住眠催作繭，燕來新乳賀成家。", "狂遊無復少年夢，聊遣清吟送日斜。"]'),
('f620bef1-6cc9-4a3c-8009-4e8096dc35fc','春晚雜興四首  其三','方一夔','宋','宋诗','song-poetry','','[]','花神衣補去青宮，紫陣紅圍一夜空。',64,'全唐诗/poet.song.235000.json','["花神衣補去青宮，紫陣紅圍一夜空。", "華髮龍鍾寒食酒，青蕪狼藉落花風。", "雨聲點滴春愁裏，世態侵尋客路中。", "我欲憑高寄蕭散，暫舒老眼數歸鴻。"]'),
('5b546303-e0b6-4924-813b-0225f96d9f55','春晚雜興四首  其四','方一夔','宋','宋诗','song-poetry','','[]','欲逐芳菲寄病身，鶑花不管老年人。',64,'全唐诗/poet.song.235000.json','["欲逐芳菲寄病身，鶑花不管老年人。", "幽尋但見肥牛地，勝賞難追駿馬塵。", "薄酒似餳聊取醉，青梅如豆正嘗新。", "清歡未足還休去，日落汀洲又暮春。"]'),
('ea5b2310-503a-4eda-8433-c382345b07ab','挽尚書先生','方一夔','宋','宋诗','song-poetry','','[]','前代衣冠第一人，老來鳴道振遺音。',64,'全唐诗/poet.song.235000.json','["前代衣冠第一人，老來鳴道振遺音。", "勳庸臣子平生志，書易聖賢千古心。", "士願執經來鹿洞，客求挾冊售鷄林。", "飛仙雖去斯文在，山閣神光照斗參。"]'),
('f150a438-190f-4b46-bc65-3486699c0099','食菜','方一夔','宋','宋诗','song-poetry','','[]','日食何曾費萬錢，畦丁辛苦劚風烟。',64,'全唐诗/poet.song.235000.json','["日食何曾費萬錢，畦丁辛苦劚風烟。", "牆陰吠狗硬如鐵，山下蹲鴟大似拳。", "忍棄毛錐飛食肉，空憐匿服卧餐氈。", "茶甌氣味堪相配，更汲源頭活水煎。"]'),
('948865ef-8e98-43d9-85bd-bbb5dbaafd28','梅後久雨','方一夔','宋','宋诗','song-poetry','','[]','自入梅天氣力微，不堪暑濕互蒸炊。',64,'全唐诗/poet.song.235000.json','["自入梅天氣力微，不堪暑濕互蒸炊。", "鬢邊衰白三千丈，雨後昏黄十二時。", "積潤圖書供火焙，新裁羅褐覆香匜。", "小占定有朝晴喜，忽聽黄鶑語柳枝。"]'),
('1378a090-6ec5-48ee-9abd-4a0edb73ba4b','田家雜興三首  其一','方一夔','宋','宋诗','song-poetry','','[]','樵路通村暗蒺藜，數椽茅蕝護疎籬。',64,'全唐诗/poet.song.235000.json','["樵路通村暗蒺藜，數椽茅蕝護疎籬。", "陰陰清樾風生樹，拍拍蒼鵝水滿陂。", "記日旋鋤燒地粟，上時新賣落車絲。", "晚晴慙愧逢端午，醉卧黄昏自不知。"]'),
('3882dfda-ee4e-485e-9981-e16708c74afd','田家雜興三首  其二','方一夔','宋','宋诗','song-poetry','','[]','兩兩蒼髯笑杖藜，蒨裙兒女隔笆籬。',64,'全唐诗/poet.song.235000.json','["兩兩蒼髯笑杖藜，蒨裙兒女隔笆籬。", "斜陽鴉噪燒錢社，細雨牛眠放牧陂。", "酒熟十千沽玉瀣，麫香三丈捲銀絲。", "客來偶及興亡事，說與衰翁也自知。"]'),
('5d73763e-fd91-42d1-946e-8ea6bc47dee1','田家雜興三首  其三','方一夔','宋','宋诗','song-poetry','','[]','不嫌飯豆與蒸藜，飽脫衣衫掛竹籬。',64,'全唐诗/poet.song.235000.json','["不嫌飯豆與蒸藜，飽脫衣衫掛竹籬。", "問酒亭前旗影市，繫船屋角藕花陂。", "踏車掛壁閒龍骨，生藥當庭蔓兔絲。", "我自耦耕非避世，姓名休使外人知。"]'),
('aaa38ced-8f60-4097-b38a-dc74f6850ea3','四時宮詞  其一','方一夔','宋','宋诗','song-poetry','','[]','陽和不解徧深宮，黯黯春愁佇立中。',64,'全唐诗/poet.song.235000.json','["陽和不解徧深宮，黯黯春愁佇立中。", "歲給買花藏笥篋，夕香拜月散簾櫳。", "鏤金巧勝勻如剪，縐縠中單薄似空。", "一曲紫簫吹徹後，薔薇幾度老春風。"]'),
('26b0278b-9493-4ac4-bfa0-b3ec6dd6696f','四時宮詞  其二','方一夔','宋','宋诗','song-poetry','','[]','披香簾捲幾斜暉，別殿承恩似覺稀。',64,'全唐诗/poet.song.235000.json','["披香簾捲幾斜暉，別殿承恩似覺稀。", "風蘤影摇陰欲轉，露蟬聲徹暑猶微。", "肉痕淺印丹砂血，手跡新裁白紵衣。", "例賜扇紈長棄却，雙雙羞看綵鸞飛。"]'),
('dc838c78-21c0-442f-bef9-f676e19781eb','四時宮詞  其三','方一夔','宋','宋诗','song-poetry','','[]','七夕閒登乞巧樓，屬車隠隠認宸遊。',64,'全唐诗/poet.song.235000.json','["七夕閒登乞巧樓，屬車隠隠認宸遊。", "幾行宮樹女牆月，一闋庭花御苑秋。", "戲展花牋圖蛺蝶，强拈綵綫候牽牛。", "轆轤聲斷屏山冷，一夜寒蛩替說愁。"]'),
('6a557621-e39f-4bee-a5ed-37eee3564322','四時宮詞  其四','方一夔','宋','宋诗','song-poetry','','[]','手撚梅花暗斷魂，十年柘館未承恩。',64,'全唐诗/poet.song.235000.json','["手撚梅花暗斷魂，十年柘館未承恩。", "曾催奏曲臨粧閣，暫出行香到寢園。", "月照金鋪關永夜，雪浮銀礫耿黄昏。", "并州剪就釵梁燕，又逐年華作上元。"]'),
('30c74429-d01c-4cb7-9870-4f9a0db436d2','避暑夜坐  其一','方一夔','宋','宋诗','song-poetry','','[]','一跌風波困敗鱗，年來是事不如人。',64,'全唐诗/poet.song.235000.json','["一跌風波困敗鱗，年來是事不如人。", "醉吹羌管驚棲鳥，閒倚胡牀閣病身。", "安得旃檀除熱惱，自將紈扇障風塵。", "新凉漸近渺雲水，分席鷗羣占白蘋。"]'),
('0e8fb70a-4f14-48db-9226-0827198e9e7a','避暑夜坐  其二','方一夔','宋','宋诗','song-poetry','','[]','北窗幽絕夢初圓，一葉秋聲醒客眠。',64,'全唐诗/poet.song.235000.json','["北窗幽絕夢初圓，一葉秋聲醒客眠。", "雌霓半空收暮雨，杜鵑六月熟高田。", "稻陂別注魚池水，石洞分承茗鼎泉。", "聊借舊書棲舊隠，夜凉新入短檠邊。"]'),
('86653629-f10e-4a55-ba7c-425207fe98a3','遊南山天寧寺','方一夔','宋','宋诗','song-poetry','','[]','客裏塵騑未着鞭，短篷送我訪幽禪。',64,'全唐诗/poet.song.235000.json','["客裏塵騑未着鞭，短篷送我訪幽禪。", "橫空雲冒臨江寺，夾岸山隨下瀨船。", "謾借一觴追勝概，暫分半日洗塵緣。", "城頭梅角聲孤起，掉首空歸又晚天。"]'),
('a75478ff-1d5e-4cd5-8c3d-97676832bb06','送客出城','方一夔','宋','宋诗','song-poetry','','[]','逐逐區中未了緣，此生飄泊是年年。',64,'全唐诗/poet.song.235000.json','["逐逐區中未了緣，此生飄泊是年年。", "片時枕上思歸夢，萬里江頭送別船。", "寒角吹殘低戍火，暮鴉衝斷遠村烟。", "我行在處成詩話，點化塵凡即是仙。"]'),
('a9c8b606-9a40-4079-ba75-07898eccbac7','過耜巖先師墓','方一夔','宋','宋诗','song-poetry','','[]','取數多時物所嫌，有才無命恨難全。',64,'全唐诗/poet.song.235000.json','["取數多時物所嫌，有才無命恨難全。", "縱橫雖掃三千字，富貴纔終五十年。", "幸有菟裘棲舊隠，愧無雞絮酹新阡。", "茫茫大塊誰能料，狐老成精鼠化仙。"]'),
('c41a777f-874d-444d-938c-aba9ff50331f','即事','方一夔','宋','宋诗','song-poetry','','[]','紛紛寵辱幾時休，朝上青雲暮作囚。',64,'全唐诗/poet.song.235000.json','["紛紛寵辱幾時休，朝上青雲暮作囚。", "能可將軍宿亭下，不堪廷尉望山頭。", "浮雲過眼難摶控，世事冥心任去留。", "涅亦不緇磨不磷，至今遺教首軻邱。"]'),
('8da2fdc9-ea91-4530-9c9c-b016496baea0','送人赴學官二首  其一','方一夔','宋','宋诗','song-poetry','','[]','生平講貫爲知幾，世好從渠與我違。',64,'全唐诗/poet.song.235000.json','["生平講貫爲知幾，世好從渠與我違。", "天下無如書益智，人生惟有仕當歸。", "青燈夜雨蟲魚註，碧水西風鱸鱠肥。", "莫道尺前難寸退，古來富貴觸危機。"]'),
('2db49218-1466-4a0a-9534-02f427a426ad','送人赴學官二首  其二','方一夔','宋','宋诗','song-poetry','','[]','清時巖穴下弓旌，儒館翹才盡至公。',64,'全唐诗/poet.song.235000.json','["清時巖穴下弓旌，儒館翹才盡至公。", "詩記行程囊古錦，劍裝新飾𩍐花驄。", "莫因貴宦負遠志，當爲饑民念鞠躬。", "欲問故人在何處，舊山桂樹正叢叢。"]'),
('ad052d28-b721-43f5-98de-3e8764d8cb1f','初夏雜興四首  其一','方一夔','宋','宋诗','song-poetry','','[]','肥梅貼暈麥摇芒，四月山居取次凉。',64,'全唐诗/poet.song.235000.json','["肥梅貼暈麥摇芒，四月山居取次凉。", "古砌月鋪銅沓冒，寒松風撼鐵琅當。", "兒孫猶有將軍臭，廝役空知太尉香。", "有客縱談當世事，薜蘿深處更移牀。"]'),
('a4b1c2ef-9c80-42e1-8e4b-f0fbff8f7a59','初夏雜興四首  其二','方一夔','宋','宋诗','song-poetry','','[]','天氣如秋意轉闌，高樓簟枕带餘寒。',64,'全唐诗/poet.song.235000.json','["天氣如秋意轉闌，高樓簟枕带餘寒。", "楝花零落魚初發，梅子青黄雨不乾。", "客怕遠行催早宿，農逢小熟勸加餐。", "近來悍吏經過少，更喜深山好長官。"]'),
('f11bd7fb-1c1c-4dbc-8494-e267a66789a1','初夏雜興四首  其三','方一夔','宋','宋诗','song-poetry','','[]','作計吟詩逐故貧，欺人鬼子轉情親。',64,'全唐诗/poet.song.235000.json','["作計吟詩逐故貧，欺人鬼子轉情親。", "案頭日飲三升墨，鐺底時空五合陳。", "燒麥旋教供野飯，貫楊準擬買溪鱗。", "蘇君端爲無田出，近日田多更累人。"]'),
('082cb37d-ac3e-4df7-b9e6-612a8bc33b44','初夏雜興四首  其四','方一夔','宋','宋诗','song-poetry','','[]','雨打梅頭麥半枯，出門步步困泥塗。',64,'全唐诗/poet.song.235000.json','["雨打梅頭麥半枯，出門步步困泥塗。", "世情何但惡溪惡，野性聊同愚谷愚。", "兒可讀書供日課，婦如有酒待時須。", "興來方試吟詩筆，西舍催錢吏索租。"]'),
('09d827e1-92bd-4bbe-b25e-44a6bded7f22','重午二首  其一','方一夔','宋','宋诗','song-poetry','','[]','畫鷁鳴鼉水滿湖，千年遺恨渺平蕪。',64,'全唐诗/poet.song.235000.json','["畫鷁鳴鼉水滿湖，千年遺恨渺平蕪。", "纍臣水底沉魚冢，玉女釵頭綴虎符。", "雙鬢點斑羞綠艾，一樽凝碧怯香蒲。", "楚鄉舊俗生悽愴，愧殺人間懦丈夫。"]'),
('e7ce0585-abb0-427d-b461-04b649a2ce88','重午二首  其二','方一夔','宋','宋诗','song-poetry','','[]','苦瘡戰馬倦風沙，伏櫪無心萬里賒。',64,'全唐诗/poet.song.235000.json','["苦瘡戰馬倦風沙，伏櫪無心萬里賒。", "老去手風從婦展，愁來背癢倩兒爬。", "人情反覆好生羽，世味差殊嗜食痂。", "一卷方書初讀罷，小窗驚怪日西斜。"]'),
('6b5f79b9-4782-473b-9afd-916defef7dac','觀物','方一夔','宋','宋诗','song-poetry','','[]','靜中羣動互飛奔，擾擾誰能脫世塵。',64,'全唐诗/poet.song.235000.json','["靜中羣動互飛奔，擾擾誰能脫世塵。", "蠅虎案頭新得雋，螳蜋枝上忽忘身。", "平生攻苦味無味，舉世爭雄人食人。", "安得洗心無一物，碧波鷗鳥自相親。"]'),
('f8f50a7d-e817-40ec-b0c9-74d1ae47e9f2','仁甫次弟余韻','方一夔','宋','宋诗','song-poetry','','[]','造物兒戲多猜嫌，百年醜好兩能全。',64,'全唐诗/poet.song.235000.json','["造物兒戲多猜嫌，百年醜好兩能全。", "眠牛纔封一抔土，鶴歸已怪三千年。", "樂天永歎北邙冢，后山慟哭南陽阡。", "從來賢達總如此，誰能羽化隨飛仙。"]'),
('bfb1d3b8-c36d-4426-81f7-0f17e1b0a774','秋興二首  其一','方一夔','宋','宋诗','song-poetry','','[]','水花風葉亂蕭蕭，凉入秋衣怯寂寥。',64,'全唐诗/poet.song.235000.json','["水花風葉亂蕭蕭，凉入秋衣怯寂寥。", "桑落寒香初出市，蓼花新漲欲平橋。", "半篷烟雨漁家傲，匹馬關山客路遥。", "拍手西風無一事，未妨橫笛向耕樵。"]'),
('348a9ef2-8246-48db-9621-80dbc21011f1','秋興二首  其二','方一夔','宋','宋诗','song-poetry','','[]','不堪老病縛閒身，面目崢嶸歲月新。',64,'全唐诗/poet.song.235000.json','["不堪老病縛閒身，面目崢嶸歲月新。", "半世畧無如意事，五年慣作在家貧。", "悠悠懷抱希知我，詡詡交遊喜負人。", "俯仰世情都勘破，西風獨立岸綸巾。"]'),
('d77a2769-4d76-4f6b-9b4b-e3e5c3a6f53a','夜坐','方一夔','宋','宋诗','song-poetry','','[]','全家久住白雲窩，貪看疎梅夜景多。',64,'全唐诗/poet.song.235000.json','["全家久住白雲窩，貪看疎梅夜景多。", "簾角花陰和月捲，墨池水凍带冰磨。", "寒欺駝褐吟肩聳，暖入鵝黄醉面酡。", "笑挹暗香人不寐，不辭百匝繞前坡。"]'),
('9de2da3f-771e-44d6-a339-9a4d2c41d519','寄何稼隠','方一夔','宋','宋诗','song-poetry','','[]','欲出孤雲意已闌，東風吹夢落東安。',64,'全唐诗/poet.song.235000.json','["欲出孤雲意已闌，東風吹夢落東安。", "燈前鄉國千山隔，窗外乾坤一面寬。", "放馬脫韁嘶曉岸，連檣牽索上晴灘。", "闌干倚遍空相憶，花落芳洲春半殘。"]'),
('82d75183-bd8c-41b9-be13-eb8ad6dbebbd','沃祥卿和前韻見寄再和答之','方一夔','宋','宋诗','song-poetry','','[]','西轉東移客興闌，風枝驚鵲不曾安。',64,'全唐诗/poet.song.235000.json','["西轉東移客興闌，風枝驚鵲不曾安。", "孤吟愧我詩筒澀，百罰憐君酒令寬。", "西閣梅林迷雨浦，畫橋松韻接寒灘。", "相思一夜知何處，夢醒樓頭鐘欲殘。"]'),
('8b410864-ece7-4e44-9807-a9c9c438d209','次韻徐子聲采桑','方一夔','宋','宋诗','song-poetry','','[]','喚起飛來說曉晴，先生無處問歸津。',64,'全唐诗/poet.song.235000.json','["喚起飛來說曉晴，先生無處問歸津。", "轉頭歲月如流水，滿眼交遊少故人。", "槲葉老樵擔玉束，菜花飛蝶護香塵。", "隔溪綠暗歌聲杳，點點青山入夢頻。"]'),
('1333ba9c-4d54-4ff6-abc5-e5de1b472408','送春','方一夔','宋','宋诗','song-poetry','','[]','春從此去不躊躇，渺渺寒波接碧蕪。',64,'全唐诗/poet.song.235000.json','["春從此去不躊躇，渺渺寒波接碧蕪。", "想逐風帆歸閬苑，又傳雲馭赴遮須。", "此生歲月隨泡影，末路功名等雉盧。", "歸向西窗聽幽弄，一樽濁酒對提壺。"]'),
('b9331fdf-6c6a-447a-9bbf-72965b3c8a74','憶復翁','方一夔','宋','宋诗','song-poetry','','[]','垂楊渡口小舟橫，我涉清溪君獨行。',64,'全唐诗/poet.song.235000.json','["垂楊渡口小舟橫，我涉清溪君獨行。", "未許馬羣空冀北，自憐墨派過彭城。", "鱗鴻乏便書難到，蝴蝶無情夢不成。", "可是孤吟清絕處，高山誰識斷腸聲。"]'),
('040065e6-285c-4ff5-a906-658739d22050','溪上','方一夔','宋','宋诗','song-poetry','','[]','古木陰陰溪上村，隔溪呼喚隔溪應。',64,'全唐诗/poet.song.235000.json','["古木陰陰溪上村，隔溪呼喚隔溪應。", "柳邊漁艇水雙港，山崦人家雲半層。", "早麥熟隨芹菜餉，晚茶香和樹芽蒸。", "自慚未得亢桑樂，癡坐寒窗似凍蠅。"]'),
('2dff47c7-574f-4a93-a6e5-5f167304038a','雜興','方一夔','宋','宋诗','song-poetry','','[]','溪上寒窗面綠漪，孤蹤漂泊渺天涯。',64,'全唐诗/poet.song.235000.json','["溪上寒窗面綠漪，孤蹤漂泊渺天涯。", "愁聽火令拋長檠，醉折花籌記小詩。", "鶑語難尋春去處，鄉心偏等夢回時。", "文章滿腹知何用，落得奔波兩鬢絲。"]'),
('1cca7347-80c1-48f4-b64e-5cf7505537df','重午','方一夔','宋','宋诗','song-poetry','','[]','楚鄉節物又今朝，老大催人不肯饒。',64,'全唐诗/poet.song.235000.json','["楚鄉節物又今朝，老大催人不肯饒。", "歲久菖花初見面，病多艾葉已盈腰。", "浪濤何處尋沉魄，菰黍無心逐畫橈。", "莫到獨醒空過了，旗亭風急又相招。"]'),
('3e6db230-a62e-440f-8d60-30dac454df18','次韻稼隠上徐雲岫喜復貢舉','方一夔','宋','宋诗','song-poetry','','[]','天闕誰推破旱雷，蟻封鼠壤一時開。',64,'全唐诗/poet.song.235000.json','["天闕誰推破旱雷，蟻封鼠壤一時開。", "雲飛遠岫無心出，春逐行人有脚來。", "桂窟舊遊空雨露，棘闈前度沒蒿萊。", "短衣儻逐前麾去，解向淮頭破賊回。"]'),
('7db15aeb-5c87-411f-9062-4c51844ae8dc','沃祥卿次前韻見寄和以答之','方一夔','宋','宋诗','song-poetry','','[]','羨君古洗刻雲雷，苞裹珍奇祕不開。',64,'全唐诗/poet.song.235000.json','["羨君古洗刻雲雷，苞裹珍奇祕不開。", "亭枕寒流隨浪動，樓橫空翠約雲來。", "吟箋題滿投囊賀，壽斝光浮戲綵萊。", "欲洗炎埃無處所，玉梅泉下日千回。"]'),
('64a359a2-c5b5-4098-bc48-3d544838be8e','次韻通甫喜復貢舉','方一夔','宋','宋诗','song-poetry','','[]','當年塗抹笑東施，羣動儇儇各自飛。',64,'全唐诗/poet.song.235000.json','["當年塗抹笑東施，羣動儇儇各自飛。", "不分前程移岸谷，至今遺恨滿庭闈。", "文章老去攻詩律，富貴年來發禍機。", "世上英雄君與操，誰甘終老故山歸。"]'),
('a34404dc-73db-44af-bc44-10f2b69f1812','秋興','方一夔','宋','宋诗','song-poetry','','[]','笑呼筇竹過溪東，摵摵秋聲到井桐。',64,'全唐诗/poet.song.235000.json','["笑呼筇竹過溪東，摵摵秋聲到井桐。", "落日遠山疑有雨，孤村古樹欲攢空。", "貪嘶馬飽銜花草，趁食魚肥墮水蟲。", "歸對書檠人不寐，鄉愁怕入夢魂中。"]'),
('9f4d2d0a-faa4-4139-8bb5-d7484d7b28e8','木犀  其一','方一夔','宋','宋诗','song-poetry','','[]','下土花中第一流，移根自笑此生浮。',64,'全唐诗/poet.song.235000.json','["下土花中第一流，移根自笑此生浮。", "獨依上界清虛府，滿貯青冥沆瀣秋。", "稜葉風翻低散亂，蒼皮蟲蝕老雕鎪。", "醉來徑向高寒處，自駕青鸞擁玉虬。"]'),
('c417511e-eff1-4f59-9170-5f4d5fa8afdd','木犀  其二','方一夔','宋','宋诗','song-poetry','','[]','蒼蒼珠樹俯寒流，析木津頭戲拍浮。',64,'全唐诗/poet.song.235000.json','["蒼蒼珠樹俯寒流，析木津頭戲拍浮。", "褐鳳摶風朝紫極，硯蟾滴露寫清秋。", "返魂香倩羅裳貯，碍月枝憑玉斧鎪。", "夜景未闌清入骨，蕭蕭鱗甲卧癡虬。"]'),
('1cbed898-ff8d-434e-8c92-63caff773cec','木犀  其三','方一夔','宋','宋诗','song-poetry','','[]','綠衣年少正風流，手折高枝喜氣浮。',64,'全唐诗/poet.song.235000.json','["綠衣年少正風流，手折高枝喜氣浮。", "三樹獨標仙窟種，四花分占玉壺秋。", "濃薰藥杵長舂搗，清逼詩肝巧斲鎪。", "世上紅兒那可比，試將此句問羅虬。"]'),
('5fd39119-8736-4a49-a36f-e02d783cfe41','食西瓜','方一夔','宋','宋诗','song-poetry','','[]','恨無纖手削駝峯，醉嚼寒瓜一百筩。',64,'全唐诗/poet.song.235000.json','["恨無纖手削駝峯，醉嚼寒瓜一百筩。", "半嶺花衫粘唾碧，一痕丹血搯膚紅。", "香浮笑語牙生水，凉入衣襟骨有風。", "從此安心師老圃，青門何處問窮通。"]'),
('3a0a900d-ff4a-4d45-9950-9483a2cbed61','景德觀陳道士圃多菊覓其種栽並寄以詩','方一夔','宋','宋诗','song-poetry','','[]','愛藥仙人醉不歸，秋光次第入玄都。',64,'全唐诗/poet.song.235000.json','["愛藥仙人醉不歸，秋光次第入玄都。", "蝶隨露蘤移花墢，風逼寒香落酒壺。", "老去君方空結習，興來我欲劚荒蕪。", "和篇應與花俱到，換得驪龍百斛珠。"]'),
('8d9f5e18-97d0-420b-9459-39f73b4fa253','送吳友直過吳門省親','方一夔','宋','宋诗','song-poetry','','[]','海闊天南不盡頭，雁來豈爲稻粱謀。',64,'全唐诗/poet.song.235000.json','["海闊天南不盡頭，雁來豈爲稻粱謀。", "飄零骨肉憐杯酒，老病形骸戀破裘。", "日暮片雲勞望眼，天寒孤棹發行舟。", "十年冷落江鄉夢，願借西風過橘州。"]'),
('e7a3b144-4578-45fc-8b53-68c69213f5b3','次韻雪岡徐景星二首  其一','方一夔','宋','宋诗','song-poetry','','[]','阿咸秀出竹林邊，千古風流有此賢。',64,'全唐诗/poet.song.235000.json','["阿咸秀出竹林邊，千古風流有此賢。", "獨向詩盟參古律，不隨世態異憎憐。", "夜光照耀需他日，汗血奔騰出少年。", "乞我飛霞與青玉，夜深環珮韻璆然。"]'),
('d4770080-62de-4034-8855-97cba0d2ac7a','次韻雪岡徐景星二首  其二','方一夔','宋','宋诗','song-poetry','','[]','窮腹便便詫老邊，敢將文字壓前賢。',64,'全唐诗/poet.song.235000.json','["窮腹便便詫老邊，敢將文字壓前賢。", "愁懷不作功名想，衰鬢從教兒女憐。", "客路知心惟有月，書燈話舊更何年。", "欲投名字來吟社，已濕寒灰不復然。"]'),
('164e26e1-c67a-4592-bf98-080c5d43f28c','今歲吾鄉頗稔而收成值雨夜坐有懷二首  其一','方一夔','宋','宋诗','song-poetry','','[]','千步平場築杵齊，西風墟落轉凄迷。',64,'全唐诗/poet.song.235000.json','["千步平場築杵齊，西風墟落轉凄迷。", "要教歲計收霜稻，不分時長弄雨粞。", "曩祝汙邪酬願望，近居畏壘費推擠。", "先生莫戀無錢飯，定把長鑱理舊畦。"]'),
('f723a43e-981a-47d6-92b5-0bc164db8cdd','今歲吾鄉頗稔而收成值雨夜坐有懷二首  其二','方一夔','宋','宋诗','song-poetry','','[]','蕭蕭疎雨未調霜，空向寒階滴夜長。',64,'全唐诗/poet.song.235000.json','["蕭蕭疎雨未調霜，空向寒階滴夜長。", "風激木圍如撼枕，蟲號土穴欲扶牀。", "蟻傾清濁香浮甕，蠏劈尖圓黄戴筐。", "獨背殘燈眠未穩，夢尋歸路到枌鄉。"]'),
('fd59881c-2102-4d2a-87d9-4c6962e30b49','次韻陳道士和徐星韻見寄  其一','方一夔','宋','宋诗','song-poetry','','[]','寄跡琳宮絳闕邊，聚星家世楚先賢。',64,'全唐诗/poet.song.235000.json','["寄跡琳宮絳闕邊，聚星家世楚先賢。", "但留法界寸田在，不要窮途衆目憐。", "談客由來無負郭，詩盟此去定忘年。", "吾衰有分非君獨，休羨千金有計然。"]'),
('771de047-56d3-4a9d-9699-00ac1caaf405','次韻陳道士和徐星韻見寄  其二','方一夔','宋','宋诗','song-poetry','','[]','不將書劍奮窮邊，藥裹君臣酒聖賢。',64,'全唐诗/poet.song.235000.json','["不將書劍奮窮邊，藥裹君臣酒聖賢。", "笑我文章全乏用，從渠心目兩相憐。", "參同顛倒長生訣，大衍推尋過去年。", "莫把詩狂壓師服，興來還解賦超然。"]'),
('81cc7715-41be-4b44-a883-da3365cc1c5d','次韻沃祥卿見謝  其一','方一夔','宋','宋诗','song-poetry','','[]','屢緣倦翼發虛彈，拋擲明珠不憚難。',64,'全唐诗/poet.song.235000.json','["屢緣倦翼發虛彈，拋擲明珠不憚難。", "但見雲烟歸筆下，不知風雨做秋闌。", "枌鄉人在依餘熱，桑落春濃壓早寒。", "時鼓梅花無譜曲，坐中驚倒董庭蘭。"]'),
('653ebbf6-bc5b-4154-a41d-e8f0a38a8e16','次韻沃祥卿見謝  其二','方一夔','宋','宋诗','song-poetry','','[]','有道論心知己少，世情開口向人難。',64,'全唐诗/poet.song.235000.json','["有道論心知己少，世情開口向人難。", "滴愁細雨驚秋暮，照睡青燈伴夜闌。", "文席知君容孔暖，孤吟愧我勝郊寒。", "浮花浪蕊何須數，歲晚歸來看石蘭。"]'),
('f8b244da-6397-4370-b0ef-1b26f2fa1284','遊碧沼寺','方一夔','宋','宋诗','song-poetry','','[]','古寺蕭蕭晝閉房，我來無處覓春陽。',64,'全唐诗/poet.song.235000.json','["古寺蕭蕭晝閉房，我來無處覓春陽。", "門前綠靜江湖汛，松下清陰暑月凉。", "空寄郭公留舊隠，愁聽望帝斷離腸。", "借君拍板都無用，看盡伶優老戲場。"]'),
('ab51dccb-6728-446c-b800-866fa517e1b9','接花','方一夔','宋','宋诗','song-poetry','','[]','枝頭信手奪春工，要借并州一割功。',64,'全唐诗/poet.song.235000.json','["枝頭信手奪春工，要借并州一割功。", "瓜柳皮粘混金碧，梅桃根換變鉛紅。", "笑談自分求孫叔，形似應難想孟公。", "却怪后皇同種橘，過淮便隔馬牛風。"]'),
('5a7eae18-3d38-48ec-a8c0-b8b917522d3e','清明遊塔山','方一夔','宋','宋诗','song-poetry','','[]','海山鼇骨白如銀，况是青山溟涬君。',64,'全唐诗/poet.song.235000.json','["海山鼇骨白如銀，况是青山溟涬君。", "不見黄泉沽紀釀，但驚紅雨落劉墳。", "百年塵土鎖連骨，一幅功名碑刻文。", "欲返斷魂呼不醒，歸塗賓從醉紛紛。"]'),
('bc517692-f1e3-4968-8d22-36340e1cd1ab','清明後一日','方一夔','宋','宋诗','song-poetry','','[]','老年光景轉風輪，惆悵清明又一春。',64,'全唐诗/poet.song.235000.json','["老年光景轉風輪，惆悵清明又一春。", "飛燕雙雙新舊恨，長亭五五往來人。", "揩磨病眼朱成碧，補接新花假像真。", "要覓西江千斛水，拂衣徑去洗緇塵。"]'),
('1adc0d50-0ccc-47f4-9509-da636aa4ee5d','遊苦竹徐墳值雨','方一夔','宋','宋诗','song-poetry','','[]','數聲呼我竹溪鷞，烟雨蒼茫苦竹岡。',64,'全唐诗/poet.song.235000.json','["數聲呼我竹溪鷞，烟雨蒼茫苦竹岡。", "半徑暮山浮翠滑，一渠春水落紅香。", "無人羞乞墦間肉，有酒空澆地下郎。", "萬化盡時終閉骨，醉來誰復算彭殤。"]'),
('df44ea8b-ff24-4381-af15-768b42c23e3a','次韻通甫至日','方一夔','宋','宋诗','song-poetry','','[]','先生熨眼洗浮埃，共看梅邊節物來。',64,'全唐诗/poet.song.235000.json','["先生熨眼洗浮埃，共看梅邊節物來。", "破悶好詩勝搔背，澆寒新酒似淋灰。", "賓主風裁推滕閣，弟子聲名詠有臺。", "憐我歲華相逐老，應將暖律發枯荄。"]'),
('ceebda30-b499-4a85-86f8-4cac8df1e9e4','別通甫','方一夔','宋','宋诗','song-poetry','','[]','歸途渺渺迫年華，回馬如飛不用撾。',64,'全唐诗/poet.song.235000.json','["歸途渺渺迫年華，回馬如飛不用撾。", "遥指荒村沽竹葉，獨行殘月看梅花。", "不嫌問路征夫冷，頗訝迎門穉子譁。", "爲報江邊羈客道，投林莫作後棲鴉。"]'),
('737a3f40-8881-45f1-b6c0-16a92a274759','春歸雜興三首  其一','方一夔','宋','宋诗','song-poetry','','[]','白首青燈滯一鄉，不將遲暮照韶光。',64,'全唐诗/poet.song.235000.json','["白首青燈滯一鄉，不將遲暮照韶光。", "經風魏紫埋傾國，破曉離黄殞折楊。", "老去功名隨夢斷，別來雲水隔天長。", "此生聚散何時了，定計歸鋤五畝荒。"]'),
('25fe6dd2-871e-45fe-b475-015971c96afb','春歸雜興三首  其二','方一夔','宋','宋诗','song-poetry','','[]','雙丸不肯駐頹光，宇宙悠悠萬物長。',64,'全唐诗/poet.song.235000.json','["雙丸不肯駐頹光，宇宙悠悠萬物長。", "寂寞餞春風雨裏，笑歌賭命綺羅鄉。", "破衾自卧三椽月，枯硯猶耕萬卷莊。", "未脫書生窮口債，向人時復說文章。"]'),
('3545a644-b606-4e4a-8950-4d789af07e43','春歸雜興三首  其三','方一夔','宋','宋诗','song-poetry','','[]','東皇歌闋祖青宮，借我𨦟旗併送窮。',64,'全唐诗/poet.song.235000.json','["東皇歌闋祖青宮，借我𨦟旗併送窮。", "繭栗潤含萌竹露，槍旗香過焙茶風。", "花殘來歲須重發，日却何時定再中。", "惆悵浮蹤底處所，夢隨飛絮故園東。"]'),
('bf2ef6ae-33da-4847-b16f-9ab4d25708da','賀山房先生得孫','方一夔','宋','宋诗','song-poetry','','[]','晚節歸來綠野堂，傳家衣鉢付諸郎。',64,'全唐诗/poet.song.235000.json','["晚節歸來綠野堂，傳家衣鉢付諸郎。", "喜存千載古罍洗，初聽九苞雛鳳凰。", "春蚤桐枝新濯秀，日長棣萼賸流芳。", "公家好事聯翩在，首寄詩篇寫弄璋。"]'),
('d7a276eb-37b2-487a-b04d-278485f6a7a3','次韻沃梅泉見寄詠稼隠相過之樂併督作詩  其一','方一夔','宋','宋诗','song-poetry','','[]','星聚何曾奏少微，浮萍桂海偶相隨。',64,'全唐诗/poet.song.235000.json','["星聚何曾奏少微，浮萍桂海偶相隨。", "摻袪東閣吟梅處，眵目寒窗點易時。", "自嘆兩翁餘口業，懸知千載有心期。", "啼猿唳鶴初無事，怕有行人怪說詩。"]'),
('79de3f1d-c06b-414c-854d-56ded97e3ecc','次韻沃梅泉見寄詠稼隠相過之樂併督作詩  其二','方一夔','宋','宋诗','song-poetry','','[]','梅壓滄浪密復疎，臨流幾度濯緌絇。',64,'全唐诗/poet.song.235000.json','["梅壓滄浪密復疎，臨流幾度濯緌絇。", "侯封富貴歸千首，身計行裝挂一壺。", "文飲暫教吾輩共，騷壇誰道我軍孤。", "汾亭洗盡箏琵耳，重理絲桐絙老梧。"]'),
('12b304a6-a59e-46c3-b1bc-689ab3612c71','次對稼隠病後見寄','方一夔','宋','宋诗','song-poetry','','[]','自憐數米續晨炊，饑火空時萬想虛。',64,'全唐诗/poet.song.235000.json','["自憐數米續晨炊，饑火空時萬想虛。", "富貴由來如夢鹿，江湖是處可羹魚。", "風輪歲月催人老，水鏡襟懷與世殊。", "書信柴胡俱不到，空慚多病馬相如。"]'),
('1d32ab2c-f042-49b7-808a-5ab81e464146','苦熱五首  其一','方一夔','宋','宋诗','song-poetry','','[]','夏來樊圃隔陰晴，誰與天工管不平。',64,'全唐诗/poet.song.235000.json','["夏來樊圃隔陰晴，誰與天工管不平。", "一窟蛟龍時作怪，千年草木偶成精。", "政疑沙界熬焦釜，未倒銀河洗太清。", "誰是蒼生霖雨手，普將禹甸釀西成。"]'),
('0dadfa25-7904-4948-b170-56a844bb659b','苦熱五首  其二','方一夔','宋','宋诗','song-poetry','','[]','絳節彤幢禦火精，世間那是水晶城。',64,'全唐诗/poet.song.235000.json','["絳節彤幢禦火精，世間那是水晶城。", "醉橫蘄竹愁重醒，睡落齊紈惜屢驚。", "家口飛蚊兒女語，鄉心過雁弟兄情。", "更闌誰撼千章木，悞作連牀夜雨聲。"]'),
('161cfb73-1379-4b2d-83db-7ae435364dcd','苦熱五首  其三','方一夔','宋','宋诗','song-poetry','','[]','午醉醒來濯碧泉，水亭况是晚凉天。',64,'全唐诗/poet.song.235000.json','["午醉醒來濯碧泉，水亭况是晚凉天。", "橫眠蓮葉半晞髮，靜對楊枝雙袒肩。", "蹇蝘聲乾林更靜，碧梧陰轉月初圓。", "茶甌更試纖纖手，不仗清風送玉川。"]'),
('402f9dc8-c8d2-4607-8ec3-905ef67573b2','苦熱五首  其四','方一夔','宋','宋诗','song-poetry','','[]','六龍無計駐雙丸，壯志摧頹似倒瀾。',64,'全唐诗/poet.song.235000.json','["六龍無計駐雙丸，壯志摧頹似倒瀾。", "萬里不成遊客夢，半生祇辦腐儒餐。", "誰憐打草衰麻答，不羨畫松楊契丹。", "世上紛紛誇禿髮，到頭那肯着南冠。"]'),
('284e2470-4f4b-4541-a7b7-ba54a048440f','苦熱五首  其五','方一夔','宋','宋诗','song-poetry','','[]','六月紅雲不肯移，清心自合勝炎曦。',64,'全唐诗/poet.song.235000.json','["六月紅雲不肯移，清心自合勝炎曦。", "雲根斲藥移松骨，石罅分泉插木皮。", "未用冰蠶來海嶠，坐看凍蟻走蛾眉。", "人間寒暑相催迫，待寄東溪萬縷絲。"]'),
('09fb3520-da1e-44ca-8da4-bcc5d5a5ac06','桂花','方一夔','宋','宋诗','song-poetry','','[]','服食生平屑辟邪，死埋金粟或金沙。',64,'全唐诗/poet.song.235000.json','["服食生平屑辟邪，死埋金粟或金沙。", "忽驚秋骨開成雪，誰遣香魂化作花。", "雲外孤芳吟舞鷲，月中半影匿妖蟇。", "先生幽佩乘風去，獨向仙堂看織紗。"]'),
('95ccaa67-5b99-4e8c-961b-e779c4be07f4','夜坐月下','方一夔','宋','宋诗','song-poetry','','[]','殘雲點點四飛揚，萬里離人共此光。',64,'全唐诗/poet.song.235000.json','["殘雲點點四飛揚，萬里離人共此光。", "誰鑄水銀懸絳闕，獨留姹女搗玄霜。", "窟中蟾兔雙灰劫，影底山河幾戰場。", "欲駐頹暉無意計，何人樓角韻伊凉。"]'),
('abec42b0-19d2-465b-9344-ef07afb96d19','讀赤壁賦','方一夔','宋','宋诗','song-poetry','','[]','萬舸浮江互蕩磨，一番蛟鰐戰盤渦。',64,'全唐诗/poet.song.235000.json','["萬舸浮江互蕩磨，一番蛟鰐戰盤渦。", "中天日月悲分影，對局英雄付逝波。", "形勝空傳二赤壁，文章誰肯百東坡。", "荆州風景今何似，秋夜時聞窈窕歌。"]'),
('35ac2395-204e-4c86-948d-1ed4a1e10446','雜興','方一夔','宋','宋诗','song-poetry','','[]','衰草含烟木葉黄，空城摇落客思鄉。',64,'全唐诗/poet.song.235000.json','["衰草含烟木葉黄，空城摇落客思鄉。", "雁高孤月臨空塞，魚退殘星過曲梁。", "醉眼昏花迷野馬，帖書戲草掣風檣。", "閒來更試絲綸手，新釣江鱸一尺長。"]'),
('9dfb30fc-6980-4239-ba3d-44c669d45137','晚眺二首  其一','方一夔','宋','宋诗','song-poetry','','[]','依稀風景小羌村，不欠東屯稻菽園。',64,'全唐诗/poet.song.235000.json','["依稀風景小羌村，不欠東屯稻菽園。", "阿魏搗香風送響，雕胡擘玉水開痕。", "招邀紫翠山當座，摽撥紅黄菊上盆。", "世上去來俱是客，隨風吹送夢歸魂。"]'),
('759462f8-457f-461f-9bcf-05d4c23d777e','晚眺二首  其二','方一夔','宋','宋诗','song-poetry','','[]','隔江斗入白雲村，分我閒雲伴綺園。',64,'全唐诗/poet.song.235000.json','["隔江斗入白雲村，分我閒雲伴綺園。", "月鵲自驚翻舞影，露蟲相弔洗啼痕。", "窮通蜍玉橫書案，得失梟盧轉采盆。", "可惜牀頭枕客道，蕭蕭奔馬醒吟魂。"]'),
('fe4af855-e4bb-4a0d-abbf-bfe69450bd5a','次韻王蒙泉見寄併和鄙作','方一夔','宋','宋诗','song-poetry','','[]','夜雨連床憶舊時，鱗鴻難寄故人詩。',64,'全唐诗/poet.song.235000.json','["夜雨連床憶舊時，鱗鴻難寄故人詩。", "憐君不察抱心久，寫我何如問信遲。", "兩地雲萍無定跡，一庭風月不分岐。", "寸衣換得天吳錦，豈是騷盟一字師。"]'),
('298e909b-b824-40c6-8ec2-00d2273c247a','菊花','方一夔','宋','宋诗','song-poetry','','[]','不入萎紅爛紫場，蕭然清苦凜風霜。',64,'全唐诗/poet.song.235000.json','["不入萎紅爛紫場，蕭然清苦凜風霜。", "客中衰鬢隨秋老，籬下寒枝似舊香。", "千載有陶期汗漫，幾人後屈話凄凉。", "每愁摇落知誰在，只有黄花守死黄。"]'),
('169af675-6fc2-4fd6-908d-acb664e8316f','寄何稼隠','方一夔','宋','宋诗','song-poetry','','[]','憶昔相逢霜露寒，再三與我返鄉關。',64,'全唐诗/poet.song.235000.json','["憶昔相逢霜露寒，再三與我返鄉關。", "溪行散亂飛蓬鬢，旅泊凄凉落日顔。", "活計獨傳鴻寶苑，清遊重上鹿門山。", "崇朝觸石需滂沛，笑我閒雲苦未閒。"]'),
('165ef324-572e-4530-8be8-c9665b67c092','偶作','方一夔','宋','宋诗','song-poetry','','[]','結緣無成謾學書，倦飛猶自揀庭梧。',64,'全唐诗/poet.song.235000.json','["結緣無成謾學書，倦飛猶自揀庭梧。", "不離文字添衰鬢，已外聲名謝壯圖。", "伯畧莫教累恩澤，儒詩何事汙裙襦。", "從今便覺高擡眼，不要奄奄學志蝓。"]'),
('fd475930-6b81-4b51-a5aa-b9b03049fe62','次韻沃梅泉見寄併見和鄙韻  其一','方一夔','宋','宋诗','song-poetry','','[]','謾道萍蹤日夜浮，自慚遲鈍戀菟裘。',64,'全唐诗/poet.song.235000.json','["謾道萍蹤日夜浮，自慚遲鈍戀菟裘。", "聖傳杯裏蘭亭帖，婢熟山中笠澤秋。", "有信付將來去燕，無心寄與沒浮鷗。", "去年曾記梅花下，細雨離魂阻勝遊。"]'),
('43a03ae0-1279-4bd8-a5dd-8f0a369f41f1','次韻沃梅泉見寄併見和鄙韻  其二','方一夔','宋','宋诗','song-poetry','','[]','散仙自在步如飛，絡腦黄金不受羈。',64,'全唐诗/poet.song.235000.json','["散仙自在步如飛，絡腦黄金不受羈。", "籬菊清香須把酒，京塵紅漲不緇衣。", "倚樓看劍浮名逼，閉戶尋詩過客稀。", "水擊槍榆俱有得，不妨着我子陵磯。"]'),
('9160bd13-2428-468d-b1df-77d7222ad02f','至日','方一夔','宋','宋诗','song-poetry','','[]','九地窮陰迸穉陽，萬家起早拜迎長。',64,'全唐诗/poet.song.235000.json','["九地窮陰迸穉陽，萬家起早拜迎長。", "梅將暖信迎青帝，橘子真心服后皇。", "耳藥肯塗銀盒雪，牙硝自踏板橋霜。", "詩情只會如工部，至日年年客異鄉。"]'),
('df1a01be-49b2-477a-a21d-04c2fc91716e','和府尹虛谷先生和徐子英韻併寄徐子英  其一','方一夔','宋','宋诗','song-poetry','','[]','千峯蒼翠擁城樓，着我宗英七里洲。',64,'全唐诗/poet.song.235000.json','["千峯蒼翠擁城樓，着我宗英七里洲。", "昔日松楸相伴住，暮年湖海未歸休。", "詠詩遥認窮司馬，騎竹爭迎舊細侯。", "莫爲梅花長挽却，好將繩削訂由求。"]'),
('cfe607b9-1856-462b-a032-fc3e7584c0ee','和府尹虛谷先生和徐子英韻併寄徐子英  其二','方一夔','宋','宋诗','song-poetry','','[]','袖手闌干獨倚樓，暫舒倦眼對滄洲。',64,'全唐诗/poet.song.235000.json','["袖手闌干獨倚樓，暫舒倦眼對滄洲。", "雲山勸我閒方住，聲利縈人懶即休。", "後世豈無青史筆，浮生那欠赤泉侯。", "巖幽得似銅駞陌，粟飯藜羹却易求。"]'),
('ec20df1a-d222-4b0a-a4b8-86b9c0b12880','兵革後初出邑郭','方一夔','宋','宋诗','song-poetry','','[]','無數青山對坐衙，讀書林下靜無譁。',32,'全唐诗/poet.song.235000.json','["無數青山對坐衙，讀書林下靜無譁。", "如今風景那須說，坊郭無民吏數家。"]'),
('cf5a154f-1400-477f-bd0c-60deed0a18cf','錢王守鳬墩在臨安道左','方一夔','宋','宋诗','song-poetry','','[]','山下燈龕掛紙錢，水楊墩上草芊綿。',32,'全唐诗/poet.song.235000.json','["山下燈龕掛紙錢，水楊墩上草芊綿。", "高人不要金丸用，買得三吳八十年。"]'),
('cb645995-9931-4169-a227-58fdd9c02146','紅梅','方一夔','宋','宋诗','song-poetry','','[]','霜月娟娟午夜寒，酒酣來此凭闌干。',32,'全唐诗/poet.song.235000.json','["霜月娟娟午夜寒，酒酣來此凭闌干。", "滿枝艷色驚愁眼，宣主當年唾未乾。"]'),
('e73939df-9d5d-4830-b4db-6c9abcfcd529','世言有問脩短之數於希夷者曰好來好去因觀落葉有感前語','方一夔','宋','宋诗','song-poetry','','[]','芳菲桃李雨新肥，緋綠園林露已淒。',32,'全唐诗/poet.song.235000.json','["芳菲桃李雨新肥，緋綠園林露已淒。", "自道好來還好去，到頭總是涴塵泥。"]'),
('ca24d8d9-aedb-4e6a-956b-e598bd0ffd1d','震澤市','方一夔','宋','宋诗','song-poetry','','[]','石峯疊疊小橋西，昔日人家桃李蹊。',32,'全唐诗/poet.song.235000.json','["石峯疊疊小橋西，昔日人家桃李蹊。", "無限歡娛俱寂寞，珠璣鋒鏑逐春犂。"]'),
('4c37a04d-e997-4535-a7ef-79e2e310fe07','夜坐評史 史記','方一夔','宋','宋诗','song-poetry','','[]','遷史馳驅縱復橫，不煩繩削自天成。',32,'全唐诗/poet.song.235000.json','["遷史馳驅縱復橫，不煩繩削自天成。", "後來縱欲修良史，法度森嚴敢變更。"]'),
('6f5667aa-bd7c-4b51-807a-f67e4159fc03','夜坐評史 西漢書','方一夔','宋','宋诗','song-poetry','','[]','班固師遷亦步趨，末容後進造庭隅。',32,'全唐诗/poet.song.235000.json','["班固師遷亦步趨，末容後進造庭隅。", "半生描摸龍門像，雖乏精神貌却腴。"]'),
('4624cb41-2202-4c23-be4b-3774ccb58ab1','夜坐評史 東漢書','方一夔','宋','宋诗','song-poetry','','[]','羨渠二子着先鞭，未把文章許范傳。',32,'全唐诗/poet.song.235000.json','["羨渠二子着先鞭，未把文章許范傳。", "遠出孟堅畦逕下，謾誇筆勢舞翩翩。"]'),
('d7b87f5d-be9e-475b-a918-73103672b178','夜坐評史 順宗實錄','方一夔','宋','宋诗','song-poetry','','[]','韓老文章不減遷，中山一傳更增妍。',32,'全唐诗/poet.song.235000.json','["韓老文章不減遷，中山一傳更增妍。", "如何實錄二三卷，氣薾言卑不類前。"]'),
('dc78e1b9-0426-47c4-8858-b5d35ef59a13','夜坐評史 五代史','方一夔','宋','宋诗','song-poetry','','[]','自許精嚴獨有歐，庸奴班馬法春秋。',32,'全唐诗/poet.song.235000.json','["自許精嚴獨有歐，庸奴班馬法春秋。", "文章雖到精神露，殆與二書爭一籌。"]'),
('bb0202a2-76db-4bd5-b14b-b79f67dded49','客有善談謔者曰鰌鮎魚龜皆水族也一日聚議謁河伯求職事鰌先去河伯授以右相鮎魚次之授以左相龜行遲欲以翰林處之龜不願曰好官二子俱做但願河伯註長壽看二子做到何處其言雖謔可爲發一笑也謾記其事','方一夔','宋','宋诗','song-poetry','','[]','傭耕陳勝假爲鬼，爛斧王喬詐得仙。',32,'全唐诗/poet.song.235000.json','["傭耕陳勝假爲鬼，爛斧王喬詐得仙。", "若見淵明爲我道，併從金母乞長年。"]'),
('6111c9fc-c593-4616-9a5d-eb87a6db2ea6','富貴','方一夔','宋','宋诗','song-poetry','','[]','懷清臺廢嬌娥怨，醉白堂空過客愁。',32,'全唐诗/poet.song.235000.json','["懷清臺廢嬌娥怨，醉白堂空過客愁。", "若向此時回首看，生平富貴一齊休。"]'),
('34635d68-a4bf-4cba-a9e8-810e877a0fe3','讀劉阮事用元微之韻','方一夔','宋','宋诗','song-poetry','','[]','層層樓閣鎖嬌鬟，要伴朝雲出遠山。',32,'全唐诗/poet.song.235000.json','["層層樓閣鎖嬌鬟，要伴朝雲出遠山。", "紫府神仙行世上，深宮妃媵落人間。"]'),
