('ac7e2916-ebc1-48b0-8274-481b6d80429e','謁融堂墓','方一夔','宋','宋诗','song-poetry','','[]','安車束帛此招賢，夢冷冬窩又百年。',64,'全唐诗/poet.song.235000.json','["安車束帛此招賢，夢冷冬窩又百年。", "已自無人守墳墓，空令過客問山川。", "時方大用文公學，士亦深排陸子禪。", "回首蜀天清不盡，臨風三酹一蕭然。"]'),
('d3368e89-81f3-45e6-80cb-12ce749d460b','步瀛橋樂章','胡次焱','宋','宋诗','song-poetry','','[]','跨海虹霓浸不收，植楹鯢背聳于樓。',64,'全唐诗/poet.song.235000.json','["跨海虹霓浸不收，植楹鯢背聳于樓。", "直通兩岸東西路，橫截一溪上下流。", "網羅學士唐天子，管領英雄張狀頭。", "醉墨淋漓題柱上，與君從此步瀛洲。"]'),
('9afc783e-ee48-4997-b00b-c845974780da','題觀壁詩','胡次焱','宋','宋诗','song-poetry','','[]','仙子王僚上九天，山中遺跡尚依然。',64,'全唐诗/poet.song.235000.json','["仙子王僚上九天，山中遺跡尚依然。", "藥爐雲冷灰無火，丹井松陰地有泉。", "蟲篆碑文傳萬古，鶴鳴華表動千年。", "我來弔古空惆悵，塵世茫茫幾變遷。"]'),
('b5c64900-8037-40ef-87dc-88eb0d8c61a5','秋日早行','胡次焱','宋','宋诗','song-poetry','','[]','草衣路室夜偏長，起問征途趁早凉。',64,'全唐诗/poet.song.235000.json','["草衣路室夜偏長，起問征途趁早凉。", "藜杖對星占曙色，芒鞋踏月涴秋光。", "櫟陰羃砌疑澆墨，桂露滴人如餽漿。", "山鬼似嫌天欲曉，故噓嵐氣扼朝暘。"]'),
('d0fcf40b-bb18-4956-ad1d-d276df252b4e','媒問嫠','胡次焱','宋','宋诗','song-poetry','','[]','媒問嫠，汝何傷。',284,'全唐诗/poet.song.235000.json','["媒問嫠，汝何傷。", "汝爲閨秀時，辛苦事蠶桑。", "僴瑟順爲正，婉娩禮自將。", "笥中有練裙，衣上無明璫。", "貧女古難嫁，賣犬辦資裝。", "中年得夫壻，憧憧拜姑嫜。", "肅容采蘋藻，洗手供羹湯。", "良人正少年，相期家道昌。", "良緣天所妬，夫壻奄云亡。", "自從夫壻亡，十年守空房。", "素帷代錦幬，苫席易牙牀。", "孤眠耿夜半，單立黯昏黄。", "煢煢影徘徊，鞅鞅情彷徨。", "皓月照枕衾，暴雨頹垣牆。", "獨寤誰呼喚，獨語誰交相。", "如凌空失翼，如涉川無梁。", "嫠來吾語汝，琴瑟貴更張。", "汝篋既單薄，汝門復淒涼。", "汝寒何以衣，汝饑何以糧。", "紡績終難給，舂汲勞欲僵。", "死者不復起，生者宜自詳。", "鄰有美丈夫，顒顒更昂昂。", "牛羊量用谷，金玉堆滿堂。", "畫梁青瑣闥，珠簾毹氍廂。"]'),
('d2398f0e-0137-4f7e-b6ac-dd201e2b335d','嫠答媒','胡次焱','宋','宋诗','song-poetry','','[]','嫠答媒，妾自憐。',289,'全唐诗/poet.song.235000.json','["嫠答媒，妾自憐。", "妾家貧如洗，妾貌粧不妍。", "中年方擇配，幸逢夫婿賢。", "藍橋疑仙會，紅葉開良緣。", "俯以奉箕箒，仰焉供豆籩。", "粵從定六禮，穩圖偕百年。", "詎疑有家願，倏罹中道捐。", "城崩哭呦呦，竹斑淚濺濺。", "空房照明月，幽隴淒寒烟。", "禽鳥喧墓門，魄降魂翩翩。", "蛜蝛滿窗戶，心結目涓涓。", "寮室昔華屋，埋玉今荒阡。", "恨不即同穴，何忍續斷絃。", "翻思合{丞一=巴}初，參透老婆禪。", "如魚水遊泳，如蔦蘿纏綿。", "奈何生死闊，泛泛水中船。", "綢繆爲夫婦，反覆如市廛。", "徒貽楊華醜，寧免柳絮顛。", "妾頗親筆硯，亦嘗閲簡編。", "女不踐二庭，婦不再移天。", "陶嬰寡鵠吟，衛妻孤燕篇。", "或刑耳自誓，或斷髮自全。", "或劓鼻偃蹇，或毀面迍邅。", "吾足幸可刖，吾臂不可牽。"]'),
('5b58e308-9dc2-4710-ae89-e27c9f624c60','梅隠君六秩壽','趙洪','宋','宋诗','song-poetry','','[]','隠君家世出梅山，描得清芬滿世間。',32,'全唐诗/poet.song.235000.json','["隠君家世出梅山，描得清芬滿世間。", "梅稟正陽全太極，同姓同心不赧顔。"]'),
('ce04f290-a383-43f6-93aa-1da4f0437e68','釘詩','繆萬年','宋','宋诗','song-poetry','','[]','頑礦非銅剛樣堅，寒坑纔離亟趨炎。',64,'全唐诗/poet.song.235000.json','["頑礦非銅剛樣堅，寒坑纔離亟趨炎。", "十來槌打隨成器，一得人拈却逞鑯。", "不怕斧敲惟要入，全憑鑽引任教嫌。", "休言深處難抽拔，自有羊蹄與鐵鉗。"]'),
('9eb83eea-43ac-4b10-b1fd-5e7f2cf44150','送馬靜山寄林曉山兄弟','林千之','宋','宋诗','song-poetry','','[]','古井誰復汲，古調誰復裁。',192,'全唐诗/poet.song.235000.json','["古井誰復汲，古調誰復裁。", "玄鶴引清吭，萬壑松風哀。", "彼美三株樹，沆瀣𣂏瓊臺。", "吾宗大小山，正爾期不來。", "袖有明月珠，遠遺馬子才。", "江空山亦深，乃肯穿蒼苔。", "妙悟玄中玄，使我心悠哉。", "有牆肩曹劉，無苑延鄒枚。", "采薇霧失道，釣鼇風折桅。", "朔風無重裘，地爐擁寒灰。", "兩窮相值遇，一笑聊參陪。", "白日苦無光，暖律何當回。", "持此將安歸，令人心膽摧。", "吾聞三神山，縹緲連蓬萊。", "滄海正清浮，神仙亦崔嵬。", "歸歟三雋朋，下界空飛埃。"]'),
('1432ed05-488c-4ffa-81d8-488af998165e','贈水簾洞黄秀才','林千之','宋','宋诗','song-poetry','','[]','讀書避世喧，結廬五雲表。',120,'全唐诗/poet.song.235000.json','["讀書避世喧，結廬五雲表。", "淡薄足生涯，詰曲藏深杳。", "仰觀紅日近，俯視衆山小。", "滄溟舞澎湃，雲氣度浩渺。", "喬松蔓翠蘿，絕壁藏啼鳥。", "一派從天來，長練掛木杪。", "海鷗忘機智，峒蝶忙飛繞。", "亦知山房靜，而被俗客擾。", "作詩寄殷勤，努力須壯少。", "他年騰踏去，蕙帳猿驚曉。"]'),
('1006639b-903a-4e34-8597-713a910d76ca','塘下','林千之','宋','宋诗','song-poetry','','[]','一片頹園生穀桑，惟餘小圃佔秋光。',64,'全唐诗/poet.song.235000.json','["一片頹園生穀桑，惟餘小圃佔秋光。", "竹籬蔓引牽牛碧，野菜崇生苦藚黄。", "抱葉蟬瘖枯樹冷，銜花鹿去古臺荒。", "興亡往往關天數，搔首躊躇對夕陽。"]'),
('5284934f-5f50-43bd-83b4-5097231545cd','送胡季昭謫象州','羅耕','宋','宋诗','song-poetry','','[]','赤心端欲贊皇圖，鼓瑟那知却好竽。',64,'全唐诗/poet.song.235000.json','["赤心端欲贊皇圖，鼓瑟那知却好竽。", "崇論已聞驚仗馬，攄忠寧復忌城狐。", "當爲天下奇男子，肯學人間小丈夫。", "更問澹庵老居士，儋州還似象州無。"]'),
('5e43de19-5648-4054-9c57-5603d81ef7d3','山齋夜坐','平天祐','宋','宋诗','song-poetry','','[]','悄然人不寐，山館意何深。',48,'全唐诗/poet.song.235000.json','["悄然人不寐，山館意何深。", "落葉添寒色，幽蟲助苦吟。", "青燈憐夜永，白髮带愁簪。", "天末懷良友，音書雁影沉。"]'),
('d2c89ced-62db-453e-bf1b-bc79684058ab','池上作','朱紹遠','宋','宋诗','song-poetry','','[]','生涯幻吹沫，功名鮎上竿。',72,'全唐诗/poet.song.235000.json','["生涯幻吹沫，功名鮎上竿。", "魚豈知許事，人意强相干。", "春風一鼓盪，芳池生碧瀾。", "逐隊半畝餘，樂有江湖寬。", "世路無險易，心閒自達觀。", "悟彼蝸殻涎，空轉蛣蜣丸。"]'),
('12db9660-cb17-4c56-b934-cb8d77c533f5','濯足','趙必漣','宋','宋诗','song-poetry','','[]','小橋坐濯足，澗狹水流急。',24,'全唐诗/poet.song.235000.json','["小橋坐濯足，澗狹水流急。", "源頭夜雨多，落花漾露濕。"]'),
('431e9529-459d-42ce-ae5e-be44637a185f','自題梅花莊','趙必漣','宋','宋诗','song-poetry','','[]','一間茅屋傍溪斜，三徑荒於靖節家。',32,'全唐诗/poet.song.235000.json','["一間茅屋傍溪斜，三徑荒於靖節家。", "但得鶴糧隨分足，更須鋤月種梅花。"]'),
('e41ee455-2855-4c1e-9c65-0e2401415eb6','題梅花莊','劉濟','宋','宋诗','song-poetry','','[]','莊後莊前千萬枝，元方題扁季方詩。',32,'全唐诗/poet.song.235000.json','["莊後莊前千萬枝，元方題扁季方詩。", "何當把酒對花樹，坐到參橫月落時。"]'),
('fb919855-4cba-4358-9d1f-77d00766374c','鳳凰臺','劉汝春','宋','宋诗','song-poetry','','[]','高臺寂寞晚雲深，故國山河萬里心。',32,'全唐诗/poet.song.235000.json','["高臺寂寞晚雲深，故國山河萬里心。", "若使當年真鳳見，不教春燕亦巢林。"]'),
('b812246b-fff7-48c8-9616-eb8e0909b09f','秋思','陳則翁','宋','宋诗','song-poetry','','[]','在世身如客，餘年老一洲。',48,'全唐诗/poet.song.235000.json','["在世身如客，餘年老一洲。", "荒村寒信早，黄葉晚風秋。", "水浄見孤影，天空生遠愁。", "傑然霜下菊，佳色滿林丘。"]'),
('4da4cd38-1ba3-48bc-92f5-1506258968ea','閩嶠軍中','陳則翁','宋','宋诗','song-poetry','','[]','貔貅齊擁霍嫖姚，却笑青山說豹韜。',64,'全唐诗/poet.song.235000.json','["貔貅齊擁霍嫖姚，却笑青山說豹韜。", "兵馬夜行殘月下，弓旌寒響朔風高。", "壺漿故老愁啼血，野飯將軍猛茹毛。", "自笑書生隨玉帳，也腰刀劍束征袍。"]'),
('e069755b-f551-4c9e-b92f-8a4f7ce36bf3','題劉世疏庵','釋希坦','宋','宋诗','song-poetry','','[]','藏却胸中萬卷書，却來山頂結茅廬。',32,'全唐诗/poet.song.235000.json','["藏却胸中萬卷書，却來山頂結茅廬。", "當時若也羈韁鎖，爭得高名是世疏。"]'),
('ea49a721-4917-465d-84ce-c231846f96da','廣化院','釋希坦','宋','宋诗','song-poetry','','[]','路轉幾多曲，山登千萬重。',48,'全唐诗/poet.song.235000.json','["路轉幾多曲，山登千萬重。", "未游走馬澤，先看鬭鷄峰。", "高樹出雲聳，寒泉趁石舂。", "徜徉因覓句，時復倚青松。"]'),
('ee58677b-4b91-4829-8f37-4afc438df5e1','福海院','釋希坦','宋','宋诗','song-poetry','','[]','路入轉幽處，渾疑別是天。',48,'全唐诗/poet.song.235000.json','["路入轉幽處，渾疑別是天。", "虬松雖變化，牛石尚酣眠。", "驟過一番雨，鳴飛七布泉。", "望中千點雪，白鷺立平田。"]'),
('7335e1ab-87af-433d-8ddd-13d82b9a417a','老人峰','釋希坦','宋','宋诗','song-poetry','','[]','二氣分時有此翁，壽年直與太虛同。',32,'全唐诗/poet.song.235000.json','["二氣分時有此翁，壽年直與太虛同。", "想應傴僂千峰上，默笑人間說籛公。"]'),
('abe01a46-0c09-4a99-82b2-e124fb7cc718','五臺明智院','釋希坦','宋','宋诗','song-poetry','','[]','時過九月秋，來作上方游。',48,'全唐诗/poet.song.235000.json','["時過九月秋，來作上方游。", "林瘦霜凋葉，鍾鳴風滿樓。", "五臺新月上，一洞暮雲收。", "奪利爭名者，寧知此地幽。"]'),
('926a81e7-10c1-4ab3-a01a-012f14c392db','崇壽院','釋希坦','宋','宋诗','song-poetry','','[]','踏破蒼苔徑，幽居在嶺巔。',48,'全唐诗/poet.song.235000.json','["踏破蒼苔徑，幽居在嶺巔。", "亭臺清映月，松竹淡籠烟。", "佳客纔登席，高僧忽起禪。", "呼童急煎茗，新汲白龜泉。"]'),
('993f0608-0a50-462b-811b-56eade808f35','曹溪','釋希坦','宋','宋诗','song-poetry','','[]','五水奔流會合通，大溪飛過一長虹。',32,'全唐诗/poet.song.235000.json','["五水奔流會合通，大溪飛過一長虹。", "芙蓉面目重重見，多在烟霞變態中。"]'),
('df1a225c-2291-4542-bca3-09fae8760658','華池','釋希坦','宋','宋诗','song-poetry','','[]','陽魂日運金烏髓，陰魄時含玉兔脂。',32,'全唐诗/poet.song.235000.json','["陽魂日運金烏髓，陰魄時含玉兔脂。", "一旦相交化神水，山中分作兩華池。"]'),
('3257eaec-336b-4acc-bfc0-a77ba58db0a0','李昭象書堂','釋希坦','宋','宋诗','song-poetry','','[]','廢興生死妄安名，山水何曾改舊清。',32,'全唐诗/poet.song.235000.json','["廢興生死妄安名，山水何曾改舊清。", "孰謂堂空人已往，溪聲還作讀書聲。"]'),
('24f16e95-bb04-4d0d-bc3f-2b47c3d21032','金步摇','釋希坦','宋','宋诗','song-poetry','','[]','偶對叢條巧櫛成，動摇徐步寂無聲。',32,'全唐诗/poet.song.235000.json','["偶對叢條巧櫛成，動摇徐步寂無聲。", "仙花不識興亡事，豈學吳宮響屧行。"]'),
('ce694c58-9388-45f6-ad63-0573e4234c43','婆餠焦','釋希坦','宋','宋诗','song-poetry','','[]','綠柳含烟烟不消，紅花噴火火無燒。',32,'全唐诗/poet.song.235000.json','["綠柳含烟烟不消，紅花噴火火無燒。", "如何焦却婆婆餠，每到春風舌苦饒。"]'),
('d9e7abcc-10ff-4e57-b1d7-e6b0bc6adf03','崑山','凌嵒','宋','宋诗','song-poetry','','[]','九峰西峙比崑崙，晉代將軍墓尚存。',32,'全唐诗/poet.song.235000.json','["九峰西峙比崑崙，晉代將軍墓尚存。", "今日捫蘿登絕頂，桑丘麥壟自村村。"]'),
('28400ec7-ad7d-4083-9e3d-c03f8c697c20','橫雲山','凌嵒','宋','宋诗','song-poetry','','[]','七峰𡷾崒擁層巒，偃蓋孤松石上蟠。',32,'全唐诗/poet.song.235000.json','["七峰𡷾崒擁層巒，偃蓋孤松石上蟠。", "行雲白龍何處去，暮雲深鎖洞門寒。"]'),
('868e4248-835b-43fb-ae6e-0dfe779f9a52','機山','凌嵒','宋','宋诗','song-poetry','','[]','六峰喬木鎖雲根，青接平原數里村。',32,'全唐诗/poet.song.235000.json','["六峰喬木鎖雲根，青接平原數里村。", "此處無人來聽鶴，海靈山鬼哭黄昏。"]'),
('1704a99a-c550-471b-ab75-b568d581a026','干山','凌嵒','宋','宋诗','song-poetry','','[]','八峰葱蒨石林幽，給事題詩記勝遊。',32,'全唐诗/poet.song.235000.json','["八峰葱蒨石林幽，給事題詩記勝遊。", "昨夜僧歸鐘鼓靜，一聲鶴唳海天秋。"]'),
