('d6879d70-04ed-4d8d-9034-18cf671bcde8','偈頌一百零三首  其七','釋月磵','宋','宋诗','song-poetry','','[]','八十種好，三十二相。',27,'全唐诗/poet.song.235000.json','["八十種好，三十二相。", "醜惡容止，餵狗不噇。", "正好燒香供養。"]'),
('9d1f613a-94cf-4360-90ee-b19000903ae8','偈頌一百零三首  其八','釋月磵','宋','宋诗','song-poetry','','[]','即心即佛，狐狸戀窟。',53,'全唐诗/poet.song.235000.json','["即心即佛，狐狸戀窟。", "非心非佛，當機放出遼天鶻。", "馬大師等閑向虛空裏拋箇題目，經今五七百年，更無一人描寫得著。"]'),
('d94c6fdf-a41e-4f38-8d62-c68371e8c26b','偈頌一百零三首  其九','釋月磵','宋','宋诗','song-poetry','','[]','記得鵝峰相聚日，嗔拳熱喝當慈悲。',49,'全唐诗/poet.song.235000.json','["記得鵝峰相聚日，嗔拳熱喝當慈悲。", "而今含恨重相見，只得開顔陪笑，歡喜接伊。", "何爲如此，爲怕粗心捋虎鬚。"]'),
('bd137ad6-1825-444f-a0ca-c6ee68b9063e','偈頌一百零三首  其一○','釋月磵','宋','宋诗','song-poetry','','[]','古佛心，無背面。',72,'全唐诗/poet.song.235000.json','["古佛心，無背面。", "泥團土塊，磚頭瓦片。", "是汝諸人，每日於土木場中，何止行一徧兩徧，三四五徧。", "因甚足踏不著，眼覷不見。", "令人長憶謝玄暉，解道澄江浄如練。"]'),
('dc0b2812-7009-4cf4-952d-fcae40251d5f','偈頌一百零三首  其一一','釋月磵','宋','宋诗','song-poetry','','[]','六陰剝盡，鄱陽湖盡底乾枯。',79,'全唐诗/poet.song.235000.json','["六陰剝盡，鄱陽湖盡底乾枯。", "一陽復生，蠙州門暗通一線。", "長一線，一線長，箇事分明不覆藏。", "有般漢聞與麽告報，便道一生二，二生三，三生萬物。", "如斯領會，笑倒街頭石敢當。"]'),
('3ef9bb4c-500d-4aac-9513-adcd14f5a723','偈頌一百零三首  其一二','釋月磵','宋','宋诗','song-poetry','','[]','見見之時，見非是見。',41,'全唐诗/poet.song.235000.json','["見見之時，見非是見。", "只如靈雲見桃花，畢竟是見非見。", "玉兔挨開碧海門，金烏啄破琉璃殿。"]'),
('c1bb8459-64d3-4577-bf0d-41d7610c436a','偈頌一百零三首  其一三','釋月磵','宋','宋诗','song-poetry','','[]','布袋頭，今日結。',48,'全唐诗/poet.song.235000.json','["布袋頭，今日結。", "上三星，下半月。", "觀著重添眼中屑。", "沒理會，易分別。", "若要通身冷汗流，嚼碎通紅塊生鐵。"]'),
('9db32f02-b570-4147-8631-6a435cca8dc3','偈頌一百零三首  其一四','釋月磵','宋','宋诗','song-poetry','','[]','諸佛的旨，諸祖玄機，分明覿面爲提持。',41,'全唐诗/poet.song.235000.json','["諸佛的旨，諸祖玄機，分明覿面爲提持。", "是汝諸人，因甚覷著眼如眉。", "易填巨壑，難滿漏巵。"]'),
('0fec9ed5-4d12-437e-8597-0ba84c67e237','偈頌一百零三首  其一五','釋月磵','宋','宋诗','song-poetry','','[]','佛祖格外機，衲僧向上著。',72,'全唐诗/poet.song.235000.json','["佛祖格外機，衲僧向上著。", "著眼覷不是，舉步踏不著。", "擬之即差，不擬尤錯。", "是汝諸人，九十日如鷹在韝，如魚在箔，有甚快樂。", "山僧今日出手，爲諸人解拈去縛。"]'),
('72eb538d-b12f-465d-a80a-6adc25db5861','偈頌一百零三首  其一六','釋月磵','宋','宋诗','song-poetry','','[]','橫十尺，豎十尺。',22,'全唐诗/poet.song.235000.json','["橫十尺，豎十尺。", "潦倒毱多尊者，三千里外斫額。"]'),
('0adfbefa-5b02-42c0-a760-6c4f4885c332','偈頌一百零三首  其一七','釋月磵','宋','宋诗','song-poetry','','["\u8861\u5c71"]','結虛空，捏定如生鐵。',41,'全唐诗/poet.song.235000.json','["結虛空，捏定如生鐵。", "解聖凡，普請出陰界。", "西天此土，南嶽天台，總不出師僧陳年破草鞋。"]'),
('1af68018-5e34-4411-ab6b-f2c43114d245','偈頌一百零三首  其一八','釋月磵','宋','宋诗','song-poetry','','[]','圓陀陀，明歷歷。',61,'全唐诗/poet.song.235000.json','["圓陀陀，明歷歷。", "堪笑老瞿曇，六年猶不識。", "驀忽眼皮綻，喜歡三七日。", "直得東湖盡力讚歎，也讚嘆不及。", "畢竟讚歎箇什麽，乞兒拾得錫。"]'),
('2c57c619-61ff-4da7-9d81-7fc8f63f1809','偈頌一百零三首  其一九','釋月磵','宋','宋诗','song-poetry','','[]','塞雲點點陣雲高，黑面將軍衣白袍。',32,'全唐诗/poet.song.235000.json','["塞雲點點陣雲高，黑面將軍衣白袍。", "奪得賊鎗并賊馬，凱歌歸去醉春醪。"]'),
('29fdc0ba-7e70-4097-a7e0-86c4f57a2e16','偈頌一百零三首  其二○','釋月磵','宋','宋诗','song-poetry','','[]','無端盡把潑衆私，攤向人前誰點癡。',32,'全唐诗/poet.song.235000.json','["無端盡把潑衆私，攤向人前誰點癡。", "對面不能掀倒去，滿天風雨謾凄其。"]'),
('4839c5bb-f334-421c-a997-6fbba1ea1ac5','偈頌一百零三首  其二一','釋月磵','宋','宋诗','song-poetry','','[]','若人生百歲，不善諸佛機。',24,'全唐诗/poet.song.235000.json','["若人生百歲，不善諸佛機。", "未若生一日，而得决了知。"]'),
('7dff4ae1-fdd4-429c-877d-44ebd3a87366','偈頌一百零三首  其二二','釋月磵','宋','宋诗','song-poetry','','[]','歲在子，月在子，一陽生在子。',55,'全唐诗/poet.song.235000.json','["歲在子，月在子，一陽生在子。", "惟有衲僧家，佛不知有釋迦老子，祖不知有達磨老子。", "又誰管你天翻地覆，陰消陽長一著子。"]'),
('2fe8a247-f4bb-4261-9548-45d40d68e3e2','偈頌一百零三首  其二三','釋月磵','宋','宋诗','song-poetry','','[]','驟雨漲溪高數尺，失却搗衣平正石。',32,'全唐诗/poet.song.235000.json','["驟雨漲溪高數尺，失却搗衣平正石。", "明朝水落石依然，老夫一夜空相憶。"]'),
('98d8c795-cd99-4478-9e06-f54d6e44f115','偈頌一百零三首  其二四','釋月磵','宋','宋诗','song-poetry','','[]','威音未生已前，有此清凉大木。',62,'全唐诗/poet.song.235000.json','["威音未生已前，有此清凉大木。", "根蟠無陰陽地上，影藏叫不響山谷。", "枝枝葉葉，婆婆娑娑，蔭覆天下人。", "彷彿當年黄蘗會中，喫蒿枝底尊宿。"]'),
('639cd622-dbdc-4ee3-842f-ff4c8abbf781','偈頌一百零三首  其二五','釋月磵','宋','宋诗','song-poetry','','[]','定乾坤句，雷厲風飛。',30,'全唐诗/poet.song.235000.json','["定乾坤句，雷厲風飛。", "提佛祖令，厓崩石裂。", "法主大寶，自然而至。"]'),
('fc870ece-d524-497b-af9a-6131bfe99b27','偈頌一百零三首  其二六','釋月磵','宋','宋诗','song-poetry','','["\u8861\u5c71"]','九十日內，山河大地一布袋。',47,'全唐诗/poet.song.235000.json','["九十日內，山河大地一布袋。", "九十日外，是聖是凡無罣礙。", "朝南嶽，暮天台。", "飯錢即且置，還我草鞋錢來。"]'),
('3b9cc3d7-a245-471f-be85-66afe80e0aff','偈頌一百零三首  其二七','釋月磵','宋','宋诗','song-poetry','','[]','擊鼓陞堂，分明指示。',20,'全唐诗/poet.song.235000.json','["擊鼓陞堂，分明指示。", "冬至月尾，賣牛買被。"]'),
('2e430fe2-75cf-4f43-9790-2d67b5f18a40','偈頌一百零三首  其二八','釋月磵','宋','宋诗','song-poetry','','[]','天地紅爐鬰且蒸，萬岳清撼寒濤聲。',36,'全唐诗/poet.song.235000.json','["天地紅爐鬰且蒸，萬岳清撼寒濤聲。", "六月賣無價，奈此松風清。", "拊闌一笑大江橫。"]'),
('8ce64d63-5bee-4bef-adf6-d48a04078b5d','偈頌一百零三首  其二九','釋月磵','宋','宋诗','song-poetry','','[]','天邊有月生雲際，木人石人眼卓豎。',32,'全唐诗/poet.song.235000.json','["天邊有月生雲際，木人石人眼卓豎。", "瞥轉玄機那邊覩，三個孩兒抱花皷。"]'),
('e4c75fe9-a5a2-4f74-bdb8-93cf638343d4','偈頌一百零三首  其三○','釋月磵','宋','宋诗','song-poetry','','[]','是亦剗，非亦剗，盡法無民。',31,'全唐诗/poet.song.235000.json','["是亦剗，非亦剗，盡法無民。", "山僧今日，曲爲指陳，幽州江口石人蹲。"]'),
('63d90880-b6e1-439c-bc55-6cb00bb8ea5e','偈頌一百零三首  其三一','釋月磵','宋','宋诗','song-poetry','','[]','從他節序又迎新，衲被蒙頭總不聞。',32,'全唐诗/poet.song.235000.json','["從他節序又迎新，衲被蒙頭總不聞。", "清曉偶然臺上立，幾多人錯認觀雲。"]'),
('e7b99c9b-e1ed-4adc-8b91-1bf8bdbd4646','偈頌一百零三首  其三二','釋月磵','宋','宋诗','song-poetry','','[]','曠大劫來明歷歷，緣何此夜眼方開。',32,'全唐诗/poet.song.235000.json','["曠大劫來明歷歷，緣何此夜眼方開。", "六年癡坐無折合，謾誑衆生出岫來。"]'),
('9dc867d7-142a-42ba-96b1-7f9aee4dc833','偈頌一百零三首  其三三','釋月磵','宋','宋诗','song-poetry','','[]','美如西子離金闕，嬌似楊妃下玉樓。',32,'全唐诗/poet.song.235000.json','["美如西子離金闕，嬌似楊妃下玉樓。", "十二金釵顛倒插，不風流處也風流。"]'),
('19c129bd-bbac-4a68-af8a-8ee94a0c9d7f','偈頌一百零三首  其三四','釋月磵','宋','宋诗','song-poetry','','[]','有準的，沒窠臼。',44,'全唐诗/poet.song.235000.json','["有準的，沒窠臼。", "有時覷捕全無，無時覷捕還有。", "取不得，捨不得，饒州城裏一分鈔，買柄芭花帚。"]'),
('67d03180-a743-4f5d-aa4d-d3b6316d6a06','偈頌一百零三首  其三五','釋月磵','宋','宋诗','song-poetry','','[]','鳥鳴芳樹，蛙閙葑池。',35,'全唐诗/poet.song.235000.json','["鳥鳴芳樹，蛙閙葑池。", "最親最切，總爲提持。", "不如三更枝上，一聲聲是杜鵑啼。"]'),
('676a508e-0dc7-4c93-97be-7e5aeb07553a','偈頌一百零三首  其三六','釋月磵','宋','宋诗','song-poetry','','[]','西江十八灘聲，太白峰頭同一眼聽。',58,'全唐诗/poet.song.235000.json','["西江十八灘聲，太白峰頭同一眼聽。", "東海潑天濤瀾，集雲峰頂同一耳觀。", "眼耳俱忘，觀聽皆滅。", "三十年後重新舉，舜若多神驚吐舌。"]'),
('6f75929a-6142-466a-affe-11832a4cebec','偈頌一百零三首  其三七','釋月磵','宋','宋诗','song-poetry','','[]','一年將盡是今宵，自覺叢林未寂寥。',32,'全唐诗/poet.song.235000.json','["一年將盡是今宵，自覺叢林未寂寥。", "莫莫堂前香藹藹，十分春色上梅稍。"]'),
('d8b57c5a-dc10-4df9-a8ac-09a83a600f19','偈頌一百零三首  其三八','釋月磵','宋','宋诗','song-poetry','','[]','昔日玲瓏岩頂上，無端日午現妖星。',68,'全唐诗/poet.song.235000.json','["昔日玲瓏岩頂上，無端日午現妖星。", "黑光照耀四天下，眩惑蠢動并含靈。", "人人盡指爲太白，山僧親識破，元却是長庚。", "諸人只今要見麽，此去明州十萬程。"]'),
('5f7258d3-6c4c-4d80-b013-2974fd93abf6','偈頌一百零三首  其三九','釋月磵','宋','宋诗','song-poetry','','[]','等閑拈起一莖草，貴如泥土賤如金。',32,'全唐诗/poet.song.235000.json','["等閑拈起一莖草，貴如泥土賤如金。", "活能死兮死能活，那箇師僧病最深。"]'),
('33260e65-a1fa-48d4-a267-9e32c2ec2d5f','偈頌一百零三首  其四○','釋月磵','宋','宋诗','song-poetry','','[]','雲開萬里乾坤闊，玉漏聲沈夜未央。',32,'全唐诗/poet.song.235000.json','["雲開萬里乾坤闊，玉漏聲沈夜未央。", "一片靈明輕發現，滿天滿地撒寒光。"]'),
('4c1178dc-d594-414a-99ae-a81fa4587f44','偈頌一百零三首  其四一','釋月磵','宋','宋诗','song-poetry','','[]','兩堂首座，一人拈出照乘之珠，一人拈出連城之璧。',46,'全唐诗/poet.song.235000.json','["兩堂首座，一人拈出照乘之珠，一人拈出連城之璧。", "臨濟尋常喝似雷奔，者裏下得一喝，何止價增十倍。"]'),
('fa7264d2-70bc-4c27-8e46-c8351a1b01d6','偈頌一百零三首  其四二','釋月磵','宋','宋诗','song-poetry','','[]','一機不露，萬機寢削。',28,'全唐诗/poet.song.235000.json','["一機不露，萬機寢削。", "今日當陽，提者一著。", "荆山之玉輕抵鵲。"]'),
('62fe0c5c-04b2-4873-8685-ceca758fbec5','偈頌一百零三首  其四三','釋月磵','宋','宋诗','song-poetry','','[]','如佛見佛，佛無異見。',42,'全唐诗/poet.song.235000.json','["如佛見佛，佛無異見。", "如法說法，法無異說。", "只如鴉鳴鵲噪，鶑啼燕語，是有異說，是無異說。"]'),
('be3b8c9d-57f7-430d-80eb-df4456b2082b','偈頌一百零三首  其四四','釋月磵','宋','宋诗','song-poetry','','[]','子得其用，父得其體。',32,'全唐诗/poet.song.235000.json','["子得其用，父得其體。", "互呈醜惡，挂人唇齒。", "至今茶樹上，葉葉哭春雨。"]'),
('e8e6e716-b378-4b20-9f73-5af4d8986628','偈頌一百零三首  其四五','釋月磵','宋','宋诗','song-poetry','','[]','世尊拈花，南泉指花，靈雲桃花，智門蓮花，總是空花，添得衲僧眼中花。',49,'全唐诗/poet.song.235000.json','["世尊拈花，南泉指花，靈雲桃花，智門蓮花，總是空花，添得衲僧眼中花。", "諸人若要發明心花，直須鐵樹開花。"]'),
('8d92840e-dbf3-4fb6-a249-c813e0b745d7','偈頌一百零三首  其四六','釋月磵','宋','宋诗','song-poetry','','[]','世尊有密語，今古無人舉。',44,'全唐诗/poet.song.235000.json','["世尊有密語，今古無人舉。", "等閑舉得最分明，夜來滴滴簷頭雨。", "諸人睡著不曾知，付與村農自歌舞。"]'),
('0f7c8265-5532-498f-8218-7c6d24c13dbb','偈頌一百零三首  其四七','釋月磵','宋','宋诗','song-poetry','','[]','道在屎溺，道在稊稗，道在瓦礫。',31,'全唐诗/poet.song.235000.json','["道在屎溺，道在稊稗，道在瓦礫。", "蕩蕩一條官驛路，何須特地栽荆棘。"]'),
('cb1cfd56-2903-458e-912a-16e708a8f3d8','偈頌一百零三首  其四八','釋月磵','宋','宋诗','song-poetry','','[]','趙州禪在口皮邊，雲門禪若九轉透瓶丹，總是欺胡瞞漢。',43,'全唐诗/poet.song.235000.json','["趙州禪在口皮邊，雲門禪若九轉透瓶丹，總是欺胡瞞漢。", "道難即易，道易即難，金烏一吸滄溟乾。"]'),
('2149139d-d75c-48ea-87c4-cdda9fbd450f','偈頌一百零三首  其四九','釋月磵','宋','宋诗','song-poetry','','[]','天下名山到因脚，六州之鐵難鑄錯。',32,'全唐诗/poet.song.235000.json','["天下名山到因脚，六州之鐵難鑄錯。", "而今老大却惺惺，倒握茶瓢當木杓。"]'),
('f4da3733-a4c1-427d-ad19-ce38d3419eff','偈頌一百零三首  其五○','釋月磵','宋','宋诗','song-poetry','','[]','憨彌勒，胡達磨。',48,'全唐诗/poet.song.235000.json','["憨彌勒，胡達磨。", "驀劄相逢，圍爐打坐。", "或說當來下生，或說開花結果。", "者匙火筯笑呵呵，總是認橘皮作火。"]'),
('3ac7a17c-afc8-4b02-9962-380758bf70ce','偈頌一百零三首  其五一','釋月磵','宋','宋诗','song-poetry','','[]','難難，虛空捏聚不成團。',37,'全唐诗/poet.song.235000.json','["難難，虛空捏聚不成團。", "易易，無手牧童穿穴鼻。", "也不難也不易，斷頭䑦子加篙枻。"]'),
('05923a60-3c80-4332-b28b-32854f1c363b','偈頌一百零三首  其五二','釋月磵','宋','宋诗','song-poetry','','[]','識得一，萬事畢，畢竟一作麽生識。',46,'全唐诗/poet.song.235000.json','["識得一，萬事畢，畢竟一作麽生識。", "不用天涯海角尋，日用當機明歷歷。", "諸人若更遲疑，分明爲汝指出。"]'),
('a0534c17-686e-4dad-8a20-0e5b41cf19cb','偈頌一百零三首  其五三','釋月磵','宋','宋诗','song-poetry','','[]','道無蹊徑，饒州東出永平門。',97,'全唐诗/poet.song.235000.json','["道無蹊徑，饒州東出永平門。", "法無定相，木歲又除壬午曆。", "冥運潜舒，玄機尚戢。", "過去已過去，未來猶未來。", "直得天凝地閉，雪老冰枯，蟄戶未開，龍無龍句。", "正當此時，諸人性命，落在甚處。", "一聲鳴爆竹，天地悉皆春。"]'),
('5a2aae8d-b584-46c4-bbeb-8b185b4e5760','偈頌一百零三首  其五四','釋月磵','宋','宋诗','song-poetry','','[]','趙州下牒求鴿，直得四稜踏地。',28,'全唐诗/poet.song.235000.json','["趙州下牒求鴿，直得四稜踏地。", "這僧蔗咬甜頭，不覺隨他圈繢。"]'),
('88ea05a2-7f4f-4680-8306-b5c29a8120d2','偈頌一百零三首  其五五','釋月磵','宋','宋诗','song-poetry','','[]','行亦禪，坐亦禪，語默動靜體安然。',16,'全唐诗/poet.song.235000.json','["行亦禪，坐亦禪，語默動靜體安然。"]'),
('5d5be246-39f7-4524-8d99-c6d8171dccd7','偈頌一百零三首  其五六','釋月磵','宋','宋诗','song-poetry','','[]','臘月火燒山，將軍度鐵關。',24,'全唐诗/poet.song.235000.json','["臘月火燒山，將軍度鐵關。", "陣雲千里遠，獨奏凱歌還。"]'),
('f074ecb1-6c1c-4b97-9b06-c5d47baca254','偈頌一百零三首  其五七','釋月磵','宋','宋诗','song-poetry','','[]','蛟不識劍劍下死，虎不識穽穽中死。',53,'全唐诗/poet.song.235000.json','["蛟不識劍劍下死，虎不識穽穽中死。", "從上諸老，各設機關，甚於劍穽。", "汝等諸人，聞如不聞，見如不見，方有少分相應。"]'),
('ef80101f-17c6-4113-a553-6ea63a838afd','偈頌一百零三首  其五八','釋月磵','宋','宋诗','song-poetry','','[]','新年頭佛法，鏡清道有，智門道無。',32,'全唐诗/poet.song.235000.json','["新年頭佛法，鏡清道有，智門道無。", "行盡江南江北路，家家門首釘桃符。"]'),
('dbf88b9c-9744-4c21-9452-2f6c59bcf092','偈頌一百零三首  其五九','釋月磵','宋','宋诗','song-poetry','','[]','漁舟一個兩個欵乃歌聲，楊柳三株四株低垂金線。',59,'全唐诗/poet.song.235000.json','["漁舟一個兩個欵乃歌聲，楊柳三株四株低垂金線。", "佛祖玄機，十分成現。", "魯公亭上來來往往，多少衲僧阿誰親見。", "見沙禽已在浮洲岸。"]'),
('88138846-99a3-4344-9d25-7bee61640bfa','偈頌一百零三首  其六○','釋月磵','宋','宋诗','song-poetry','','[]','佛病祖病，正在膏肓。',50,'全唐诗/poet.song.235000.json','["佛病祖病，正在膏肓。", "文殊是藥採將來都用不著，杜順灸豬左膊上亦錯商量。", "東湖水點菖蒲茶，個是單傳海上方。"]'),
('81600a84-e191-4d12-ac37-b5471568a41a','偈頌一百零三首  其六一','釋月磵','宋','宋诗','song-poetry','','[]','有縱跡，沒縫罅。',56,'全唐诗/poet.song.235000.json','["有縱跡，沒縫罅。", "善財七日尋覓不得，趙州五年分疏不下。", "汝等諸人，那邊經冬，者邊過夏。", "因甚問著，如聾似啞。", "水銀無假。"]'),
('c8c4d662-9034-4aeb-aa6d-8e74872af34b','偈頌一百零三首  其六二','釋月磵','宋','宋诗','song-poetry','','[]','天台山萬疊，信手輕撥轉。',24,'全唐诗/poet.song.235000.json','["天台山萬疊，信手輕撥轉。", "六種皆震動，玲瓏人人面。"]'),
('1dfff387-0b3e-4aad-9d2e-7a5f2c18c49b','偈頌一百零三首  其六三','釋月磵','宋','宋诗','song-poetry','','[]','周家有國聖明朝，甘蔗無端産異苗。',32,'全唐诗/poet.song.235000.json','["周家有國聖明朝，甘蔗無端産異苗。", "後代兒孫非五逆，百千鴆毒一瓢澆。"]'),
('209543ed-a6fa-4250-b1ac-dc9adca8c1d3','偈頌一百零三首  其六四','釋月磵','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太白峰頂雲，太湖波心月。',49,'全唐诗/poet.song.235000.json','["太白峰頂雲，太湖波心月。", "黑夜散清光，炎洲飛皓雪。", "不是古佛玄機，亦非諸祖妙訣。", "別別，萬像森羅驚吐舌。"]'),
('d3727846-e8ee-4131-a0a0-a4f1735dfbe0','偈頌一百零三首  其六五','釋月磵','宋','宋诗','song-poetry','','[]','真正法要，玄極祕密。',20,'全唐诗/poet.song.235000.json','["真正法要，玄極祕密。", "言語道斷，心行處滅。"]'),
('a2a46f00-0b30-417f-8087-fdd5600e637a','偈頌一百零三首  其六六','釋月磵','宋','宋诗','song-poetry','','[]','東村王老夜燒錢，掇轉須彌作案山。',32,'全唐诗/poet.song.235000.json','["東村王老夜燒錢，掇轉須彌作案山。", "途路紛紛未歸客，擡眸錯認白雲間。"]'),
('f02bccf1-d11c-44f9-a118-4b794330fe85','偈頌一百零三首  其六七','釋月磵','宋','宋诗','song-poetry','','[]','八十樵翁無頼查，芭鞋踏破亂山霞。',32,'全唐诗/poet.song.235000.json','["八十樵翁無頼查，芭鞋踏破亂山霞。", "那知一跡不到處，別有葛洪仙處家。"]'),
('9ece989f-767d-4126-9073-57b201eade40','偈頌一百零三首  其六八','釋月磵','宋','宋诗','song-poetry','','[]','大庾嶺頭，高安灘頭。',33,'全唐诗/poet.song.235000.json','["大庾嶺頭，高安灘頭。", "下盡手脚，結盡冤讎。", "箇事何曾得徹頭，禍在源頭。"]'),
('7d440a45-3120-4e83-a657-ba51c7a32d2b','偈頌一百零三首  其六九','釋月磵','宋','宋诗','song-poetry','','[]','大道平平無壅塞，無端特地設深坑。',32,'全唐诗/poet.song.235000.json','["大道平平無壅塞，無端特地設深坑。", "衲僧若具丈夫志，解向機先掉臂行。"]'),
('921738ee-39b8-49a8-b1ba-57b94de702ea','偈頌一百零三首  其七○','釋月磵','宋','宋诗','song-poetry','','[]','正覺山中夜氣清，瞿曇特地不惺惺。',32,'全唐诗/poet.song.235000.json','["正覺山中夜氣清，瞿曇特地不惺惺。", "却將曠劫無明種，認作浮雲缺處星。"]'),
('5f01b657-82dc-4977-a0d0-a07e95cf2357','偈頌一百零三首  其七一','釋月磵','宋','宋诗','song-poetry','','[]','黄蘗山頭三頓棒，集雲峰下四藤條。',44,'全唐诗/poet.song.235000.json','["黄蘗山頭三頓棒，集雲峰下四藤條。", "行不著，用得喬。", "堪笑大禪佛，小廝兒，錯將一滴，認作全潮。"]'),
('53bd1f83-19e2-43be-83f5-7dc8e395f7db','偈頌一百零三首  其七二','釋月磵','宋','宋诗','song-poetry','','[]','擊梧桐，驚老鳳。',28,'全唐诗/poet.song.235000.json','["擊梧桐，驚老鳳。", "戽九淵，縛獰龍。", "同不同，別有靈犀一點通。"]'),
('9633eeb0-cc1f-47c8-bfb8-b113998f64ed','偈頌一百零三首  其七三','釋月磵','宋','宋诗','song-poetry','','[]','寂歷梁峰歲月深，春風浩蕩入枯林。',32,'全唐诗/poet.song.235000.json','["寂歷梁峰歲月深，春風浩蕩入枯林。", "要開萬世無窮業，只在堅持一寸心。"]'),
('130aba18-9d3f-4483-8fbd-a9958b27d472','偈頌一百零三首  其七四','釋月磵','宋','宋诗','song-poetry','','[]','瞿曇錯認者星兒，動地驚天誰阿誰。',32,'全唐诗/poet.song.235000.json','["瞿曇錯認者星兒，動地驚天誰阿誰。", "奉勸諸人今夜裏，只消熟睡到雞啼。"]'),
('aaedc89d-a3a7-4672-a5a9-6f5de12040e3','偈頌一百零三首  其七五','釋月磵','宋','宋诗','song-poetry','','[]','雪後園林春正濃，玉容公子玉花驄。',32,'全唐诗/poet.song.235000.json','["雪後園林春正濃，玉容公子玉花驄。", "彫弓閑試黄金彈，打落天邊一個鴻。"]'),
('464d4cb8-2755-414f-ba5d-6f6c02420a95','偈頌一百零三首  其七六','釋月磵','宋','宋诗','song-poetry','','[]','江山處處東風軟，桃李紛紛春意酣。',32,'全唐诗/poet.song.235000.json','["江山處處東風軟，桃李紛紛春意酣。", "是滅度耶不滅度，當機識取老瞿曇。"]'),
('4bc2af4b-5f75-4da8-a9e8-6387c7f7ced0','偈頌一百零三首  其七七','釋月磵','宋','宋诗','song-poetry','','[]','普請摘茶，仰山撼樹。',39,'全唐诗/poet.song.235000.json','["普請摘茶，仰山撼樹。", "則川提籃，撿點將來落二三。", "入草一回親見得，枝枝葉葉是瞿曇。"]'),
('aea879e1-389e-466c-8d15-a2318378a7fa','偈頌一百零三首  其七八','釋月磵','宋','宋诗','song-poetry','','[]','雲門向廣寒宮裏呈月，圓悟向龍王宮裏呈珠。',35,'全唐诗/poet.song.235000.json','["雲門向廣寒宮裏呈月，圓悟向龍王宮裏呈珠。", "薦福雖臂長袖短，亦有一箇道處。"]'),
('f0e5784d-7a55-4cde-943a-cca92667e5ec','偈頌一百零三首  其七九','釋月磵','宋','宋诗','song-poetry','','[]','鐵面將軍騎鐵馬，喑嗚殺氣暗乾坤。',32,'全唐诗/poet.song.235000.json','["鐵面將軍騎鐵馬，喑嗚殺氣暗乾坤。", "縱饒勇銳如韓百，千里應須破膽魂。"]'),
('d2bc53b6-f6c7-42e4-9ea0-13b853a53dd7','偈頌一百零三首  其八○','釋月磵','宋','宋诗','song-poetry','','[]','昨日雨，今日雨。',53,'全唐诗/poet.song.235000.json','["昨日雨，今日雨。", "漁父謳歌，老農歡舞。", "堪笑蒲許林中，鄧師伯把不定，却向豆子山前打瓦皷。", "熟不熟，但看五月廿六。"]'),
('45f3a57b-d232-4b63-9251-56920634df43','偈頌一百零三首  其八一','釋月磵','宋','宋诗','song-poetry','','[]','誰駕燭龍，赫日當空。',75,'全唐诗/poet.song.235000.json','["誰駕燭龍，赫日當空。", "山河大地通身汗出，草木昆蟲無處潜蹤。", "昨夜三更，拄杖子驀然𨁝跳。", "觸著帝釋鼻孔，雨似盆傾。", "是汝諸人半醒半困，猶在夢中，喜喜歡歡是老農。"]'),
('3e9367cd-e363-46ee-8008-739330fca603','偈頌一百零三首  其八二','釋月磵','宋','宋诗','song-poetry','','[]','將軍矍鑠笑盈眉，鐵馬衝關舞戰旗。',32,'全唐诗/poet.song.235000.json','["將軍矍鑠笑盈眉，鐵馬衝關舞戰旗。", "指點陣雲千萬里，碧油幢裏醉金巵。"]'),
('7e3010f4-bc00-458b-ac4b-0dcda9656286','偈頌一百零三首  其八三','釋月磵','宋','宋诗','song-poetry','','[]','水盈萬壑，葉落三秋。',50,'全唐诗/poet.song.235000.json','["水盈萬壑，葉落三秋。", "漁板一聲飛野鴨，長空極目思悠悠。", "堪笑當年馬大師，無端杻著百丈鼻，直至如今痛不休。"]'),
('e8343eca-f157-4a3d-92d0-6fe5458e7d35','偈頌一百零三首  其八四','釋月磵','宋','宋诗','song-poetry','','[]','達磨西來，傳個策子。',47,'全唐诗/poet.song.235000.json','["達磨西來，傳個策子。", "少至萬言，多無一字。", "賤如金璧，貴如泥土。", "第一句爲君擧，聽著即聾，覷著即瞽。"]'),
('1db98bf8-2696-453f-9dc1-18602a775800','偈頌一百零三首  其八五','釋月磵','宋','宋诗','song-poetry','','[]','參得到，悟得徹，自謂龍門上客。',34,'全唐诗/poet.song.235000.json','["參得到，悟得徹，自謂龍門上客。", "薦福有棒，亦未到伊喫。", "行百里者半九十。"]'),
('49f1db2e-4afb-46b7-ba9c-f0c9fc106ff7','偈頌一百零三首  其八六','釋月磵','宋','宋诗','song-poetry','','[]','當年竺國此時節，浄飯王宮生悉達。',32,'全唐诗/poet.song.235000.json','["當年竺國此時節，浄飯王宮生悉達。", "老倒雲門棒頭短，千古萬古爲妖孽。"]'),
('322888d5-3efd-41bd-98b7-fddd7274c428','偈頌一百零三首  其八七','釋月磵','宋','宋诗','song-poetry','','[]','總總林林，厥疾彌深。',44,'全唐诗/poet.song.235000.json','["總總林林，厥疾彌深。", "文殊既無靈驗之藥，盧扁難下膏肓之針。", "山僧有箇秘傳訣，掃除萬病是無心。"]'),
('d7c333f2-78fa-44a0-9f14-db8ff1c858d9','偈頌一百零三首  其八八','釋月磵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東湖東湖見，西湖西湖見。',24,'全唐诗/poet.song.235000.json','["東湖東湖見，西湖西湖見。", "八月十五夜，皎皎如鏡面。"]'),
('a347ba99-0e6e-4287-b5d3-309aa3a2d166','偈頌一百零三首  其八九','釋月磵','宋','宋诗','song-poetry','','[]','衲僧家不著僧求，不著法求，不著佛求。',35,'全唐诗/poet.song.235000.json','["衲僧家不著僧求，不著法求，不著佛求。", "綠楊隄上芰荷香裏，三三兩兩數沙鷗。"]'),
('44eed38e-ec7b-4720-9b8c-cb48f8438dd0','偈頌一百零三首  其九○','釋月磵','宋','宋诗','song-poetry','','[]','投子欲挂羚羊之角，爭奈臭肉來蠅。',30,'全唐诗/poet.song.235000.json','["投子欲挂羚羊之角，爭奈臭肉來蠅。", "榮禪客獵犬無靈性，徒戀枯樁。"]'),
('27b52e40-6d0d-4659-b292-62693f0b33fd','偈頌一百零三首  其九一','釋月磵','宋','宋诗','song-poetry','','[]','名不得，狀不得，不可得中親搆得。',43,'全唐诗/poet.song.235000.json','["名不得，狀不得，不可得中親搆得。", "絕瑕翳，明皎潔，大似中秋夜明月。", "別別，廣寒宮殿爛銀闕。"]'),
('5d907666-367f-420c-8324-ecfe76bc1d52','偈頌一百零三首  其九二','釋月磵','宋','宋诗','song-poetry','','[]','金蓮萬朵爛熒□，照徹銀霄第幾層。',32,'全唐诗/poet.song.235000.json','["金蓮萬朵爛熒□，照徹銀霄第幾層。", "無量劫來明歷歷，須知元本是心燈。"]'),
('55359a48-985a-4ac2-9ceb-8a657f561fa2','偈頌一百零三首  其九三','釋月磵','宋','宋诗','song-poetry','','[]','今古事茫茫，陰陽割昏曉。',72,'全唐诗/poet.song.235000.json','["今古事茫茫，陰陽割昏曉。", "碧露綴小桃，綠線垂堤柳。", "燕語雕梁，蛙鳴芳草。", "鐘聲雜報聲，大底大，小底小。", "山僧見了，直得培增慎惱，一片涅柈心，狼藉知多少。"]'),
('5540ad71-2723-4c06-9c07-1a4eaaf3a396','偈頌一百零三首  其九四','釋月磵','宋','宋诗','song-poetry','','[]','不是而上事，亦非格外機。',26,'全唐诗/poet.song.235000.json','["不是而上事，亦非格外機。", "蚯蚓抹過東海，蝍蟟吞却須彌。"]'),
('f2b79f21-de89-41bd-9c63-61db0d08cc62','偈頌一百零三首  其九五','釋月磵','宋','宋诗','song-poetry','','[]','波斯手裏捻生鐵，把作希奇無價珍。',32,'全唐诗/poet.song.235000.json','["波斯手裏捻生鐵，把作希奇無價珍。", "識破分文元不直，寒光笑衮浪花新。"]'),
('f501e35b-1628-401e-a1d7-7536ce216c82','偈頌一百零三首  其九六','釋月磵','宋','宋诗','song-poetry','','[]','魚行水濁，鳥飛毛落。',28,'全唐诗/poet.song.235000.json','["魚行水濁，鳥飛毛落。", "若起一毫佛見法見，盡六州之鐵難鑄錯。"]'),
('684a9342-eb8a-4729-91f6-2bb10d94ee73','偈頌一百零三首  其九七','釋月磵','宋','宋诗','song-poetry','','[]','破砂盆，無貴賤。',38,'全唐诗/poet.song.235000.json','["破砂盆，無貴賤。", "等閑拈向昌江上，盡大地人同一見。", "彷彿宣州木瓜，依稀景鎮寶變。"]'),
('6ccb87e0-0693-4d61-a4aa-c025963384af','偈頌一百零三首  其九八','釋月磵','宋','宋诗','song-poetry','','[]','指臨濟，見黄蘗，陷虎機深。',46,'全唐诗/poet.song.235000.json','["指臨濟，見黄蘗，陷虎機深。", "接雲門，嗣雪峰，送賦過界。", "薦福聻雲晴，楚天春欲雨，三草二木皆萌芽。"]'),
('4d891c66-7a07-4e55-9083-7f6e6d5cc58a','偈頌一百零三首  其九九','釋月磵','宋','宋诗','song-poetry','','[]','東湖一櫂過侯溪，兩兩相看眼似眉。',32,'全唐诗/poet.song.235000.json','["東湖一櫂過侯溪，兩兩相看眼似眉。", "若問陳年閑佛法，杜鵑聲在最高枝。"]'),
('968de9ae-f1d6-4e39-99dd-59ff1a09d356','偈頌一百零三首  其一○○','釋月磵','宋','宋诗','song-poetry','','[]','奪賊鎗兮便殺賊，山河大地血淋漓。',32,'全唐诗/poet.song.235000.json','["奪賊鎗兮便殺賊，山河大地血淋漓。", "今朝冷地翻交轉，萬壘西風鐵馬嘶。"]'),
('934af76d-cb09-4875-9a60-7bdd4666f33c','偈頌一百零三首  其一○一','釋月磵','宋','宋诗','song-poetry','','[]','鳳脫千絲之網，魚離百搳之鈎。',30,'全唐诗/poet.song.235000.json','["鳳脫千絲之網，魚離百搳之鈎。", "沒拘束，魚悠悠，明月清風天地秋。"]'),
('d00aed7f-70f6-4925-8fb0-b427c80abe03','偈頌一百零三首  其一○二','釋月磵','宋','宋诗','song-poetry','','[]','厖眉雪頂採樵翁，誤入天台第幾重。',32,'全唐诗/poet.song.235000.json','["厖眉雪頂採樵翁，誤入天台第幾重。", "回首不知塵世隔，月明知樂響瑶宮。"]'),
('b849f4d7-b0fd-4285-9c5a-6240c74ab0fc','偈頌一百零三首  其一○三','釋月磵','宋','宋诗','song-poetry','','[]','地釣東湖二十年，眼頭老却幾風煙。',32,'全唐诗/poet.song.235000.json','["地釣東湖二十年，眼頭老却幾風煙。", "等閑笑捲絲綸去，秋滿江山月滿天。"]'),
('7442f927-221e-4197-8c34-6c2a657d9e1d','普說三轉語頌出示衆  其一','釋月磵','宋','宋诗','song-poetry','','[]','拶到途窮路絕處，灼然命若一絲危。',32,'全唐诗/poet.song.235000.json','["拶到途窮路絕處，灼然命若一絲危。", "當機燒尾奔當火，那箇魚騰碧漢時。"]'),
('e73eeb40-2b87-49bc-b029-546ac87e419d','普說三轉語頌出示衆  其二','釋月磵','宋','宋诗','song-poetry','','[]','太華峰頭有一物，怪如猛虎踞林丘。',32,'全唐诗/poet.song.235000.json','["太華峰頭有一物，怪如猛虎踞林丘。", "擡眸子細認得著，充畟陳年箇石頭。"]'),
('ac22758b-0fb2-49e2-b1e4-67ce4a95eb1f','普說三轉語頌出示衆  其三','釋月磵','宋','宋诗','song-poetry','','[]','等閑拈起一機看，頓覺重重海嶽昏。',32,'全唐诗/poet.song.235000.json','["等閑拈起一機看，頓覺重重海嶽昏。", "劃爾一聲轟霹靂，木人聞後更誰聞。"]'),
('d9b5aa03-9256-4d56-892b-f6115bb49152','偈頌四首  其一','釋月磵','宋','宋诗','song-poetry','','[]','瑞岩惺惺，薦福莫莫。',53,'全唐诗/poet.song.235000.json','["瑞岩惺惺，薦福莫莫。", "瞞頇佛性，束之高閣。", "月磵別用的當一著，易覷捕，難執捉。", "無意求時却宛然，有心月處還應錯。"]'),
('78da1e37-16b4-4d19-a8b3-e6092d4735cd','偈頌四首  其二','釋月磵','宋','宋诗','song-poetry','','[]','彩雲影裏仙人現，手把紅羅扇遮面。',32,'全唐诗/poet.song.235000.json','["彩雲影裏仙人現，手把紅羅扇遮面。", "急須著眼看仙人，莫看仙人手中扇。"]'),
('1666bef4-64dc-4a45-8e12-bc71ad48d372','偈頌四首  其三','釋月磵','宋','宋诗','song-poetry','','[]','一輪明月，兩度中秋。',30,'全唐诗/poet.song.235000.json','["一輪明月，兩度中秋。", "不知今夜裏，誰復再登樓。", "雲開萬里桂香浮。"]'),
('98aaa28c-ed29-4275-892f-45c9eac11f7d','偈頌四首  其四','釋月磵','宋','宋诗','song-poetry','','[]','庭前桂綻金粟黄，滿地散清香。',46,'全唐诗/poet.song.235000.json','["庭前桂綻金粟黄，滿地散清香。", "魯直當年參晦堂，吾無隠乎爾。", "當下錯承當，累及叢林，千古更錯商量。"]'),
('138846d5-1931-47d7-b6a4-6b2a4557e1a1','東岩壽儀贊','釋月磵','宋','宋诗','song-poetry','','[]','以幻智燈，無幽不燭。',46,'全唐诗/poet.song.235000.json','["以幻智燈，無幽不燭。", "舌頭較善，手頭較毒。", "中興東圓，晚據天育。", "盡東南界內，數來惡業，無這尊宿。"]'),
('15aa2a3b-c93d-4a09-871f-190fb5d99682','題丹霞燒木佛圖','釋月磵','宋','宋诗','song-poetry','','[]','丹霞燒木佛，義出豐年。',38,'全唐诗/poet.song.235000.json','["丹霞燒木佛，義出豐年。", "院主眉須墮，彩奔齪家。", "法海浪平春晝永，戲將老手拔鯨牙。"]'),
('b8446efd-362f-40a3-b436-ae7f9793ac54','送欽禪人遊嶽','釋月磵','宋','宋诗','song-poetry','','[]','雪峰不登嶽，辛苦事參訪。',96,'全唐诗/poet.song.235000.json','["雪峰不登嶽，辛苦事參訪。", "虛空開笑口，猿鶴增悲悵。", "我昔乘天風，絕頂倚藤杖。", "羣山如子來，萬境供一望。", "至今清夜夢，吟嘯煙雲上。", "道人膽氣粗，一葉吞湘浪。", "欲識活祖師，告君語非妄。", "綠苔裹斷磚，便是南岳讓。"]'),
('46b8c3ba-b9ec-4a52-8f91-a3b4a3b0d9d5','送仁姪入浙','釋月磵','宋','宋诗','song-poetry','','[]','古來行脚有樣子，莫只遊山并玩水。',128,'全唐诗/poet.song.235000.json','["古來行脚有樣子，莫只遊山并玩水。", "江南兩浙多禪林，带眼直須先带耳。", "數十年來已寂寥，況復亂離生死裏。", "一言非理不可道，一武非地不可履。", "善友師教不可捨，庸鄙强饕不可擬。", "彼所非者誠可監，我所長者不可恃。", "一切妄想生死因，參須實參明自己。", "他日歸來如所囑，痛棒依前分付你。"]'),
('69ea4e64-9b0d-4c77-bfaa-a636e9994430','送彥侍者','釋月磵','宋','宋诗','song-poetry','','[]','瑞陽俊彥彥侍者，貌山澤癯語灑灑。',96,'全唐诗/poet.song.235000.json','["瑞陽俊彥彥侍者，貌山澤癯語灑灑。", "訪我東湖竹邊寺，爲言來自遠公社。", "殷勤載覓贈行語，有語非語筆難寫。", "渾崙一句持贈君，不可取兮亦非捨。", "歸見溪邊老菸菟，當機有掌休便打。", "免教臭口向人開，道汝又捋虎鬚也。"]'),
('8249633f-b86b-4c05-ae79-6feaab1dfef1','借雪竇韻送淳維那','釋月磵','宋','宋诗','song-poetry','','[]','吳山碧，楚江碧，天地茫茫渺何極。',88,'全唐诗/poet.song.235000.json','["吳山碧，楚江碧，天地茫茫渺何極。", "出門無是無不是，著眼當機須辨的。", "諸方門戶潑天開，真底奚真僞奚僞。", "燈籠露柱盡知識，庭前柏樹西來意。", "春風意，春風急。", "千里萬里誰能及，湖水蹙天波欲立。"]'),
('5cff50e2-b6a7-484c-8954-4a3256ba2d8d','送妙達往浙','釋月磵','宋','宋诗','song-poetry','','[]','逸汝短句意不盡，送汝長句無可寫。',96,'全唐诗/poet.song.235000.json','["逸汝短句意不盡，送汝長句無可寫。", "不長不短賦一篇，適值今朝忙不暇。", "臨別草草笑與言，真箇參禪忘晝夜。", "一回參到無參處，猶是上宿道傍舍。", "吳越青山千萬重，揀箇鉢囊何處挂。", "娘生兩眼驀然開，方信山僧真可駡。"]'),
('46983104-b9e0-4b76-9643-0eca286abfff','送印空書記','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一印印空來點窄，三賢十聖那可測。',74,'全唐诗/poet.song.235000.json','["一印印空來點窄，三賢十聖那可測。", "匡廬萬疊雲錦鄉，鄱湖萬頃水精國。", "篆文見得甚分明，元是一字不著畫。", "拍來號令人與天，頓教古道長顔色。", "我應隔江，合十聲嘖。"]'),
('4c3195f0-1b0f-4d29-8b19-757e573088b3','送僧','釋月磵','宋','宋诗','song-poetry','','[]','摘楊花，摘楊花，唵摩尼吽㗶吒。',50,'全唐诗/poet.song.235000.json','["摘楊花，摘楊花，唵摩尼吽㗶吒。", "便恁麽會已是錯，不恁麽會尤更差。", "一回撞著無面目老骨檛，方知元不在天涯。"]'),
('ce64e8d8-d9cd-42f0-84ba-5b098ee041c6','送圓侍者','釋月磵','宋','宋诗','song-poetry','','[]','香林侍雲門，閲十八寒暑。',72,'全唐诗/poet.song.235000.json','["香林侍雲門，閲十八寒暑。", "剛把野狐涎，涴却所衣褚。", "汝侍吾筆硯，我元無一語。", "乃以羊角峰，蘸竭東湖水。", "學本無止法，猶海深無底。", "斥鷃從卑飛，大鵬九萬里。"]'),
('e37edff5-00f7-44c9-9367-456fa058c701','送付藏主','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','老我無堪涉世艱，鬢毛新糝雪霜斑。',100,'全唐诗/poet.song.235000.json','["老我無堪涉世艱，鬢毛新糝雪霜斑。", "有人來自廬山中，眼如點漆音如鐘。", "銜袖出新卷，兩眼驚且眩。", "方知親自香溪哥室來，老婆心切言詼詼。", "三世諸佛一口吞，一大藏教徹底翻。", "叢林鄉社有此俊邁之英才，我輩可老可死無餘懷。"]'),
('843d950d-9646-4737-a918-2af6559ca55c','印月','釋月磵','宋','宋诗','song-poetry','','[]','性海湛如，心月皎如。',60,'全唐诗/poet.song.235000.json','["性海湛如，心月皎如。", "水與月融，月與水攝。", "水月交光，印文呈露。", "山河大地，萬象森羅。", "一印印定，虛徹洞明。", "廓兮烱兮，以證來觀。"]'),
('bcf44047-f166-4342-879a-468726839d52','送福上人','釋月磵','宋','宋诗','song-poetry','','[]','禪欲參兮道欲學，莫負娘生一雙脚。',76,'全唐诗/poet.song.235000.json','["禪欲參兮道欲學，莫負娘生一雙脚。", "培塿不足登，蹄涔應易涸。", "觀水須觀百千溟渤之鉅海，登山須登萬丈嵩華之喬嶽。", "高高高無極，深深深無底。", "一回見得親，冥鴻千萬里。"]'),
('10fc9958-0661-46e1-afe1-5b8f4b75e285','正秀行脚','釋月磵','宋','宋诗','song-poetry','','[]','長老小師不參禪，只爲尋常見得慣。',128,'全唐诗/poet.song.235000.json','["長老小師不參禪，只爲尋常見得慣。", "汝今別我要行脚，與汝謾說箇公案。", "我亦黄龍長老兒，少年發志大猶低。", "一筇行徧半天下，要勘諸方老古錐。", "發足仍發勇猛志，莫把參禪當容易。", "只今諸老若晨星，半人所在亦須至。", "山僧年老已心孤，那堪送汝更寫偈。", "出門步步好爲人，九萬里程一鵬翅。"]'),
('e52c2952-006e-47b5-8d30-8581d3706dd8','進無止','釋月磵','宋','宋诗','song-poetry','','[]','灼然大道如大海，浩無涯涘深無底。',80,'全唐诗/poet.song.235000.json','["灼然大道如大海，浩無涯涘深無底。", "摐摐萬有資之生，生生不已由茲始。", "飲者大小隨所量，隨量滿足皆厭喜。", "有人直欲探其源，得其源矣進無止。", "若從涓滴識全潮，方信萬波元一水。"]'),
('cbd86def-1815-4db2-b572-76fba1561a82','達此宗','釋月磵','宋','宋诗','song-poetry','','[]','若論此道若須彌，根四部洲高無極。',62,'全唐诗/poet.song.235000.json','["若論此道若須彌，根四部洲高無極。", "日月循環無晝夜，毗嵐縱作無變易。", "欲達此宗須造顛，徧參閩楚幾山碧。", "一回見得親，萬疊巍峨只卷石。"]'),
('915ae03a-c2e2-430d-8cfc-809038c85599','雕匠羌若正','釋月磵','宋','宋诗','song-poetry','','[]','古汗有敏匠，能作諸佛像。',26,'全唐诗/poet.song.235000.json','["古汗有敏匠，能作諸佛像。", "有相皆是妄，無相之中有真相。"]'),
('c1548d25-b431-43bb-8cfa-2318210c1c4d','德詳大師禮補陀五臺','釋月磵','宋','宋诗','song-poetry','','[]','五臺峩峩五雲裏，補陀峩峩東海底。',112,'全唐诗/poet.song.235000.json','["五臺峩峩五雲裏，補陀峩峩東海底。", "大士元不在其中，誤賺平人知幾幾。", "江南吳越諸導師，短偈長篇費言語。", "老僧有語寫不得，一再殷勤奉勸汝。", "若論觀音與曼殊，盡恒沙界無不是。", "灼然端的要見渠，不用千里與萬里。", "只消著眼未生前，面目堂堂即自己。"]'),
('1769ae09-1f56-48b4-83a8-d46dfd323f45','竹隠','釋月磵','宋','宋诗','song-poetry','','[]','香嚴去溈阜，欲南陽種竹。',72,'全唐诗/poet.song.235000.json','["香嚴去溈阜，欲南陽種竹。", "片瓦太無端，等閑相擊觸。", "累及忘所知，嘉名受污辱。", "有人今効尤，千頃種寒玉。", "澹然冰霜中，歲晚樂幽獨。", "慎勿輕擊著，清風自然足。"]'),
('73d163e2-339f-43cf-99b1-e62fac432393','送善禪人','釋月磵','宋','宋诗','song-poetry','','[]','學道如牧牛，尋牛須訪跡。',48,'全唐诗/poet.song.235000.json','["學道如牧牛，尋牛須訪跡。", "牛既已純熟，牧乃便省力。", "靠壁舊烏藤，一朝生兩翼。", "天地豈不大，去當六月息。"]'),
('c510dd2f-cad0-4217-9479-485388eff134','送瑊侍者','釋月磵','宋','宋诗','song-poetry','','[]','有佛處不得住，斗門硬閘。',89,'全唐诗/poet.song.235000.json','["有佛處不得住，斗門硬閘。", "無佛處急走過，攔江鐵網。", "趙州立者兩重關，致使學者欲去被去礙，欲住被住礙。", "無自由分，伶利衲僧。", "拶得透，跳得出，方爲慶快。", "雖然，更須知五里單牌，十里雙堠始得。"]'),
('a49baf0d-b1bf-4511-aa37-3cf29a0b6209','送僧','釋月磵','宋','宋诗','song-poetry','','[]','勇猛發心要行脚，莫把光陰空費却。',48,'全唐诗/poet.song.235000.json','["勇猛發心要行脚，莫把光陰空費却。", "青山綠水眼中塵，梵語唐言皆毒藥。", "瞥轉機先親見徹，萬里秋空飛一鶚。"]'),
('69301a86-ba4d-4522-975a-57e6583bcc99','淵侍者歸天童西岩和尚塔所','釋月磵','宋','宋诗','song-poetry','','[]','堂堂幻智翁，爲宋鉅魔孽。',84,'全唐诗/poet.song.235000.json','["堂堂幻智翁，爲宋鉅魔孽。", "我昔誤見之，痛棒打得折。", "冷地驀思量，有屈無處雪。", "淵也長庚來，言侰曾不滅。", "幻出窣堵波，黄金充一國。", "村草步頭草，香風春茁茁。", "有語遠寄將，捻鼻消一咄。"]'),
('e96e348f-2aeb-47c7-a9ef-09ced14f9bb8','送竺源合侍者','釋月磵','宋','宋诗','song-poetry','','[]','佛道實幽遠，未易可窺測。',72,'全唐诗/poet.song.235000.json','["佛道實幽遠，未易可窺測。", "著眼朕非先，猶鬲恒沙國。", "一切俱放下，百不會不知。", "只在鼻笑頭，元不鬲絲厘。", "吾道今如何，秋風落葉多。", "滿手握春風，吹醒冰霜柯。"]'),
('01308625-63cf-4dc5-bcbc-ca3b5c5bf3ef','送則自然書記','釋月磵','宋','宋诗','song-poetry','','[]','老來不寫送行語，送子不可無一句。',120,'全唐诗/poet.song.235000.json','["老來不寫送行語，送子不可無一句。", "幾回特地費思量，有句可寫難寫意。", "從上佛與祖，別無可指示。", "只要息心仍息念，牆壁木偶恰相似。", "驀然見得親，不負出家志。", "茫茫日月去如飛，轉得眼來老已至。", "當思祖道重千鈞，凜如一髮孰可寄。", "釣雪磯頭瞠老眼，秋空萬里孤鴻遠。"]'),
('d24a0d49-1078-4df4-b3d0-a6dbbf917e46','送舜禪往廬山','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','行脚須具行脚眼，當以前輩爲標格。',68,'全唐诗/poet.song.235000.json','["行脚須具行脚眼，當以前輩爲標格。", "近來叢席說廬山，禪子競趨不吳越。", "汝今直往虎侯溪，一香三拜依位立。", "棒如雨點打將來，當下知歸方是行脚事云畢。"]'),
('1b7576ed-3ff2-4398-a057-29aaf748e798','宗藏主之吳越','釋月磵','宋','宋诗','song-poetry','','[]','嫋嫋春風軟，點點春山遠。',58,'全唐诗/poet.song.235000.json','["嫋嫋春風軟，點點春山遠。", "如來禪與祖師意，滿眼滿耳無不是。", "短筇撥著南北峰，錢塘萬頃寒濤舂。", "一笑歸去來，雲中五老笑顔開。"]'),
('26e99967-0c48-4e41-916d-0e47f392f934','送曇昱姪禮拜浄慈愚極老叔','釋月磵','宋','宋诗','song-poetry','','[]','汝今別我去行脚，聽我殷勤重告汝。',96,'全唐诗/poet.song.235000.json','["汝今別我去行脚，聽我殷勤重告汝。", "人身難得今已得，直須著意明自己。", "只今叢林未寂寥，四海一翁老愚叔。", "惠日峯前九拜時，照顧粗拳當面築。", "白髮盈顛七十翁，期汝有成志超越。", "爲報江海幾故人，晚年富貴一磯雪。"]'),
('c04e34b2-3dbc-43d3-98a4-5d2281ceec1c','送辨藏主','釋月磵','宋','宋诗','song-poetry','','[]','老眼正昏明，喜見哥寧馨。',59,'全唐诗/poet.song.235000.json','["老眼正昏明，喜見哥寧馨。", "吐語{釒得}璆玕，秀發禪林英。", "斯道猶大厦，頹焉欲傾阤。", "獨支期敏手，毋擅立壑美。", "大鵬一擧九萬里。"]'),
('148afe29-36c5-48a9-b6c7-4d05288c7d74','珍維那歸徑山就簡虎岩和尚','釋月磵','宋','宋诗','song-poetry','','[]','水雲相望楚與吳，三年不作問安書。',80,'全唐诗/poet.song.235000.json','["水雲相望楚與吳，三年不作問安書。", "英英禪子來岩邊，爲我細說岩平安。", "但言倒握無形棒，若佛若祖難近傍。", "煩寄一語休拍盲，本來無佛無衆生。", "不妨借取腕頭力，永爲大地人知識。"]'),
('1600882f-c97c-4a5c-ac81-8a6175578d67','禮仗錫巳禪師塔','釋月磵','宋','宋诗','song-poetry','','[]','吞却七峰無寸土，灼然無地著屍骸。',32,'全唐诗/poet.song.235000.json','["吞却七峰無寸土，灼然無地著屍骸。", "不知當日誰閑管，剛把虛空掘窖埋。"]'),
('9810d6f9-6018-4238-beb5-1a3a10b53a32','禮思大禪師塔','釋月磵','宋','宋诗','song-poetry','','[]','巋然七十二峰秀，靈骨溫溫色尚新。',32,'全唐诗/poet.song.235000.json','["巋然七十二峰秀，靈骨溫溫色尚新。", "我若等閑開坐具，阿師無地著渾身。"]'),
('8ad5f862-fe5a-489e-ad34-da0878972906','禮楊岐禪師塔','釋月磵','宋','宋诗','song-poetry','','[]','正脈如今一綫微，不堪惆悵淚交頤。',32,'全唐诗/poet.song.235000.json','["正脈如今一綫微，不堪惆悵淚交頤。", "冷雲深沒楚山頂，全體當年縮項時。"]'),
('cde7553b-c4dc-401d-b151-04f3680e663d','悼霍山','釋月磵','宋','宋诗','song-poetry','','[]','老倒霍山無頼吒，妙高峰頂恣拋沙。',32,'全唐诗/poet.song.235000.json','["老倒霍山無頼吒，妙高峰頂恣拋沙。", "大開死口凌霄上，又是一番重退牙。"]'),
('4b58740a-2520-4c64-8f82-68c7be4c6be8','懶瓚岩','釋月磵','宋','宋诗','song-poetry','','[]','天子親頒字十行，難徵老子起岩房。',32,'全唐诗/poet.song.235000.json','["天子親頒字十行，難徵老子起岩房。", "只將牛糞星兒火，煨得蹲鴟萬古香。"]'),
('d1ca21d3-5a29-4725-81c4-d02f0db69170','石屏塔','釋月磵','宋','宋诗','song-poetry','','[]','曾分定石竺峰前，回首秋風三十年。',32,'全唐诗/poet.song.235000.json','["曾分定石竺峰前，回首秋風三十年。", "漠漠吳天自空闊，老猿和雨哭蒼煙。"]'),
('a4aa487e-420f-405e-8d64-24876823fe3e','石林塔','釋月磵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲寒窣堵玉稜層，自酹西湖一勺清。',32,'全唐诗/poet.song.235000.json','["雲寒窣堵玉稜層，自酹西湖一勺清。", "老舌熾然無慈在，錢塘潮撼宋王城。"]'),
('c5c98eea-86e3-4cbe-a0c0-159ac644f78e','禮黄龍先師塔','釋月磵','宋','宋诗','song-poetry','','[]','鈍鍬攪動蒼龍窟，浪激波騰海嶽昏。',32,'全唐诗/poet.song.235000.json','["鈍鍬攪動蒼龍窟，浪激波騰海嶽昏。", "一笑不知深問訊，先師靈骨儼然存。"]'),
('23281db4-0f25-4934-8ed5-5f801bb7ebd9','浙中象外諸友寄新作','釋月磵','宋','宋诗','song-poetry','','[]','肝膽重重楚越分，別來不願見諸君。',32,'全唐诗/poet.song.235000.json','["肝膽重重楚越分，別來不願見諸君。", "那知熟血重相噴，涴却三千里水雲。"]'),
('41e169da-4292-4b99-96b1-20b1c12d1a01','懷徑山諸友','釋月磵','宋','宋诗','song-poetry','','["\u8861\u5c71"]','十年交結幾冤憎，別後誰能記姓名。',32,'全唐诗/poet.song.235000.json','["十年交結幾冤憎，別後誰能記姓名。", "遥想瞎馿成大隊，挹南嶽又望東溟。"]'),
('6239330b-05b5-4347-a847-5ed697fbefe4','謝無文惠書不至','釋月磵','宋','宋诗','song-poetry','','[]','一幅無文倍息全，無端流落水雲邊。',32,'全唐诗/poet.song.235000.json','["一幅無文倍息全，無端流落水雲邊。", "秋空雁字重書出，頓首分明到不宣。"]'),
('4f6605a1-4f1e-4fac-b8c3-94439eaae7b4','田叟','釋月磵','宋','宋诗','song-poetry','','[]','半畝春風箇钁頭，通身泥水不曾休。',32,'全唐诗/poet.song.235000.json','["半畝春風箇钁頭，通身泥水不曾休。", "布成荆棘參天了，老子今年大有秋。"]'),
('83ec9976-662b-4510-a19a-3456f6edb766','斗山','釋月磵','宋','宋诗','song-poetry','','[]','四角量來四極同，乾坤大地在其中。',31,'全唐诗/poet.song.235000.json','["四角量來四極同，乾坤大地在其中。", "鰕兒沒興跳得出，衝破須百萬重。"]'),
('a561f748-0559-4702-8300-5aa1d94feb2d','賀廬山羅漢老子','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','說法聲如動地雷，小南鋪席又重開。',32,'全唐诗/poet.song.235000.json','["說法聲如動地雷，小南鋪席又重開。", "成羣引得獃尊者，遠遠也從高麗來。"]'),
('f6b93a78-9857-4cab-93c2-e1db9b21c99d','悼無文和尚','釋月磵','宋','宋诗','song-poetry','','[]','玉几深深結死冤，錯傳一印漫無文。',32,'全唐诗/poet.song.235000.json','["玉几深深結死冤，錯傳一印漫無文。", "春雷轟破轟不破，盡盡江天飛暮雲。"]'),
('dbea6b8b-09f8-4f24-bb79-8faa27dae6e9','玉崖朝京歸住天池','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','天上明光四度登，古今屈措幾人曾。',32,'全唐诗/poet.song.235000.json','["天上明光四度登，古今屈措幾人曾。", "放光近向廬山頂，莫謂文殊夜放燈。"]'),
('7fc16285-997a-44d0-bfcd-efdb65807a83','送仁姪','釋月磵','宋','宋诗','song-poetry','','[]','惡業相從十五年，未嘗蹉口教參禪。',32,'全唐诗/poet.song.235000.json','["惡業相從十五年，未嘗蹉口教參禪。", "而今年老心孤甚，三十烏藤趁上船。"]'),
('882bd395-4174-4a53-9b77-0a1bbc983bc1','南侍者往送乃師朝京','釋月磵','宋','宋诗','song-poetry','','[]','阿師北去朝金闕，款語丁寧子一回。',32,'全唐诗/poet.song.235000.json','["阿師北去朝金闕，款語丁寧子一回。", "京洛春風無限好，我寬襟袖裹將來。"]'),
('1fc1b690-4db0-48b0-b883-00ee22908f60','法相習兄小室在黄金山下','釋月磵','宋','宋诗','song-poetry','','[]','人間萬事不如閑，湖海歸來緊著關。',32,'全唐诗/poet.song.235000.json','["人間萬事不如閑，湖海歸來緊著關。", "自笑一生貧不盡，黄金推作屋頭山。"]'),
('86011b74-2e80-4f5a-8ff2-1c41fe24f35d','寄和寅知客來韻','釋月磵','宋','宋诗','song-poetry','','[]','老來懷抱轉難平，棒下全無舐犢情。',32,'全唐诗/poet.song.235000.json','["老來懷抱轉難平，棒下全無舐犢情。", "尚有一分慈憫處，教人只向棘中行。"]'),
('550daa96-c7d7-4ae6-8494-0078512ad0e4','萬杉東源和尚塔','釋月磵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','活葬東風百草源，只因錯會祖師禪。',32,'全唐诗/poet.song.235000.json','["活葬東風百草源，只因錯會祖師禪。", "十千古木匡廬頂，一一枝頭啼杜鵑。"]'),
('0ca63f7b-bef5-456a-803b-cf268e32f53b','送僧歸金陵白蓮菴','釋月磵','宋','宋诗','song-poetry','','[]','石頭城裏屋三椽，滿屋清香是白蓮。',32,'全唐诗/poet.song.235000.json','["石頭城裏屋三椽，滿屋清香是白蓮。", "皎潔一心何所似，夜深淮水月初圓。"]'),
('28498f8b-02d7-4727-bed9-76499280b77e','摘茶','釋月磵','宋','宋诗','song-poetry','','[]','拚雙赤手入叢林，要覓春風一寸心。',32,'全唐诗/poet.song.235000.json','["拚雙赤手入叢林，要覓春風一寸心。", "但覺爪牙歸掌握，不知煙霧濕衣襟。"]'),
('a418ef5b-68fa-45c4-8ed3-ce1186006e9e','蓮社題經薦孤魂','釋月磵','宋','宋诗','song-poetry','','[]','一卷百千萬億卷，普使幽冥趨浄方。',32,'全唐诗/poet.song.235000.json','["一卷百千萬億卷，普使幽冥趨浄方。", "越水東邊明月夜，白蓮朵朵晉時香。"]'),
('bb38626e-1220-4da3-ae59-0e8a5b4c8f56','贈髮匠','釋月磵','宋','宋诗','song-poetry','','[]','年來頓覺髮如絲，多少傍人笑老癡。',32,'全唐诗/poet.song.235000.json','["年來頓覺髮如絲，多少傍人笑老癡。", "妙手不須頻摘剃，幾人得到白頭時。"]'),
('d03e6d4c-0ff6-4123-846f-e39aab24a98d','多寶寺','釋月磵','宋','宋诗','song-poetry','','[]','千澗碧流寒漱玉，萬山黄葉冷摇金。',32,'全唐诗/poet.song.235000.json','["千澗碧流寒漱玉，萬山黄葉冷摇金。", "若言即此見多寶，猿叫嶽雲深更深。"]'),
