('15df8b51-0559-4ddc-be7c-a1332347fb18','送住禪人歸疏山','釋月磵','宋','宋诗','song-poetry','','[]','住住住，眨眼白雲飛去。',27,'全唐诗/poet.song.235000.json','["住住住，眨眼白雲飛去。", "杜鵑聲在最高處，春風花滿甜桃樹。"]'),
('7efa8a2e-2b46-4294-8521-7996be54ef86','送親宗古住西山崇報  其一','釋月磵','宋','宋诗','song-poetry','','[]','滿天花雨忽毿毿，定起閑將鼻觀參。',32,'全唐诗/poet.song.235000.json','["滿天花雨忽毿毿，定起閑將鼻觀參。", "却是西山山下寺，古薇枝上綻優曇。"]'),
('31bbf1a5-b0b3-447c-b537-2d3f8c4a5404','送親宗古住西山崇報  其二','釋月磵','宋','宋诗','song-poetry','','[]','法道如今危未危，老眸近覺淚霑頤。',32,'全唐诗/poet.song.235000.json','["法道如今危未危，老眸近覺淚霑頤。", "期君硬著腕頭力，一髮千鈞在此時。"]'),
('0a66c133-0edc-472b-8c79-13946800c757','中道者','釋月磵','宋','宋诗','song-poetry','','[]','笑問殷勤求底事，却言近離古杭州。',32,'全唐诗/poet.song.235000.json','["笑問殷勤求底事，却言近離古杭州。", "開口便作佛法會，老來無力舉藤條。"]'),
('348af74a-3bcb-47d0-84a4-1bb475cbbd49','仙禪人','釋月磵','宋','宋诗','song-poetry','','[]','一人半人之所在，吳越從頭驗一回。',32,'全唐诗/poet.song.235000.json','["一人半人之所在，吳越從頭驗一回。", "三尺炊巾襟袖裏，向人只道看山氣。"]'),
('b5b6608e-6a62-4da4-a371-6c7f44934340','寂林','釋月磵','宋','宋诗','song-poetry','','[]','我國從來本晏然，蕭條活計自忘年。',32,'全唐诗/poet.song.235000.json','["我國從來本晏然，蕭條活計自忘年。", "無端一陣微風過，萬樹蒼松競說玄。"]'),
('d7a286ce-242d-4d37-bf3a-3a8affb10016','鏡清塔','釋月磵','宋','宋诗','song-poetry','','[]','阿師活葬此江臯，障却錢塘幾度潮。',32,'全唐诗/poet.song.235000.json','["阿師活葬此江臯，障却錢塘幾度潮。", "可是髑髏乾不盡，蛙聲依舊響春宵。"]'),
('a56dadd8-634d-4ee0-bc45-ea0e491b38a8','東黄龍雪村','釋月磵','宋','宋诗','song-poetry','','[]','一別龍峰五十年，堪嗟塵世事茫然。',32,'全唐诗/poet.song.235000.json','["一別龍峰五十年，堪嗟塵世事茫然。", "門前舊日長松樹，恨殺春風啼杜鵑。"]'),
('d4a4e84f-b181-461d-a8dc-2ac424cd4483','書明月山房','釋月磵','宋','宋诗','song-poetry','','[]','猗歟大塊中，有此赤肉團。',72,'全唐诗/poet.song.235000.json','["猗歟大塊中，有此赤肉團。", "曾無生與死，從渠暑復寒。", "熾然常說法，風動萬琅玕。", "了然無一物，滿目是青山。", "以幻觀吾幻，以閑樂吾閑。", "世態自消長，日月長循環。"]'),
('c28ab682-a121-4fb7-a76b-41961f797119','出山相贊','釋月磵','宋','宋诗','song-poetry','','[]','正覺山中與麽來，慚惺滿面是塵埃。',32,'全唐诗/poet.song.235000.json','["正覺山中與麽來，慚惺滿面是塵埃。", "未曾空却衆生界，添得人間一禍胎。"]'),
('813c709d-a5f3-4b48-aa77-4e108c35baec','達磨贊','釋月磵','宋','宋诗','song-poetry','','[]','開口觸著梁王諱，擧步踏翻揚子江。',32,'全唐诗/poet.song.235000.json','["開口觸著梁王諱，擧步踏翻揚子江。", "比似者般底麤行，西天東土更無雙。"]'),
('796d015b-70a9-46fe-99c5-a20c1c49cac9','觀音贊  其一','釋月磵','宋','宋诗','song-poetry','','[]','蒙却頭，入正定。',26,'全唐诗/poet.song.235000.json','["蒙却頭，入正定。", "定眼忽開，有何所證。", "楊柳枝頭春雨暝。"]'),
('cc5df3de-a8a0-46b2-b3ec-d4cf7c564242','觀音贊  其二','釋月磵','宋','宋诗','song-poetry','','[]','抱膝坐盤陀，以耳觀無礙。',28,'全唐诗/poet.song.235000.json','["抱膝坐盤陀，以耳觀無礙。", "一匊悲心海樣深，何時空却衆日界。"]'),
('184acb5c-3c19-428b-8936-d81ca97496fa','布袋贊  其一','釋月磵','宋','宋诗','song-poetry','','[]','曲江磯頭，奉化縣裏。',34,'全唐诗/poet.song.235000.json','["曲江磯頭，奉化縣裏。", "拖潑囊落落魄魄，剛道一生歡喜。", "不知月在雲中笑你。"]');
